INSERT INTO `tb_m_aspek` (`ID`, `NAME`, `TYPE`, `DESKRIPSI_HASIL_TES`, `DESKRIPSI_PENGEMBANGAN_KARAKTERISTIK`) VALUES
(2, 'Linguistic-Bahasa', 1, 'Kamu memiliki ketertarikan yang ditunjang dengan penguasaan penggunaan Bahasa yang baik dan efektif.  Kamu mampu menganalisis informasi dengan baik, menggunakan beragam jenis kata dan menyusunnya menjadi kalimat yang mudah dimengerti. Kamu menyukai beragam aktivitas yang bersinggungan dengan Bahasa seperti membaca, menulis, mendengarkan dan berbicara. Kamu bisa mencoba untuk belajar Bahasa asing agar kemampuan linguistikmu semakin keren! Kamu bisa berkarier di beberapa bidang seperti dramawan, editor, pengarang, jurnalis, pengacara, sastrawan, novelis dan sebagainya.', 'Penggunaan Bahasa yang kamu miliki sangat baik, pemilihan kata yang pas dan sesuai. Bacalah buku untuk menambah perbendaharaan kata yang kamu miliki, mulailah menulis dan aktiflah berdiskusi. Tambah pengetahuan mu dalam banyak bidang, selanjutnya kamu akan lebih mudah menjadi pembicara di banyak kegiatan.'),
(3, 'Logical-matematik', 1, 'Kamu memiliki kemampuan dalam berpikir secara induktif dan deduktif, kamu memiliki penalaran logika, analisis pola angka dan pemecahan masalah yang cukup baik. Kamu mampu menghitung dan bermain angka dan melakukan pemecahan masalah yang terjadi dengan baik, kemampuan berpikir ilmiah yang kamu miliki membuat kamu menjadi sosok yang yang sangat logis dan mudah diterima orang lain. Kamu sangat cocok bekerja pada beberapa bidang seperti logikus, matematikus, saintis, programmer dan negosiator. ', 'Kamu bisa meningkatkan kemampuanmu dengan banyak berlatih dalam mengerjakan soal yang berkaitan dengan analisis pola angka. Kamu bisa mengikuti kelas matematika tambahan atau bimbel. Selain itu, kamu juga bisa bergabung dalam kelompok penelitian, hal ini akan sangat cocok dengan karakter mu yang selalu berpikir rasional.'),
(4, 'Visual-Spatial', 1, 'Kamu memiliki ketertarikan dan kemampuan yang baik untuk memahami secara lebih dalam hubungan antara objek dan ruang. Kemampuan imajinasi yang aktif dan bekerja sangat baik membuat kamu memiliki beberapa kemampuan yang menarik seperti persepsi yang tepat dari berbagai sudut, reprentasi grafik, mudah menemukan jalan dalam ruang juga peka terhadap warna, garis dan bentuk. Kamu cocok bekerja di beberapa bidang seperti pemburu, arsitek, decorator, navigator, ahli peta, pelukis, pemahat dan sebagainya. ', 'Melihat karakteristikmu, kamu bisa mencoba mempelajari lebih lanjut mengenai visualisasi. Cobalah membuat design ruang atau sketsa sebuah bangunan, kamu akan lebih mudah bekerja dengan kemampuan mu yang sangat menarik ini. Cobalah untuk memasuki program study yang berkaitan dengan karakteristikmu, dan tingkatkan kemampuanmu.'),
(5, 'Bodily- Kinesthetic', 1, 'Kamu memiliki kemampuan yang baik dalam pengendalian gerak tubuh. Kamu mudah berekspresi dengan tubuh, mengaitkan pikiran dengan gerak tubuh, bermain mimik wajah, bermain drama juga peran. Kamu menyukai kegiatan yang melibatkan gerak tubuh seperti berolahrag dan menari. Koordinasi dan fleksibilitas tubuh yang kamu miliki cukup tinggi. Kamu sangat cocok berkarier pada beberapa bidang seperti actor, atlet, penari, pemahat, olahragawan, ahli bedah dan sebaginya.', 'Kamu bisa meningkatkan kemampuanmu dengan terus berlatih mengenai koordinasi dan fleksibilitas tubuh. Fokuslah untuk meningkatkan kemampuanmu dengan berlatih di sanggar atau mengikuti les tambahan. Rutinlah melakukan latihan fisik untuk kestabilan gerak tubuhmu.'),
(6, 'Musical', 1, 'Kamu memiliki ketertarikan dan kemampuan untuk menghasilkan, mengingat, dan memaknai pola suara yang berbeda. Kecerdasan ini membuat kamu memiliki beberapa kemampuan yang cukup menarik seperti kepekaan terhadap suara dan music, mengetahui struktur music dengan baik, mampu menciptakan melodi, mampu menciptakan, menyajikan dan mengembangkan karya music dengan baik. Kamu bisa berkrier di beberapa bidang seperti musikus, penyanyi, pemain opera, komponis, dirigen dan sebagainya. ', 'Kemampuan dalam bidang music sangat dominan. Mulailah berlatih lebih keras dengan mengikuti kelas menyanyi atau aransemen musik. Tontonlah beberapa video yang mempelajari mengenai music, ikutilah kelas music tambahan dan bangunlah rasa percaya diri mu untuk mulai tampil didepan.'),
(7, 'Interpersonal', 1, 'Kamu merupakan sosok yang percaya diri untuk dapat berinteraksi dengan siapapun. Bagimu, berkumpul dengan banyak orang adalah sumber energi. Kamu mampu menyesuaikan diri dengan berbagai macam karakteristik orang, dan mampu memprediksi apa yang sedang mereka rasakan. Meyakinkan orang-orang mengenai gagasan yang kamu miliki, merupakan tantangan yang menyenangkan untuk kamu lakukan. Kamu dapat berkarier secara professional dalam beberapa bidang seperti manajer, marketer, pekerja sosial, pengajar, negosiator, diplomat, konselor dan lain sebagainya. ', 'Karakteristikmu sangat menarik, ikutilah beberapa kegiatan sosial dan organisasi untuk memperluas relasi pertemananmu. Hal ini akan sangat bermanfaat ketika kamu memasuki dunia kerja. Pelajarilah cara berinteraksi dengan tetap mengedepankan etika agar kamu tetap terlihat berkelas, perhatikan gesture tubuh dan gaya bicara mu ketika berinteraksi dengan orang lain.'),
(8, 'Intrapersonal', 1, 'Kamu merupakan sosok yang mampu mengenali dan memahami suasana hati, keinginan motivasi dan seseorang serta orang lain.kecerdasan ini membawa kamu untuk memiliki kemampuan yang sangat dibutuhkan orang lain seperti kemampuan berkonsentrasi dengan baik, peka dan sadar terhadap ekspresi perasaan yang berbeda, pengenalan diri yang dalam, keseimbangan diri yang baik, kesadaran akan spiritual dan realitas. Selain itu kamu juga pribadi yang reflektif dan suka bekerja seorang diri. Kamu dapat berkarier pada beberapa bidang seperti psikolog, penulis, konselor, konsultan karier, motivator dan sebagainya.', 'Kemampuan mu sangat baik dalam berkonsentrasi, kamu akan menjadi teman dan pendengar yang sangat baik. Untuk meningkatkan kemampuan mu kamu bisa mencoba mempelajari hal-hal yang tidak perlu dilakukan secara berkelompok seperti menulis. Bacalah beragam jenis buku atau tonton video di platform social media untuk menambah pengetahuan dan keterampilan mu.'),
(9, 'Naturalistik', 1, 'Kamu memiliki kemampuan dan keteratrikan untuk mengidentifikasi dan membedakan berbagai jenis tanaman, hewan dan formasi cuaca yang di temukan di alam. Kecerdasan ini mendukung kamu memiliki kemampuan yang cukup dalam mengenal flora dan fauna, mengklasifikasi dan mengidentifikasi tumbuhan juga Binatang. Kamu menyukai alam dan senang hidup diluar rumah untuk menjelajahi alam. Dengan kecerdasan yang kamu miliki kamu cocok untuk bekerja pada beberapa sektor seperti botanis, anatomis, pengamat lingkungan, dan sebagainya.', 'Kamu dan alam adalah kesatuan. Cobalah mengeksplore lebih jauh mengenai alam untuk meningkatkan kemampuan mu. Kamu bisa mencoba mendaki gunung, menyelam, atau mengunjungi tempat pembudidayaan tanaman dan kebun Binatang. Bacalah beberapa informasi mengenai flora dan fauna untuk menambah pengetahuanmu.'),
(10, 'REALISTIC', 2, 'Hai sobat karier, berdasarkan hasil tes minat kamu menonjol pada bidang Realistic! Kamu adalah pribadi yang suka bekerja dengan tangan dan lebih suka bekerja diluar ruangan. Kamu memiliki keterampilan menggunakan dan mengoperasikan alat, mengemudi, merawat hewan dan bekerja dengan tanaman. Kamu juga cocok bekerja sebagai pilot, petani, holtikultura, insinyur, mekanik, olahragawan dan lainnya. ', 'Lakukan kegiatan yang menunjang kemampuan mu dibidang realistic. Kamu bisa mempelajari lebih lanjut mengenai Teknik industry, teknik mesin. atau teknik pertanian dan lainnya. kamu bisa memulai untuk berfokus pada bidang yang kamu minati, dan mulailah belajar dari para ahlinya. '),
(11, 'Investigative ', 2, 'Hai sobat karier, berdasarkan hasil tes minat kamu masuk dalam tipe Investigative! Kamu adalah pribadi yang suka menemukan dan meneliti ide, kamu suka bereksperimen, mengajukan pertanyaan dan suka menyelesaikan masalah. Kamu memiliki keterampilan berpikir analitis dan logis. Mampu menghitung, berkomunikasi dengan menulis dan berbicara, mendiagnosis dan menyelidiki. Kamu juga cocok bekerja dalam bidang Ilmu Pengetahuan, penelitian, pekerja medis atau Kesehatan, zoologi, laboran, pertanian dan lainnya.', 'Mulailah untuk mengikuti kegiatan yang menunjang kariermu dalam bidang ini. Tingkatkan kemampuan Bahasa inggrismu, lalu pelajari lebih jauh mengenai sains dan ilmu computer. Lakukanlah eksperimen-eksperimen kecil terlebih dahulu, kembangkan karakter investigative mu dengan banyak berdiskusi soal keilmuan dengan para ahli.'),
(12, 'Artistic', 2, 'Hai sobat karier, berdasarkan hasil tes kamu masuk dalam type Artistic! Kamu adalah pribadi yang suka menggunakan kata-kata, menyukai unsur seni, seperti music dan drama untuk berkomunikasi, dan senang berekpresi melalui seni. Kamu memiliki keterampilan yang cukup baik dalam bidang seni seperti menyanyi, merancang, menyajikan, merencanakan, Menyusun karya seni. Kamu cocok bekerja dalam banyak bidang lho! Seperti artis, illustrator, fotografer, penulis lagu, actor, reporter perancang busana dan banyak lainnya!', 'Tingkatkan kemampuanmu dengan terus berlatih dalam bidang seni yang kamu sukai. Kamu bisa memulainya dengan berlatih melalui bantuan beberapa platform social media atau bisa melakukan les di sanggar seni agar kemampuanmu semakin baik. Kesenanganmu dalam berekspresi melalui seni harus dipertahankan ya sobat!'),
(13, 'SOCIAL', 2, 'Hai sobat karier, berdasarkan hasil tes kamu masuk dalam type Social! Kamu termasuk pada pribadi yang memiliki empati cukup tinggi. Kamu suka mengajar, melatih dan memberi informasi kamu sangat peduli pada kesejahteraan orang-orang disekitarmu. Kamu punya keterampilan yang cukup baik dalam berkomunikasi secara lisan dan tertulis. Kamu cocok bekerja dalam bancocok bekerja sebagai guru, perawat, pekerja sosial, dan masih banyak lagi! ', 'Sobat karier, kamu adalah pribadi dengan empati yang cukup tinggi. Untuk meningkatkan kemampuanmu, mulailah untuk membuka les, bimbingan belajar dan aktif menjadi relawan. Beberapa kegiatan tersebut dapat menunjang kemampuan komunikasimu menjadi semakin baik dan memperluas relasi yang kamu miliki. '),
(14, 'Enterprising', 2, 'Hai sobat karier, berdasarkan hasil tes kamu masuk dalam type Enterprising! Kamu adalah pribadi yang cukup menyenangkan dan suka bertemu dengan orang, kamu mampu memimpin, berbicara dan mempengaruhi orang lain, membangun Kerjasama dan berbisnis. Kamu memiliki keterampilan yang cukup menarik seperti menjual, mempromosikan, membujuk mengembangkan ide, berbicara didepan umum dan merencanakan sesuatu dengan baik. Kamu bisa bekerja sebagai tenaga penjual, pengacara, politisi, akuntan dan masih banyak lagi!', 'Kemampuanmu untuk meyakinkan orang lain sangat baik. Mulailah untuk mengambil langkah untuk menjadi pemimpin atau pembicara dalam suatu forum. Bangunlah relasi yang luas dan mulailah berbisnis di bidang yang kamu minati. Bangun rasa percaya dirimu dengan baik, dan pelajari lebih jauh mengenai publik speaking yang baik.'),
(15, 'Conventional', 2, 'Hai sobat karier, berdasarkan hasil tes kamu masuk dalam type Conventional! kamu lebih suka bekerja didalam ruangan pada tugas-tugas yang melibatkan pengorganisasian dan akurasi. Kamu juga sosok yang selalu mengikuti prosedur, memiliki kemampuan yang baik dalam pengolahan data dan angka loh! Selain itu kamu  pribadi yang sangat detail teliti dan penuh perencanaan. Kamu bisa bekerja pada banyak bidang diantaranya sekretaris, resepsionis, pustakawan, petugas Bank, operator computer dan lainnya.', 'Sobat karier, ketelitianmu dalam melakukan sesuatu sangat baik. Dari karakteristik yang kamu miliki, kamu bisa meningkatkan kemampuanmu dengan mempelajari Microsoft word, excel, power point dan lainnya. kamu juga bisa mulai belajar pengolahan data dan angka.'),
(16, 'Eksistensial', 1, 'Kamu memiliki ketertarikan untuk memahami pertanyaan abstrak tentang keberadaan, makna dan tujuan hidup. Kamu juga memiliki kecenderungan untuk mengekplorasi pertanyaan-pertanyaan filosofis selain itu kamu juga sangat peka terhadap masalah sosial. Dengan kemampuan yang kamu miliki kamu sangat cocok bekerja sebagai psikolog atau ahli filsuf.', 'Pemikiran kritismu adalah senjata yang baik. Bacalah banyak buku dan seringlah berdiskusi soal keilmuan dengan para ahli. Mulailah membahas isu-isu yang terjadi, baik isu lokal ataupun global. Bertemulah dengan banyak orang untuk mengeksplorasi kehidupan.');
