INSERT INTO `tb_m_info` (`ID`, `CODE`, `DESKRIPSI_BIDANG_MINAT`, `KETERAMPILAN_KUNCI`, `KOMPONEN_PEKERJAAN`, `PROGRAM_STUDY`, `TYPE`) VALUES
(1, 10, 'Suka bekerja terutama dengan tangan, membuat, memperbaiki, merakit atau membangun sesuatu, menggunakan dan mengoperasikan peralatan, alat atau mesin. Seringkali suka bekerja di luar ruangan', 'Menggunakan dan mengoperasikan alat, peralatan dan mesin, merancang, membangun, memperbaiki, memelihara, bekerja secara manual, mengukur, bekerja secara detail, mengemudi, bergerak, merawat hewan, bekerja dengan tanaman', 'Pilot, petani, hortikultura, pembangun, insinyur, personel angkatan bersenjata, mekanik, tukang melapis, listrik, teknolog komputer, penjaga taman, olahragawan', 'Bahasa Inggris, Matematika, Sains, Workshop, Teknologi, Komputer, Studi Bisnis, Pertanian, Hortikultura, Pendidikan Jasmani', 2),
(2, 11, 'Suka menemukan dan meneliti ide, mengamati, menyelidiki, dan bereksperimen, mengajukan pertanyaan, dan menyelesaikan masalah', 'Berpikir analitis dan logis, menghitung, berkomunikasi dengan menulis dan berbicara, merancang, merumuskan, menghitung, mendiagnosis, bereksperimen, menyelidiki', 'Ilmu pengetahuan, penelitian, pekerjaan medis dan kesehatan, ahli kimia, ilmuwan kelautan, teknisi kehutanan, teknisi laboratorium medis atau pertanian, ahli zoologi, dokter gigi, dokter', 'Bahasa Inggris, Matematika, Sains, Komputer, Teknologi', 2),
(3, 12, 'Suka menggunakan kata-kata, seni, musik atau drama untuk berkomunikasi, melakukan, atau mengekspresikan diri, membuat dan merancang sesuatu', 'Mengekspresikan secara artistik atau fisik, berbicara, menulis, menyanyi, tampil, merancang, menyajikan, merencanakan, menyusun, bermain, menari', 'Artis, ilustrator, fotografer, penulis lagu, komposer, penyanyi, pemain instrumen, penari, aktor, reporter, penulis, editor, pengiklan, penata rambut, perancang busana', 'Bahasa Inggris, Ilmu Sosial, Musik, Drama, Seni, Desain Grafis, Komputer, Studi Bisnis, Bahasa', 2),
(4, 13, 'Suka mengajar, melatih dan memberi informasi, membantu, mengobati, menyembuhkan dan melayani dan menyapa, peduli dengan kesejahteraan diri dan kesejahteraan orang lain', 'Berkomunikasi secara lisan atau tertulis, peduli dan mendukung, melatih, bertemu, menyapa, membantu, mengajar, memberi informasi, mewawancarai, melatih', 'Guru, perawat, asisten perawat, penasihat, petugas polisi, pekerja sosial, tenaga penjualan, petugas layanan pelanggan, pelayan, sekretaris', 'Bahasa Inggris, Ilmu Sosial, Matematika, Sains, Kesehatan, Pendidikan Jasmani, Seni, Komputer, Studi Bisnis, Bahasa', 2),
(5, 14, 'Suka bertemu orang, memimpin, berbicara dan mempengaruhi orang lain, mendorong orang lain, bekerja dalam bisnis', 'Menjual, mempromosikan dan membujuk, mengembangkan ide-ide, berbicara di depan umum, mengelola, mengatur, memimpin dan menangkap, menghitung, merencanakan', 'Tenaga penjual, pengacara, politisi, akuntan, pemilik bisnis, eksekutif atau manajer, agen perjalanan, musik atau promotor olahraga', 'Bahasa Inggris, Matematika, Studi Bisnis, Akuntansi, Ekonomi, Ilmu Sosial, Drama, Komputasi, Manajemen Informasi Teks, Bahasa', 2),
(6, 15, 'Suka bekerja di dalam ruangan dan pada tugas-tugas yang melibatkan pengorganisasian dan akurasi, mengikuti prosedur, bekerja dengan data atau angka, pekerjaan perencanaan dan acara', 'Komputasi dan keyboarding, merekam dan menyimpan catatan, memperhatikan detail, bertemu dan menyapa, melakukan perhitungan, menangani uang, mengatur, mengatur, bekerja secara mandiri', 'Sekretaris, resepsionis, pekerja kantor, pustakawan, petugas bank, operator komputer, toko dan petugas pengiriman', 'Bahasa Inggris, Matematika, Studi Bisnis, Akuntansi, Ekonomi, Komputer, Manajemen Informasi Teks', 2),
(7, 2, 'Kemampuan untuk menganalisis informasi dan membuat produk yang melibatkan Bahasa lisan, tulisan seperti pidato, buku dan memo.', 'Mengerti urutan dan arti kata-kata., Menjelaskan, mengajar, bercerita, berdebat., Humor., Mengingat dan menghafal., Analisis linguistik., Menulis dan berbicara., Main drama, berpuisi, berpidato., Mahir dalam perbendaharaan kata.', 'Dramawan, editor,pengarang, jurnalis, sastrawan, orator, ahli sastra, novelis.', 'Komunikasi, sastra, jurnalistik, pariwisata dan hukum.', 1),
(8, 3, 'Memuat kemampuan seseorang dalam berpikir secara induktif dan deduktif, berpikir menurut aturan logika, memahami dan menganalisis pola angka-angka serta memecahkan masalah dengan menggunakan kemampuan berpikir.', 'Logika., Reasioning, pola sebab akibat., Klasifikasi dan kategorisasi., Abstraksi, simbolisasi., Pemikiran induktif dan deduktif., Menghitung dan bermain angka., Pemikiran ilmiah., Problem solving., Silogisme', 'Logikus, matematikus, saintis, programer, negosiator', 'Akuntansi, matematika, sains, aktuaria atau programmer.', 1),
(9, 4, 'Kemampuan untuk menganalisis informasi dan membuat produk yang melibatkan Bahasa lisan, tulisan seperti pidato, buku dan memo.', 'Mengenal relasi benda-benda dalam ruang dengan tepat., Punya persepsi yang tepat dari berbagai sudut., Representasi grafik., Manipulasi gambar, menggambar., Mudah menemukan jalan dalam ruang., Imajinasinya aktif., Peka terhadap warna, garis, dan bentuk.', 'Pemburu, arsitek, dekorator, navigator, ahli peta, pelukis, pemahat, pengambar, pemain catur', 'Arsitektur, seni rupa, DKV, Teknik atau pilot.', 1),
(10, 5, 'Kemampuan untuk menggunakan tubuh sendiri untuk menciptakan produk atau memecahkan masalah.', 'Mudah berekspresi dengan tubuh., Mengkaitkan pikiran dan tubuh., Kemampuan bermain mimik., Main drama, main peran., Aktif bergerak, olahraga, menari., Koordinasi dan fleksibilitas tubuh tinggi.', 'Aktor, atlet, penari, pemahat, ahli bedah, olahragawan', 'Jurusan keolahragaan, seni kriya, seni tari, tata busana, dokter bedah.', 1),
(11, 6, 'Kemampuan untuk menghasilkan, mengingat, dan memaknai pola suara yang berbeda.', 'Kepekaan terhadap suara dan musik., Tahu struktur musik dengan baik., Mudah menangkap musik., Mencipta melodi., Peka dengan intonasi, ritmik., Menyanyi, pentas musik., Mencipta musik., Pemain alat musik.', 'Musikus, penyanyi, pemain opera, komponis, dirigen, pemain musik', 'Musik', 1),
(12, 7, 'Kemampuan untuk mengenali dan memahami suasana hati, keinginan, motivasi dan niat orang lain.', 'Mudah kerjasama dengan teman., Mudah mengenal dan membedakan perasaan dan pribadi teman., Komunikasi verbal dan non-verbal., Peka terhadap teman, empatis., Suka memberikan feedback.', 'Komunikator, fasilitator, penggerak massa, pemersatu', 'Perawat, Kesehatan Masyarakat, gizi, Pendidikan dan psikologi.', 1),
(13, 8, 'Kemampuan untuk mengenali dan memahami suasana hati, keinginan, motivasi, dan niat seseorang.', 'Dapat berkonsentrasi dengan baik., Kesadaran dan ekspresi perasaan-perasaan yang berbeda., Pengenalan diri yang dalam., Keseimbangan diri., Kesadaran akan realitas spiritual., Reflektif, suka kerja sendiri.', 'Sufi, pendoa batin, spiritual yang mendalam, pendamai', 'Psikologi, bimbingan konseling,', 1),
(14, 9, 'Kemampuan untuk mengidentifikasi dan membedakan berbagai jenis tanaman, hewan dan formasi cuaca yang ditemukan dialam.', 'Mengenal flora-fauna., Mengklasifikasi dan identifikasi tumbuhan dan binatang., Suka pada alam., Hidup di luar rumah.', 'Botanis, anatomis', 'Dokter hewan, peternakan, kelautan dan kehutanan.', 1),
(15, 16, 'kemampuan untuk memahami pertanyaan abstrak tentang keberadaan, makna, dan tujuan hidup. cenderung memiliki keinginan kuat untuk mengeksplorasi pertanyaan-pertanyaan filosofis dan mencari jawaban atas pertanyaan tentang hakikat keberadaan manusia', 'Memiliki pandangan jangka panjang., Memikirkan sebab akibat., Tertarik mendalami ilmu atau pelajaran agama., Suka menolong orang lain., Sangat peka terhadap masalah sosial.', 'Psikolog, ahli filsuf', 'Psikologi atau filsafat', 1);
INSERT INTO `tb_m_jurusan` (`ID`, `NAMA_JURUSAN`, `DESKRIPSI`, `PENGETAHUAN_DAN_KEAHLIAN`, `KENAPA_HARUS_JURUSAN_INI`, `PROSPEK_KERJA`, `DUNIA_PERKULIAHAN`, `GAMBAR`) VALUES
(1, 'Pendidikan Bahasa Inggris', '<p class=\'text-justify\'>Pendidikan Bahasa Inggris fokus pada pembelajaran mendengarkan, berbicara, membaca, menulis juga penggunaan bahasa Inggris dalam berbagai konteks seperti berkomunikasi dalam bisnis, presentasi, penulisan artikel, bahkan pertunjukan drama. Tentu saja kamu juga akan mempelajari tata bahasa juga<em>&nbsp;ya</em>, sobat karier. Selain itu,&nbsp;<em>nggak</em>&nbsp;ketinggalan materi tentang kependidikan, seperti pengembangan kurikulum dan&nbsp;<em>teaching assessment</em>.</p>', '<ul>\r\n<li>Kemampuan komunikasi lisan</li>\r\n<li>Kemampuan komunikasi tertulis</li>\r\n<li>Kemampuan memahami bacaan</li>\r\n<li>Kemampuan memahami analis</li>\r\n<li>Kemampuan berpikir systematis</li>\r\n<li>Keterampilan interpersonal</li>\r\n</ul>', '<ul>\r\n<li>Selain menjadi guru Bahasa inggris sekolah, kamu juga bisa membuka kursus Bahasa inggris ataupun jasa penerjemah</li>\r\n<li>Jika kamu pribadi yang suka jalan-jalan bisa bergabung di torism center, misalnya dengan jadi pemandu wisata, karena Bahasa inggris merupakan Bahasa internasional jadi kamu akan mahir dalam berkomunikasi dengan wisatawan mancanegara</li>\r\n<li>Kamu juga terjun ke dunia media dan kreatif, misalnya sebagai pengisi suara di film yang di alih bahasakan ataupun membuat subtitle film. Selain itu, bisa juga loh jadi jurnalis</li>\r\n<li>Saat kamu memutuskan untuk sekedar liburan ataupun go internasional, kamu tidak akan kesulitan untuk berkomunikasi, karena Bahasa inggris digunakan sebagai Bahasa universal</li>\r\n<li>Selain punya pemahaman yang baik tentang ilmu kebahasaan dan ilmu kesusastraan, kamu juga meiliki wawasan yang luas soal budaya, ekonomi, politik, dan Sejarah negara-negara yang menjadikan Bahasa inggris sebagai Bahasa ibu.</li>\r\n</ul>', '<p>Lulusan jurusan Pendidikan Bahasa Inggris punya peluang kerja yang luas&nbsp;<em>sobatt!!</em>. Selain menjadi guru bahasa Inggris di sekolah, kamu bisa membuka usaha kursus bahasa Inggris untuk siswa SD, SMP, SMA, bahkan kursus untuk persiapan TOEFL ataupun IELTS. Karena selain pengusaan tata bahasa yang baik, kamu juga memiliki bekal ilmu kependidikan untuk mengajarkan bahasa Inggris kepada siswa. Kamu pun bisa membuka jasa penerjemahan maupun penyuntingan artikel bahasa Inggris. Untuk mengembangkan potensi yang ada dalam dirimu, bisa juga lho mencoba bidang lain, seperti media dan kreatif, pariwisata, dan lainnya. Berikut ini beberapa pilihan karier yang bisa kamu geluti:</p>\r\n<ul>\r\n<li>Penerjemah lisan (interpreter)</li>\r\n<li>Guru Bahasa asing</li>\r\n<li>Penerjemah tulisan (translator)</li>\r\n<li>Konsultan Pendidikan</li>\r\n<li>Staf maskapai penerbangan</li>\r\n<li>Concierge hotel</li>\r\n<li>Pemandu wisata (tour guide)</li>\r\n<li>Jurnalis (reporter)</li>\r\n<li>Dll</li>\r\n</ul>', '<p>Melanjutkan studi di jurusan Pendidikan Bahasa Inggris, kamu akan belajar banyak hal terkait&nbsp;<strong>ilmu kebahasaan, kesusastraan, juga kependidikan</strong>. Umumnya, kamu akan kuliah selama 4 tahun atau 8 semester. Di awal kuliah, kamu akan diasah kemampuan membaca, berbicara, mendengarkan, dan menulis. Kamu harus melahap materi tata bahasa. Selanjutnya, kamu juga akan mengkaji berbagai karya dalam bahasa Inggris, penggunaan bahasa Inggris dalam bisnis, serta pengembangan kurikulum pembelajaran bahasa Inggris. Jadi, di jurusan ini kamu akan belajar&nbsp;<em>English in full package</em>.</p>\r\n<p>Beberapa&nbsp;<strong>mata kuliah</strong>&nbsp;yang bisa kamu temui misalnya&nbsp;<em>Speaking</em>,&nbsp;<em>Writing</em>,&nbsp;<em>Reading</em>,&nbsp;<em>ListeningComprehension</em>,&nbsp;<em>Structure</em>,&nbsp;<em>Linguistic</em>,&nbsp;<em>Sociolinguistic</em>,&nbsp;<em>Psycholinguistic</em>,&nbsp;<em>English Phonetics and Phonology</em>,&nbsp;<em>English Morphology</em>,&nbsp;<em>English Syntax</em>,<em>&nbsp;English Semantic</em>,&nbsp;<em>Curriculum and Material Development</em>,&nbsp;<em>English Language Teaching Assessment</em>,&nbsp;<em>Integrated Intensive Course</em>, dan sebagainya. Setelah lulus, sobat karier berhak untuk menyandang gelar Sarjana Pendidikan.</p>\r\n<p>Untuk menambah kemampuan, kamu juga bisa&nbsp;<em>lho</em>&nbsp;mengambil&nbsp;<strong>kursus singkat</strong>&nbsp;di luar negeri misalnya program TESOL (Pengajaran Bahasa Inggris untuk Penutur Bahasa Lain), TEFL (Pengajaran Bahasa Inggris sebagai bahasa asing), ataupun TESL (Pengajaran Bahasa Inggris sebagai bahasa kedua). Program tersebut akan sangat menunjang kariermu nantinya jika berkecimpung di dunia pendidikan. Selain itu, kamu juga bisa mengambil program lain di jenjang pascasarjana. Ada berbagai pilihan kampus bergengsi di luar negeri yang bisa kamu jadikan referensi.</p>', 'pendidikan_bahasa_inggris.jpg'),
(2, 'Matematika', '<p>Urusan Matematika fokus mempelajari berbagai teori matematika secara mendalam, seperti geometri, aljabar, hingga matematika diskrit. Jadi, sobat karir akan bertemu dengan beragam konsep dalam matematika seperti mempelajari fitur lain dari angka, juga ruang multidimensi. Selain itu, ada juga&nbsp;<em>lho</em>&nbsp;matematika terapan untuk mempelajari aplikasi matematika di bidang lainnya.</p>', '<ul>\r\n<li>Kemampuan melakukan analis</li>\r\n<li>Kemampuan berpikir kritis dan rasional</li>\r\n<li>Kemampuan berpikir terstruktur</li>\r\n<li>Kemampuan berhitung</li>\r\n<li>Kemampuan problem solving</li>\r\n<li>Kemampuan meneliti</li>\r\n<li>Detil, teliti dan tekun</li>\r\n</ul>', '<ul>\r\n<li>Ilmu matematika sejatinya sangat aplikatif, sehingga ada banyak peluang karier bagi lulusannya, misalnya disektor keuangan, teknologi informasi, dan sebagainya.</li>\r\n<li>Saat ini, Perusahaan asuransi wajib menggunakan tenaga aktuaris untuk merancang produk asuransi dan tingkat premi, menentukan status keuangan Perusahaan, dan melakukan proyeksi keuangan. Nah ini peluang besar bagi lulusan matematika.</li>\r\n<li>Banyak Perusahaan juga membutuhkan lulusan matematika sebagai analis bisnis pada bagian production planning control maupun supply chain management</li>\r\n<li>Kamu yang senang matematika tapi juga tertarik dengan dunia bisnis, punya peluang untuk jadi seorang big data analyst.</li>\r\n<li>Jika ingin menjadi guru, kamu dapat memilih jurusan Pendidikan matematika.</li>\r\n</ul>', '<p>Ada banyak peluang karier yang menanti lulusan Matematika. Karena ilmu yang dipelajari selama kuliah sangat aplikatif, tak heran kalau jenis dan jenjang karier yang ditawarkan juga sangat bervariasi. Lulusan Matematika bisa mengembangkan potensinya di sektor keuangan, teknologi informasi, dan lainnya. Jadi sobat karir perlu bangga dengan penguasaan ilmu Matematika, karena punya nilai jual yang tinggi. Secara umum, rata-rata&nbsp;<strong>gaji awal lulusan Matematika berada pada kisaran Rp4.000.000</strong>, dengan pekerjaan sebagai staf dari bidang tertentu di suatu perusahaan. Nah, besaran ini tentunya dipengaruhi oleh kemampuan dan pengalaman yang kamu punya, area tempat bekerja serta tingkatan pekerjaan saat kamu diterima. Berikut ini ada beberapa pilihan karier yang bisa kamu geluti:</p>\r\n<ul>\r\n<li>Penilai Real Estate</li>\r\n<li>Market researcher</li>\r\n<li>Insinyur aplikasi (application engineer)</li>\r\n<li>Insinyur perangkat lunak (software developer)</li>\r\n<li>Data scientist</li>\r\n<li>Programmer (software developer)</li>\r\n<li>Quality Assurance (QA) dan Quality Control (QC)</li>\r\n<li>Ahli statistic</li>\r\n<li>Aktuaris</li>\r\n</ul>', '<p>Kuliah di jurusan Matematika selama&nbsp;<strong>4 tahun atau 8 semester</strong>, sobat karir akan banyak mengutak-atik berbagai teorema dan membuktikannya. Selain itu, kamu akan mempelajari bagaimana memperoleh nilai optimal dari permasalahan yang kompleks, bagaimana matematika diaplikasikan dalam bidang komputer, keuangan, dan bidang lainnya. Kamu juga akan dibekali dengan cara berpikir logis, analitis, dan sistematis untuk menyelesaikan suatu permasalahan. Jadi, jurusan ini cocok&nbsp;<em>banget</em>&nbsp;dengan sobat karir yang suka menghitung dan punya data analisis yang kuat.</p>\r\n<p>Untuk menjadi seorang&nbsp;<strong>Sarjana Sains</strong>&nbsp;yang ahli dalam bidang Matematika, sobat karir akan bertemu dengan mata kuliah seperti Kalkulus, Matematika Diskrit, Geometri Analitik, Geometri Transformasi, Aljabar Linear, Teori Himpunan, Persamaan Diferensial Elementer, Program Linear, Matematika Komputasi, Fungsi Variabel Kompleks, Analisis Real dan Kompleks, Teori Peluang, Teori Optimasi, dan masih banyak lagi. Setelah lulus, sobat karir, bisa melanjutkan studi ke jenjang<strong>&nbsp;pascasarjana</strong>&nbsp;pada bidang Matematika atau bidang lain yang terkait dengan Matematika dan aplikasinya. Ada banyak banget pilihan kampus bergengsi di dalam juga luar negeri yang bisa kamu jadikan referensi untuk melanjutkan studi.</p>', 'matematika.jpg'),
(3, 'Sains Data', '<p>Jurusan sains data merupakan dampakdari kemunculan revolusi 4.0 ditambah dengan banyaknya teknologi yang muncul, jurusan sains Data menjadi cukup menarik untuk dijadikan sebagai pilihan. Terlebih, saat ini banyak Perusahaan yang ikut menggunakan sains data untuk pengembangan bisnisnya.</p>\r\n<p>&nbsp;</p>\r\n<p>Trend ini menyebabkan kebutuhan Perusahaan pada tenaga data sains tentu menjadi semakin meningkat. Bahkan survey yang dilakukan oleh IBM atau Institute Of Bussiness Management For Bisnis Value mengunngkapkan bila kebutuhan lulusa jurusan data sains mengalami lonjakan yang begitu sgnifikan diseluruh dunia.</p>\r\n<p>&nbsp;</p>\r\n<p>Data scientist, menjadi salah satu profesi lulusan data sains yang semakin diincar karena memiliki penghasilan yang sangat baik. Tidak mengherankan, peminat jurusan data science di Indonesia juga terus meningkat.</p>\r\n<p>Lantas, data scientist jurusan apa? Untuk mengetahui pengertian sains data, kamu harus mengetahui pengertian data terlebih dahulu. Data adalah kumpulan data yang diolah menjadi informasi, olahan informasi tersebut akan digunakan sebagai medium agar dapat mengambil keputusan. Data sendiri terdiri dari berbagai jenis seperti yang terstruktur, semi terstruktur serta tidak terstruktur.</p>\r\n<p>Sedangkan, sains data adalah sebuah ilmu terapan yang menganalisis serta mempelajari data, khususnya data numeric, baik terstruktur atau tidak terstruktur. Ilmu sains data ini adalah bidang ilmu gabungan mulai dari statistika, bisnis dan ilmu komputer.</p>', '<ul>\r\n<li>Pengetahuan konsep dan metode statistika serta matematika</li>\r\n<li>Pengetahuan model pemrograman</li>\r\n<li>Pengetahuan perangkat lunak sesuai kebutuhan</li>\r\n<li>Kemampuan mengolah dan menganalisis data agar menghasilkan rekomendasi proses pengambilan Keputusan</li>\r\n<li>Kemampuan menguasai Bahasa pemrograman, pengambilan informasi serta visualisasi data</li>\r\n<li>Kemampuan mengambil Keputusan sesuai data yang tersedia</li>\r\n</ul>', '<ul>\r\n<li>Banyak industry yang membutuhkan lulusan data sains. Seperti yang sudah disinggung sebelumnya, kebutuhan data sains sekarang semakin meningkat. Lulusan dari jurusan ini memiliki banyak peluang pekerjaan.</li>\r\n<li>Teknologi terus bergerak maju. Saat ini, pemerintah Indonesia memberikan dukungan penuh pada dunia teknologi. Bahkan bidang industry sekarang ini menggunakan teknologi digital untuk mengelola Perusahaan. Oleh sebab itu peran dari lulusan data sains begitu diperlukan untuk mengelola data tersebut.</li>\r\n<li>Kamu bisa memiliki keterampilan komunikasi. Jangan salah, jurusan sains data tidak melulu mengenai data. Ketika terjun dalam jurusan ini, kamu juga dituntut memiliki komunikasi yang baik, sehingga dapat menjelaskan data yang sudah diolah didepan umum agar audiens bisa memahami data tersebut.</li>\r\n<li>Memiliki peminatan pada data sains. Bila kamu merupakan orang yang senang melakukan analisis serta memecahkan masalah, jurusan ini menjadi pilihan yang tepat.</li>\r\n<li>Banyak ilmu yang bisa kamu ambil. Dalam jurusan ini, kamu bukan hanya fokus dalam satu bidang, sehingga kamu bukan hanya mempelajari masalah statistic. Kamu akan belajar seperti apa bahasa pemrograman yang digunakan.</li>\r\n<li>Ilmuan data semakin dibutuhkan. Dengan begitu banyaknya perusahan teknologi yang bermunculan, sekarang ini ilmuan data juga semakin dicari oleh industry, sehingga peluang karirmu akan terbuka sangat lebar di sini.</li>\r\n</ul>', '', '<p>Ketika menempuh pendidikan sains data di perguruan tinggi, kamu akan mempelajari bahasa pemrograman, khususnya yang dipergunakan untuk data mining. Pengolahan data serta interpretasi data yang akan kamu lakukan juga membutuhkan ilmu statistika.</p>\r\n<p>Ada berbagai macam mata kuliah sains data yang nantinya akan kamu pelajari seperti di semester 1, kamu akan belajar masalah Aljabar Linear untuk Sains Data, kemudian kamu juga akan mempelajari Pemrograman.</p>\r\n<p>Kemudian di semester berikutnya kamu akan mempelajari masalah Algoritma Pemrograman, ada pula mata kuliah Statistika, Struktur Data, Perancangan data Implementasi Basis Data. Berikutnya mata kuliah seperti Sistem Manajemen Basis Data, Infrastruktur dan Platform untuk Sains Data, Teori Peluang dan Implementasi.</p>\r\n<p>Pada pertengahan semester, kamu akan belajar mata kuliah Rekayasa Sistem Informasi, Keamanan Data, Rekayasa dan Organisasi Sistem Big Data, Penambangan Teks, Sains Data pada Industri dan lainnya.</p>\r\n<p>Setelah lulus jurusan ini, gelar sains data yang akan kamu dapatkan adalah sarjana komputer. Sobat karier semakin tertarik terjun ke jurusan ini?</p>\r\n<p>Universitas dengan jurusan Sains Data sebenarnya tidak begitu banyak, karena jurusan ini tergolong baru. Ada beberapa kampus di Indonesia yang memiliki jurusan ini seperti Telkom University, kemudian IPB atau Institut Pertanian Bogor, Universitas Airlangga, Universitas Nusa Mandiri, Universitas Teknologi Yogyakarta.</p>\r\n<p>Kampus lainnya seperti Institut Teknologi Sumatera, kemudian Universitas Bina Nusantara serta Universitas Katolik Parahyangan. Berbeda dengan beberapa kampus di atas, UI atau Universitas Indonesia juga mempunyai Data Science Center untuk Unit Kerja Khusus, sehingga UI juga menawarkan data sains sebagai mata kuliah.</p>\r\n<p>Kemudian, bila sudah menempuh pendidikan S1 Sains Data, kamu juga bisa semakin memperdalam keilmuan dengan masuk kedalam jurusan S2 Sains Data.</p>', 'sains_data.jpg'),
(4, 'Teknologi Informasi', '<p>jurusan Teknologi Informasi atau TI mendalami solusi-solusi terkait teknologi komputer yang diterapkan pada berbagai bidang, di antaranya yakni pemerintahan, kesehatan, pendidikan, termasuk pengembangan bisnis. Banyak orang yang menyamakan Jurusan TI ini dengan jurusan lain seperti Sistem Informasi dan Teknik Informatika. Padahal ketiganya tidak sama, sobat karir!</p>\r\n<p>Jurusan Teknik Informatika berfokus pada pemrograman dan pengembangan software atau aplikasi, sedangkan Jurusan Sistem Informasi berfokus pada hal lain di luar pemrograman yakni implementasi ilmu komputer dalam mendukung fungsi manajemen ataupun bisnis. Lalu, Jurusan Teknologi Informasi sendiri merupakan jurusan yang mempelajari tentang sistem atau teknologi olah data termasuk implementasinya pada berbagai hal, termasuk pengembangan software, artificial intelligence, dan pengembangan sistem informasi berbasis cloud. Dengan begitu, nantinya, lulusan Jurusan Teknologi Informasi akan sangat berperan dalam berbagai proses dalam membangun sistem informasi mulai dari pembuatan database, network, software, hardware, dan lain sebagainya.</p>\r\n<p>Lulusan Jurusan Teknologi Informasi banyak dibutuhkan karena saat ini peradaban dunia sudah memasuki era serba digital. Di mana kehidupan masyarakat banyak bergantung pada teknologi yang tengah berkembang pesat, sehingga tidak mengherankan jika Jurusan TI menjadi sasaran para millenials.</p>\r\n<p>Jika sudah menempuh pendidikan Prodi Teknologi Informasi, setelah lulus kamu akan mempunyai kemampuan dan pengetahuan secara detail terkait hardware dan software, serta bagaimana mengatasi segala bentuk masalah yang terjadi pada komputer. Kamu pun akan memiliki kemampuan untuk mengelola informasi dan data yang cepat dan juga berkualitas.</p>', '<ul>\r\n<li>Kemampuan membangun, mengelola, dan mengembangkan sistem informasi</li>\r\n<li>Pemahaman database</li>\r\n<li>Kemampuan observasi dan identifikasi masalah</li>\r\n<li>Kemampuan analisis</li>\r\n<li>Penguasaan dasar-dasar pemrograman</li>\r\n<li>Kemampuan komunikasi</li>\r\n</ul>', '<ul>\r\n<li>Banyak perusahaan baik itu perusahaan&nbsp;<em>startup</em>maupun perusahaan yang sudah stabil membuka kesempatan bagi lulusan Jurusan Teknologi Informasi. Hal tersebut karena saat ini fokus persaingan dalam memenangkan konsumen sudah banyak bergeser ke media digital sehingga diperlukan orang-orang yang dapat membantu perusahaan untuk membangun media digitalnya sendiri.</li>\r\n<li>Selain dicari banyak perusahaan besar, gaji untuk karyawan atau pegawai bidang Teknologi Informasi cukup besar, karena tidak semua orang bisa bekerja sebagai pegawai bidang TI. Posisi karyawan TI sendiri dianggap berkelas karena memang pekerjaannya cukup berpengaruh dan tidak sembarang orang bisa melakukannya.</li>\r\n<li>Jika sudah menjadi pegawai bidang TI, pekerjaannya akan sangat bervariasi. Tidak hanya berkutat dengan komputer saja, tetapi banyak aktivitas kerja yang seru seperti robotika hingga bioteknologi. Tentu ini adalah salah satu hal positif yang bisa dijadikan pertimbangan memilih Jurusan TI.</li>\r\n<li>Mengingat teknologi terus mengalami perkembangan, ini membuat Sarjana Teknologi Informasi terus mempelajari hal baru. Jika saat menempuh pendidikan TI yang dipelajari teori, maka saat sudah bekerja akan banyak hal baru yang didapatkan karena teknologi mengalami kebaruan yang terus menerus.</li>\r\n<li>Lulusan Jurusan Teknologi Informasi juga bisa menjadi&nbsp;<em>freelancer</em>yang mendapatkan&nbsp;<em>fee</em>&nbsp;per&nbsp;<em>project</em>&nbsp;dengan jumlahnya relatif besar.</li>\r\n<li>Berkarier sebagai ahli Teknologi Informasi memiliki jam kerja yang tergolong fleksibel karena tidak melulu di balik meja. Banyak permasalahan komputer yang nantinya diselesaikan di lapangan secara langsung. Nilai tambahnya, ahli TI lebih paham dalam urusan logika dan memecahkan sebuah masalah di kehidupan sehari-hari</li>\r\n</ul>', '<p>Ada banyak posisi yang bisa dipilih lulusan Jurusan TI nantinya, misalnya menjadi konsultan teknologi informasi. Konsultan TI adalah pekerjaan yang saat ini sedang naik daun. Tanggung jawab dan tugas konsultan TI adalah memberikan evaluasi pada sistem yang ada serta memberikan bantuan pada perusahaan dalam memilih cara tercepat dan termurah dalam mengoperasikan sistem.</p>\r\n<p>Selain itu, lulusan TI juga bisa memilih untuk menjadi seorang arsitek&nbsp;<em>cloud</em>, profesi yang masih tergolong baru. Kemunculan profesi ini untuk mengikuti perkembangan teknologi&nbsp;<em>cloud</em>&nbsp;yang cukup&nbsp;<em>massive</em>&nbsp;saat ini. Fokus kerjanya adalah pada pengembangan sistem dan&nbsp;<em>software</em>. Arsitek&nbsp;<em>cloud&nbsp;</em>bertanggung jawab dalam merencanakan dan mendesain, hingga memberikan pengarahan pada masa proyek penerapan juga menjadi tugas profesi ini. Pada intinya arsitek&nbsp;<em>cloud</em>&nbsp;ini bekerja pada bagian teknologi dan bisnis. Untuk sisi bisnis di sini, profesi arsitek cloud perlu memahami fungsionalitas apa yang diperlukan perusahaan dan keuntungan yang bisa diambil.</p>\r\n<p>Profesi lainnya yang bisa dipilih lulusan Teknologi Informasi adalah menjadi seorang digital forensik. Profesi ini juga tidak untuk sembarang orang. Hanya ahli TI saja yang bisa menjalankan profesi satu ini. Tugasnya adalah mencari, mengidentifikasi, hingga melakukan evaluasi informasi dari barang bukti berbasis digital. Ini sangat dibutuhkan karena semakin banyak kejahatan yang terjadi di tengah masyarakat lewat media digital. Penegak hukum membutuhkan bantuan ahli digital forensik dalam mengungkap segala bentuk kejahatan TI.</p>', '<p>Kuliah di Jurusan Teknologi Informasi nantinya kamu mendapatkan pelajaran tentang cara merancang, mengimplementasi, hingga melakukan konfigurasi dan melakukan perawatan infrastruktur yang berhubungan dengan komputer dan Teknologi Informasi.</p>\r\n<p>Selama perkuliahan,&nbsp;<strong>mata kuliah</strong>&nbsp;yang sobat karier dapatkan difokuskan pada aspek teknologinya. Kamu akan dituntut untuk mempunyai pengetahuan dan&nbsp;<em>skill</em>, hingga pengalaman dalam memilih produk&nbsp;<em>hardware</em>&nbsp;dan&nbsp;<em>software</em>&nbsp;yang sesuai dengan infrastruktur sistem informasi perusahaan, termasuk&nbsp;<em>skill</em>&nbsp;meng-<em>upgrade</em>&nbsp;hingga merawat sistem yang dibangun.</p>\r\n<p>&nbsp;</p>\r\n<p>Menjadi Sarjana Teknologi Informasi harus bisa algoritma komputasi dengan baik. Mata kuliah yang didapatkan fokus pada perancangan dan pengembangan&nbsp;<em>software</em>&nbsp;dan aplikasi. Mata kuliah yang akan didapatkan seperti Logika Matematika, Komputasi, hingga Algoritma. Sedangkan mata kuliah yang berhubungan dengan kemampuan teknis antara lain Jaringan Komputer,&nbsp;<em>System Sequrity</em>, IT Forensik,&nbsp;<em>Cloud Computing</em>,&nbsp;<em>Mobile Programming</em>, dan Rekayasa Perangkat Lunak.</p>\r\n<p>Nantinya, para alumni atau lulusan dari Jurusan TI akan memiliki&nbsp;<strong>gelar S. TI</strong>&nbsp;di belakang nama mereka. Setelah itu, peluang kerja pun akan terbuka sangat lebar untuk mereka.</p>', 'teknologi_informasi.jpg'),
(5, 'Study bisnis', '<p>Beberapa tahun belakangan, Jurusan Bisnis menjadi salah satu jurusan favorit di berbagai kampus di Indonesia. Jurusan ini cocok&nbsp;<em>banget</em>&nbsp;untuk kamu yang memiliki visi menjadi seorang pengusaha muda. Bisnis merupakan bidang ilmu yang mempelajari bagaimana melakukan pemasaran produk, pembukuan dan pengelolaan keuangan serta hal-hal terkait keberlanjutan dari suatu usaha. Bidang ini membantu memahami kebutuhan pelanggan dan mengkomersialisasikannya. Jadi, bisa dibilang bidang ini merupakan kombinasi dari Manajemen dan Akuntansi</p>', '<ul>\r\n<li>Kemampuan manajerial</li>\r\n<li>Kemampuan komunikasi</li>\r\n<li>Kemampuan negosiasi</li>\r\n<li>Kemampuan melakukan observasi</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan meneliti</li>\r\n</ul>', '<ul>\r\n<li>Kamu punya bekal yang kuat untuk mulai terjun ke dunia bisnis, jadi setelah lulus kuliah bisa banget memulai karier sebagai seorang Pengusaha.</li>\r\n<li>Kamu bisa mengaplikasikan ilmu bisnis dalam bidang apapun,sob! Karena perdagangan barang dan jasa yang melewati batas negara saat ini semakin masif. Bisa go international deh!</li>\r\n<li>Kamu bisa menciptakan lapangan pekerjaan bagi orang banyak lho. Tentu saja lewat usaha yang kamu bangun.</li>\r\n<li>Sumber referensi ilmu bisnis luas banget. Kamu bisa mempelajarinya secara mendalam dari buku, jurnal ilmiah, majalah bisnis, situs-situs internet hingga video di youtube.</li>\r\n<li>Kamu punya kesempatan yang luas untuk melanjutkan studi jenjang pascasarjana di kampus-kampus top dunia dengan program beasiswa</li>\r\n</ul>', '<p>Ada banyak sekali peluang karier yang menanti lulusan Jurusan Bisnis. Bahkan peluang itu bisa sobat karier, ciptakan sendiri,&nbsp;<em>lho</em>! Berbekal keilmuan dan keterampilan yang kamu dapatkan di bangku kuliah, lulusan Bisnis punya nilai jual yang patut dibanggakan. Banyak perusahaan membutuhkanmu untuk ikut ambil bagian dalam mengembangkan bisnisnya. Untuk&nbsp;<em>fresh graduate</em>, mulai berkarier lewat&nbsp;<em>business development program</em>&nbsp;di suatu perusahaan adalah pilihan yang sebaiknya tidak dilewatkan. Beberapa perusahaan juga ada yang menawarkan jalur&nbsp;<em>management trainee</em>. Berbekal ilmu bisnis yang kamu miliki, kamu berkesempatan mengembangkan potensimu di sektor apapun. Seperti dari bisnis retail,&nbsp;<em>fast moving consumer goods</em>,&nbsp;<em>fashion</em>, pariwisata, properti, dan sebagainya. Jenjang karier untuk lulusan Bisnis sangat bervariasi,sob! Secara umum, pendapatan rata-rata lulusan Jurusan Bisnis berada pada kisaran Rp4.000.000, dengan pekerjaan sebagai staf dari bidang tertentu di suatu perusahaan. Tentu saja, besaran ini memperhatikan kemampuan dan pengalaman yang kamu dimiliki, area tempat bekerja, juga tingkatan yang dimasuki.</p>', '<p>Umumnya, supaya bisa meraih gelar&nbsp;<strong>Sarjana Bisnis</strong>&nbsp;atau&nbsp;<strong>Sarjana Manajemen</strong>, kamu akan harus melalui perkuliahan selama 4 tahun atau 8 semester. Jurusan ini banyak ragamnya&nbsp;<em>lho</em>! Ada yang memberi nama jurusan Bisnis, Manajemen Bisnis, Manajemen Bisnis Internasional, juga Manajemen Bisnis Syariah. Kuliah di jurusan Bisnis akan difokuskan pada bagaimana mengelola sumber daya dalam usaha secara berkelanjutan agar terus berkembang. Kamu akan dibekali dengan cara mengelola perusahaan mulai dari finansial, operasional, pemasaran, juga organisasi bisnis. Nah, kalau jurusan Bisnis Syariah, tentu saja yang kamu pelajari adalah bagaimana mengelola bisnis menggunakan prinsip-prinsip syariah. Di jurusan Bisnis, kamu pun akan mempelajari cara membangun bisnis dari nol. Seru&nbsp;<em>banget</em>&nbsp;deh!</p>\r\n<p>&nbsp;</p>\r\n<p>Beberapa&nbsp;<strong>mata kuliah</strong>&nbsp;yang bisa kamu temui misalnya Komunikasi Bisnis, Bisnis Internasional, Perilaku Konsumen, Penjualan dalam Bisnis,&nbsp;<em>Business Creation</em>,&nbsp;<em>Business Development</em>, Manajemen Keuangan, Manajemen Operasi, Manajemen Pemasaran, Manajemen Stretegis, Perpajakan, Teknologi Informasi untuk Bisnis, Desain dan Dinamika Organisasi,&nbsp;<em>Decision Analysis</em>,&nbsp;<em>Leadership</em>, Ekonomika Strategi,&nbsp;<em>Knowledge of Creative Business</em>, Sistem Informasi Manajemen, dan sebagainya. Setelah lulus, kamu bisa melanjutkan studi pascasarjana di kampus-kampus top dunia! Ada banyak sekali pilihan kampus bergengsi di luar negeri yang bisa kamu jadikan referensi. Setiap kampus biasanya menawarkan program yang beragam, tinggal sesuaikan dengan minatmu ya!</p>\r\n<p>&nbsp;</p>\r\n<p>Saat ini bisnis terus berkembang sama halnya program studi di perguruan tinggi negeri, maka hadir nya jurusan&nbsp;<a href=\"https://campus.quipper.com/majors/id-bisnis-digital\">bisnis digital</a>&nbsp;karena perkembangan bisnis dimana banyak perusahaan menjalankan bisnis melalui online atau digital.</p>', 'study_bisnis.jpg'),
(6, 'Ekonomi', '<p>Sobat karir, jika kalian ingin belajar ilmu ekonomi, kalian akan fokus pada upaya pengalokasian sumber daya yang terbatas dan memperoleh keuntungan optimal. Selain itu, kamu juga akan mengeksplorasi upaya pemberdayaan ekonomi. Dewasa ini, tren pembelajaran Ilmu Ekonomi mulai banyak yang mengarah pada behavioral economics loh sob! Selain itu, mulai berkembang pula crime economics, jadi kamu bisa melakukan analisis terhadap permasalahan hukum yang ditinjau dari sisi ekonomi. Menarik kan?</p>', '<ul>\r\n<li>Kemampuan matematika</li>\r\n<li>Kemampuan observasi terhadap masalah sosial-ekonomi</li>\r\n<li>Kemampuan berpikir logis dan terstruktur</li>\r\n<li>Kemampuan berpikir kritis</li>\r\n<li>Kemampuan menganalisis</li>\r\n<li>Kemampuan menyelesaikan persoalan</li>\r\n</ul>', '<ul>\r\n<li>Lulusan Ilmu Ekonomi sangat dibutuhkan di pemerintahan sebagai analis, karena nantinya kamu akan memiliki peranan yang cukup penting dalam roda perekonomian negara, baik di sektor fiskal maupun moneter.</li>\r\n<li>Bagi kamu yang suka melakukan observasi masalah sosial-ekonomi dan meneliti perilaku individu, cocok sekali dengan jurusan ini, mengingat banyaknya lembaga penelitian yang membutuhkan lulusan Ilmu Ekonomi</li>\r\n<li>Seiring dengan semakin terbukanya keran globalisasi dan semakin terintegrasinya negara-negara di dunia, maka lulusan Ilmu Ekonomi juga sangat dibutuhkan dalam perdagangan internasional.</li>\r\n<li>Salah satu lembaga bergengsi yang banyak membutuhkan lulusan Ilmu Ekonomi adalah Bank Indonesia, nggak ketinggalan deretan lembaga keuangan internasional lain seperti World Bank, International Monetary Fund, Asian Development Bank, dan lainnya</li>\r\n<li>Pilihan fokus studi di jenjang pascasarjana juga sangat beragam lho</li>\r\n</ul>', '<p>Peluang karier yang menanti lulusan Ilmu Ekonomi banyak banget, mulai dari institusi dalam negeri hingga institusi asing. Jenis pekerjaan dan jenjang karier yang ditawarkan pun cukup bervariasi. Soal gaji, jangan khawatir karena dijamin kompetitif kok! Tentunya rentang gaji bergantung pada level pekerjaan yang dimasuki, area tempat bekerja, kemampuan, serta pengalaman yang dimiliki. Meski umumnya, pilihan karier yang utama bagi lulusan Ilmu Ekonomi biasanya di sektor keuangan namun pada dasarnya banyak potensi yang bisa kamu kembangkan bahkan sobat karier juga bisa bekerja di sektor media maupun kreatif.</p>', '<p>Nantinya selama 4 tahun atau 8 semester sobat karir! tidak hanya belajar soal teknik pengambilan sebuah keputusan secara rasional, efektif, dan efisien. Karena kamu dituntut untuk dapat mengalokasikan sumber daya terbatas agar tercapai keuntungan optimal. Namun, dalam hal ini tidak hanya terbatas pada maksimisasi profit dan minimalisasi biaya lho.</p>\r\n<p>Nah, selama ini banyak orang beranggapan kalau kuliah di Ekonomi pasti akan jauh deh dari yang namanya Matematika. Ternyata, jurusan Ilmu Ekonomi itu justru dekat banget hubungannya dengan Matematika. Kenapa bisa begitu ya? Karena sejatinya Matematika dalam Ilmu Ekonomi itu merupakan alat analisis dan &ldquo;bahasa&rdquo; yang akan memudahkanmu memahami suatu fenomena yang sulit dijelaskan secara naratif.</p>\r\n<p>Jika sobat karier ingin lulus dari jurusan Ilmu Ekonomi dan menyandang gelar Sarjana Ekonomi, kamu akan menemui mata kuliah seperti Mikroekonomika, Makroekonomika, Statistika Ekonomi, Matematika Ekonomi, Ekonometrika, Ekonomika Pembangunan, Ekonomika Publik, Ekonomika Moneter, Perdagangan Internasional, Keuangan Internasional, Teori Permainan, Ekonomika Regional, Ekonomika Tenaga Kerja, Ekonomika Sumber Daya Alam dan Lingkungan, dll. Oh iya, jurusan ini juga cukup besar lho peminatnya di jenjang pascasarjana. Pilihan kampusnya pun sangat beragam dengan fokus riset yang berbeda pula.</p>\r\n<p>Jika masih bimbang tentang jurusan ini, kamu juga bisa mengetahui jurusan yang lebih spesifik seperti perpajakan, Ekonomi Syariah, Ekonomi Pembangunan.</p>', 'ekonomi.jpg'),
(7, 'Akuntansi', '<p>Sobat karier, pasti sudah nggak asing dengan Jurusan Akuntansi. Jurusan Akuntansi adalah bidang studi yang mempelajari materi terkait metode pencatatan dan penyusunan laporan keuangan yang berguna membantu pemangku kepentingan dalam proses pengambilan keputusan.</p>\r\n<p>Jurusan Akuntansi dikenal sebagai jurusan yang sangat dekat dengan angka, khususnya segala sesuatu yang terkait dengan keuangan. Meskipun begitu, mahasiswa Jurusan Akuntansi tidak hanya belajar tentang cara menghitung uang, termasuk juga tentang manajemen, perpajakan, sistem informasi, hingga pengauditan</p>', '<ul>\r\n<li>Pengetahuan dan Keahlian</li>\r\n<li>Kemampuan mengelola keuangan</li>\r\n<li>Kemampuan mengevaluasi anggaran</li>\r\n<li>Kemampuan menyajikan laporan keuangan</li>\r\n<li>Kemampuan menilai laporan keuangan</li>\r\n<li>Kemampuan menginterpretasikan angka</li>\r\n<li>Kemampuan menganalisis</li>\r\n<li>Kemampuan membuat rekomendasi</li>\r\n<li>Teliti dalam menghitung</li>\r\n</ul>', '<ul>\r\n<li>Setiap sektor membutuhkan staf di bidang Akuntansi, bisa dikatakan jika prospek kerja jurusan ini sangat bagus. Jadi, akan sangat mudah bagi lulusan Akuntansi untuk bekerja di sektor apapun.</li>\r\n<li>Jenjang karier yang ditawarkan bagi lulusan Akuntansi khususnya di bagian keuangan juga cukup menjanjikan lho.</li>\r\n<li>Jurusan Akuntansi sangat tepat bagi kamu yang ingin terjun ke dunia bisnis.</li>\r\n<li>Jika kamu tidak ingin sekadar menjadi staf di suatu perusahaan, kamu bisa membuka lapangan pekerjaan dengan mendirikan kantor sendiri seperti Kantor Akuntan Publik.</li>\r\n<li>Kamu bahkan bisa meningkatkan keunggulan dalam dirimu dengan mengambil sertifikasi profesional di bidang Akuntansi.</li>\r\n<li>Kamu yang suka membantu orang lain, juga bisa membuka Kantor Konsultan Pajak. Lulusan Akuntansi juga bisa jadi pengacara lho , tetapi pengacara pajak ya!</li>\r\n</ul>', '<p>Kamu tidak perlu bertanya-tanya kira-kira lulusan Jurusan Akuntansi akan bekerja dimana, karena prospek kerja lulusannya sangat luas! Bisa dikatakan, hampir seluruh sektor membutuhkan lulusan Akuntansi. Jenjang karier yang ditawarkan pun cukup bervariasi. Secara umum, rata-rata gaji awal lulusan Akuntansi berada pada kisaran Rp4.000.000, dengan pekerjaan sebagai staf bagian keuangan. Meskipun begitu, besaran ini sangat bergantung pada kemampuan, area tempat bekerja, tingkatan jabatan, dan pengalaman yang dimiliki.</p>\r\n<p>Karier di sektor keuangan menjadi pilihan utama bagi lulusan Akuntansi. Tapi, jangan salah sob, industri non-keuangan, pemerintahan, dan lembaga nirlaba juga patut dicoba untuk mengembangkan potensi dan keahlian yang bisa kamu miliki.</p>\r\n<p>&nbsp; Selain peluang di berbagai perusahaan swasta kini banyak dibutuhkan juga sesorang yang spesifik memahami keuangan secara syariah atau mengikuti ajaran islam, di beberapa perguruan tinggi juga ada jurusan akuntansi syariah untuk program sarjana.</p>', '<p>Kuliah di Jurusan Akuntansi, akan ditempa untuk mempelajari banyak hal tentang laporan keuangan. Selama 4 tahun atau 8 semester, agar meraih gelar Sarjana Akuntansi atau Sarjana Ekonomi, kamu akan belajar segala hal tentang laporan keuangan. Mulai dari bagaimana membuat laporan keuangan yang sesuai dengan standar masing-masing perusahaan, melakukan analisis laporan keuangan, menilai kelayakan usaha lewat laporan keuangan, sampai menilai prospek kedepannya. Selain itu, juga belajar audit, yang secara sederhana kamu akan mempelajari cara melihat apakah laporan keuangan dapat dikatakan layak atau tidak.</p>\r\n<p>Beberapa mata kuliah yang akan sobat karir jumpai di Jurusan Akuntansi, antara lain Akuntansi Keuangan, Akuntansi Manajemen, Akuntansi Biaya, Analisis Laporan Keuangan, Perpajakan, Pengauditan, Sistem Informasi Akuntansi, Akuntansi Sektor Publik, Akuntansi Pemerintahan, dll.</p>\r\n<p>Jika kamu bercita-cita ingin menjadi Akuntan profesional, jangan lupa menempuh Pendidikan Profesi Akuntan setelah lulus S1. Kamu juga bisa mengambil program sertifikasi untuk meningkatkan kemampuanmu. Misalnya, dengan mengambil Certified Public Accountant (CPA) atau Certified Management Accountant (CMA). Kalau kamu ingin jadi auditor, bisa mengambil Certified Internal Auditor (CIA) atau bisa juga mengambil Certified Information System Auditor (CISA). Selain itu, kalau kamu ingin menempuh pendidikan lanjut. Banyak juga lho kampus yang menawarkan program pascasarjana. Kamu bisa pilih, mau mengambil peminatan apa dan di kampus bergengsi mana. Jurusan lainnya yang fokus pada keuangan yaitu aktuaria yang mana spesifik mempelajari perhitungan resiko.</p>', 'akuntansi.jpg'),
(8, 'Aktuaria ', '<p>Jurusan Aktuaria adalah jurusan yang mempelajari ilmu probabilitas, matematika, statistik dan keuangan untuk dapat melakukan pengelolaan resiko dan ketidakpastian dalam membantu client meminimalkan resiko.</p>\r\n<p>&nbsp;</p>\r\n<p>Lulusan Jurusan Aktuaria akan mendapat gelar Sarjana Ilmu Aktuaria (S.Aktr), tetapi belum bisa disebut sebagai aktuaris. Untuk menjadi seorang aktuaris, kamu harus mengikuti dan lulus ujian profesi aktuaris yang diselenggarakan oleh Persatuan Aktuaris Indonesia (PAI).</p>\r\n<p>&nbsp;</p>\r\n<p>Profesi aktuaris tengah menjadi sorotan atau prioritas Otoritas Jasa Keuangan (OJK) yang gencar melakukan sosialisasi program 1000 aktuaris. Data menyebutkan saat ini jumlah aktuaris di Indonesia baru memenuhi sekitar 50% dari kuota yang diharapkan. So, hal tersebut bisa membuka peluang yang besar bagi sobat karir yang ingin berkarier di bidang ini.</p>', '<ul>\r\n<li>Kemampuan analisis</li>\r\n<li>Kemampuan berpikir strategis</li>\r\n<li>Kemampuan matematika</li>\r\n<li>Kemampuan riset</li>\r\n<li>Kemampuan manajemen risiko</li>\r\n</ul>', '<ul>\r\n<li>Lulusannya tersebar di perusahaan besar</li>\r\n<li>Gaji yang ditawarkan untuk profesi aktuaris tergolong tinggi</li>\r\n<li>Meningkatkan kemampuan aplikatif bernalar dan berhitung karena permasalahan yang dikaji dalam bidang ini cukup kompleks</li>\r\n</ul>', '<p>Lulusan Jurusan Aktuaria sebagian besar melanjutkan program sertifikasi untuk menjadi seorang aktuaris. Namun, pilihan karier seorang alumni jurusan ini tidak hanya menjadi seorang aktuaris. Beberapa prospek yang bisa kamu pilih setelah menyelesaikan pendidikan di Jurusan Aktuaria yaitu :</p>\r\n<ul>\r\n<li>Akuntan</li>\r\n<li>Ekonom</li>\r\n<li>Aktuaris</li>\r\n</ul>', '<p>Pilihan program kuliah Jurusan Aktuaria di Indonesia awalnya hanya tersedia pada program vokasi (D3). Namun, seiring berjalannya waktu kampus-kampus juga mulai menyelenggarakan program untuk Strata 1 (S1). Untuk menjadi seorang sarjana aktuaria, kamu akan menghabiskan waktu 8 semester dengan skripsi sebagai tugas akhir.</p>\r\n<p>Akan lebih baik jika kamu memilih jurusan ini karena kamu menyukai hal-hal yang berhubungan dengan analisis, matematika, dan statistika, dengan berbagai aplikasinya agar tidak merasa terbebani ketika menjalani kuliah dan mengerjakan tugas-tugasnya.</p>\r\n<p>Apalagi nantinya untuk menjadi seorang aktuaris, kamu harus meluluskan ujian profesi yang diselenggarakan oleh Perhimpunan Aktuaris Indonesia (PAI). Terdapat 10 mata ujian dimana untuk mendapat gelar Ajun Aktuaris atau Associate Society of Actuaries of Indonesia (ASAI) diperlukan kelulusan 7 mata ujian di awal. Lalu dilanjutkan dengan kelulusan untuk 3 mata ujian lanjutan untuk memperoleh gelar Aktuaris atau Fellow Society of Actuaries of Indonesia (FSAI), gelar profesi puncak dalam aktuaria.</p>\r\n<p>Setiap universitas yang memiliki jurusan aktuaria tentunya memiliki kurikulum yang berbeda-beda. Namun, pada dasarnya jumlah SKS yang harus diselesaikan pada program S1 Aktuaria adalah 144 SKS. Beberapa mata kuliah khas yang ditemui di jurusan ini adalah Pemodelan Risiko, Model Stokastik, Perangkat Lunak Aktuaria, dan mata kuliah yang berhubungan dengan asuransi.</p>\r\n<p>Jika kamu ingin mempelajari tentang finansial secara general, kamu dapat mengambil jurusan akuntansi dimana mempelajari hal dasar hingga spesifik.</p>', 'aktuaria_.jpg'),
(9, 'Sekretaris', '<p>Jurusan sekretaris adalah jurusan yang mengkaji tentang seluk-beluk dunia kesekretariatan sehingga diharapkan lulusannya siap menjalani karier sekretaris secara profesional. Tugas sekretaris pada umumnya yakni untuk membantu pimpinan dalam menangani tugas-tugasnya. Maka, di jurusan ini kamu dituntut untuk menguasai keterampilan dalam menyelesaikan masalah-masalah organisasi.</p>\r\n<p>&nbsp;Keterampilan yang dimaksud di antaranya seperti pengetahuan dan keterampilan di bidang korespondensi, teknologi informasi, menyediakan peralatan perkantoran, serta melakukan perencanaan, pendataan, hingga pendistribusian informasi maupun surat menyurat perusahaan.</p>', '<ul>\r\n<li>Kemampuan komunikasi</li>\r\n<li>Kemampuan berpikir logis</li>\r\n<li>Keahlian mengoperasikan komputer</li>\r\n<li>Kemampuan mengetik cepat</li>\r\n<li>Kemampuan menulis</li>\r\n<li>Kemampuan bahasa Indonesia dan bahasa asing</li>\r\n<li>Kemampuan tata kearsipan</li>\r\n<li>Kemampuan menyusun laporan</li>\r\n<li>Kemampuan time management</li>\r\n</ul>', '<ul>\r\n<li>Prospek kerja sebagai sekretaris menjanjikan, Banyak perusahaan yang mencari lulusan Jurusan Sekretaris dan menawarkan gaji cukup besar.</li>\r\n<li>Kamu akan mendapatkan banyak pengetahuan mengenai manajemen perusahaan. Cukup banyak mata kuliah seputar manajemen yang akan diperoleh</li>\r\n<li>Kamu akan mendapatkan mata kuliah bahasa asing diantaranya bahasa Inggris, bahasa Mandarin dan bahasa Jepang. Hal ini dikarenakan keterampilan bahasa asing sangatlah penting terutama sebagai seorang sekretaris. Kamu dituntut untuk dapat menguasai ketiga bahasa tersebut, terutama bahasa Inggris, baik secara tulisan maupun lisan untuk mendukung pekerjaan kamu nantinya</li>\r\n<li>Mahasiswa Jurusan Sekretaris juga akan dibekali kemampuan menggunakan komputer. Mengingat sekretaris dituntut untuk bekerja cepat, maka kamu akan dibekali kemampuan mengetik cepat. Selain itu, kamu juga harus bisa menguasai Microsoft Office seperti Word, Excel, Power Point, bahkan meng-handle database.</li>\r\n<li>Kamu akan lebih sering melakukan praktik maupun presentasi. Seringkali praktik dibuat serealistis mungkin seolah mahasiswa telah bekerja di perusahaan sebagai sekretaris. Seperti mengadakan meeting, presentasi, dan masih banyak lagi. Kegiatan seperti ini sangat cocok bagi kamu yang suka gaya perkuliahan menyenangkan dan kreatif.</li>\r\n</ul>', '<p>Lulusan Program Studi Kesekretarisan memiliki prospek kerja yang cukup luas. Mereka akan sangat dibutuhkan perusahaan, tetapi tak menutup kemungkinan untuk berkarier sebagai pengajar.</p>\r\n<p>Profesi utama yang bisa ditekuni lulusan jurusan ini tidak lain dan tidak bukan ialah sekretaris. Profesi sekretaris amat sangat dibutuhkan di berbagai perusahaan dan industri, baik itu skala lokal, nasional, multi nasional hingga asing. Bahkan, di satu perusahaan biasanya dibutuhkan lebih dari satu sekretaris sesuai tingkatannya, mulai dari sekretaris bagian, departemen, divisi, direksi, komisaris, dan perusahaan.</p>\r\n<p>Selain menjadi sekretaris, peluang lain yakni menjadi resepsionis. Resepsionis memiliki beberapa tugas utama seperti menerima sekaligus melayani tamu, menerima dan menghubungkan telepon, menerima dan meneruskan paket, serta mengatur jadwal pertemuan klien dengan pihak kantor. Lulusan jurusan ini juga berpeluang berkarier sebagai staf administrasi, bertugas mengatur serta menata administrasi kantor.</p>\r\n<p>Kamu juga bisa bergabung dengan event organizer sebagai event planner atau sejenisnya. Tugasnya merencanakan, menyusun, hingga menyelenggarakan acara. Kamu bisa membuka sendiri jasa event organizer lho dengan potensi penghasilan mencapai ratusan juta.</p>\r\n<p>Selain itu, kamu juga bisa menjadi personal assistant dan bekerja langsung pada pada orang-orang yang membutuhkan jasa personal assistant. Biasanya yang membutuhkan jasa personal assistant yaitu kalangan direksi dan eksekutif. Tugasnya adalah untuk membantu atasan melakukan tugas harian. Seringkali tugasnya tidak sebatas di kantor, melainkan juga membantu atasan dalam kehidupan sehari-hari. Kemudian bila tidak ingin bekerja di perusahaan, lulusan jurusan ini juga bisa bekerja sebagai tenaga pengajar. Seperti menjadi guru di sekolah kejuruan administrasi atau menjadi dosen.</p>', '<p>Tujuan Program Studi Sekretaris adalah untuk menghasilkan ahli madya di bidang kesekretariatan yang terampil dan profesional. Sehingga selama perkuliahan, kamu akan merasakan kegiatan perkuliahan yang realistis. Maka, kuliah di jurusan ini akan membuat kamu lebih sering mengikuti praktik daripada teori. Adapun praktik tersebut di antaranya presentasi yang mana tujuannya adalah untuk melatih mahasiswa terbiasa tampil dan mampu berkomunikasi dengan baik.</p>\r\n<p>Adapun mata kuliah yang akan kamu dapatkan bila memilih jurusan ini meliputi Azas-azas Manajemen, Bahasa Indonesia, Bahasa Inggris, Mengetik Cepat, Pendidikan Etika dan Kearifan Lokal, dan Kesekretariatan.</p>\r\n<p>Kamu juga akan mendapatkan materi seputar pengantar bisnis, akuntansi, perbankan, manajemen pemasaran, pengembangan diri, teknik negosiasi, dan manajemen kearsipan. Selain itu, juga materi seputar manajemen logistik, manajemen Sumber Daya Manusia, sistem informasi manajemen, manajemen perkantoran, manajemen personalia, dan lain sebagainya.</p>\r\n<p>Program Studi Sekretaris juga memiliki mata kuliah yang berhubungan dengan komunikasi. Adapun Ilmu Komunikasi yang diajarkan di jurusan ini tak lain adalah untuk membekali kamu untuk dapat berkomunikasi dengan baik ketika berkarier nanti.</p>\r\n<p>Kamu akan mendapatkan mata kuliah bahasa asing diantaranya bahasa Inggris. Beberapa kampus mungkin menyediakan mata kuliah bahasa asing lain, seperti bahasa Mandarin, bahasa Jepang, dan bahasa Korea untuk memenuhi kebutuhan perusahaan yang bergerak secara internasional. Perkuliahan terasa semakin realistis terutama bila pengajar atau dosennya pernah bekerja sebagai sekretaris selama bertahun-tahun. Kamu bisa mendapatkan ilmu dan pengetahuan tambahan dari pengalaman sang dosen.</p>\r\n<p>Di jurusan ini, mahasiswa juga dituntut untuk selalu tampil rapi, disiplin waktu, cekatan dalam mengerjakan sesuatu dan berpikir kreatif. Sebab sikap-sikap tersebut akan sangat diperlukan setelah nanti lulus dan bekerja sebagai sekretaris.</p>\r\n<p>Untuk menempuh Program Studi Sekretaris, kamu dapat memilih untuk mendaftar di Akademi Sekretari dan Manajemen, Sekolah Tinggi Ilmu Komunikasi dan Sekretari, universitas swasta maupun universitas negeri yang menyediakan jurusan tersebut. Biasanya tersedia untuk jenjang D3 dan S1</p>', 'sekretaris.jpg'),
(10, 'Pendidikan dokter', '<p>Ini nih, salah satu Jurusan favorit banyak calon mahasiswa. Meski dikenal dengan perkuliahan yang padat dan ditempuh dengan waktu yang cukup lama, Jurusan Pendidikan Dokter nggak pernah sepi peminat. Saat berkuliah di Pendidikan Dokter kamu akan mempelajari cara mendiagnosis penyakit yang dialami pasien kemudian mengobati dan mencegah timbulnya kembali penyakit itu. Selama kuliah kamu banyak belajar anatomi tubuh manusia, biologi sel dan molekuler, genetika, biokimia, juga farmakologi. Kamu juga dibekali dengan latihan keterampilan dalam skill lab. Nah setelah fase perkuliahan pre-klinik, kamu bakalan dapat pelatihan dasar di berbagai stase di Rumah Sakit. Setelah itu, baru deh diputuskan mau langsung ambil program spesialisasi atau bekerja pada institusi Kesehatan</p>', '<ul>\r\n<li>Kemampuan melakukan observasi</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan berpikir kritis dan terstruktur</li>\r\n<li>Kemampuan problem solving</li>\r\n<li>Keterampilan komunikasi</li>\r\n<li>Detil, Teliti, Tekun</li>\r\n</ul>', '<ul>\r\n<li>Soal prospek kerja jangan ditanya lagi, lulusan Pendidikan Dokter biasanya tidak sulit dapat pekerjaan. Jika sudah sah menyandang gelar Dokter, kamu bisa praktik di Rumah Sakit, puskesmas, klinik kesehatan, atau membuka praktik pribadi</li>\r\n<li>Di Rumah Sakit, selain praktik kamu juga bisa terlibat dalam proses pengelolaan pelayanan medis maupun non-medis</li>\r\n<li>Jika ingin bekerja struktural, ada banyak instansi pemerintah yang memerlukan seorang Dokter, seperti BPOM, Basarnas, juga BNN. Kamu juga bisa lho jadi tenaga medis di TNI dan Polri</li>\r\n<li>Kalau kamu menaruh minat pada dunia akademis maupun penelitian, bisa jadi seorang Dosen sekaligus Peneliti yang fokus meneliti pengobatan suatu penyakit.</li>\r\n<li>Setelah menjadi dokter umum nanti kamu bisa melanjutkan studi ke jenjang selanjutnya dengan mengambil program spesialis maupun program magister biomedik</li>\r\n</ul>', '<p>Sobat karir, lulusan dokter ga melulu berkutat di dunia medis loh! Banyak peluang kerja lain yang gakalah oke. Selain membuka praktik, Dokter juga bisa bekerja struktural. Misalnya di Kementerian Kesehatan, Badan Pengawas Obat dan Makanan, Badan Narkotika Nasional, Badan Penyelenggara Jaminan Sosial, Badan SAR Nasional, dan sebagainya. Ada juga beberapa Dokter yang memutuskan melakukan penelitian terhadap pengobatan suatu penyakit demi kemajuan bidang Ilmu Kedokteran.</p>', '<p>Kuliah di jurusan Pendidikan Dokter terbagi jadi dua fase, praklinik dan klinik. Akan tetapi, pada dasarnya kamu akan mempelajari bagaimana caranya mendiagnosis penyakit yang dialami seorang pasien kemudian mengobati dan mencegah timbulnya kembali penyakit. Di semester awal kamu bakal dapat materi dasar Anatomi yang membahas bagian-bagian tubuh, juga Fisiologi yang menjelaskan fungsi dan mekanisme dasar organ tubuh. Tidak lupa, ada materi tentang Biologi Sel dan Molekuler, Genetika, Biokimia, Farmakologi, dan lainnya.</p>\r\n<p>Saat ini, rata-rata kampus Kedokteran menggunakan sistem blok, kamu akan belajar gimana cara menangani suatu kasus (Problem based learning). Kira-kira ada sekitar 21 blok yang akan kamu pelajari, setiap blok biasanya ditempuh 6-7 minggu, termasuk dengan praktikum dan ujiannya. Selain itu, kamu juga akan belajar cara melayani pasien, melakukan pemeriksaan, memberikan pengobatan, juga menjelaskan suatu keadaan kepada pasien dan keluarganya dalam skill lab. Jadi, sobat karir bisa menyelesaikan semua teori di fase praklinik paling cepat 3,5 tahun.</p>\r\n<p>Nah, setelah meraih gelar Sarjana Kedokteran, kamu akan memasuki fase klinik dan disebut sebagai Dokter Muda atau dikenal dengan koas (dari kata Cooperative Assistant). Kamu akan belajar dari satu stase ke stase lainnya di Rumah Sakit. Misalnya di stase mayor ada penyakit dalam, obgyn, bedah, dan anak. Kalau di stase minor antara lain mata, anestesi, rehabilitasi medik, syaraf, forensik, THT, dan lainnya. Ada juga stase Ilmu Kesehatan Masyarakat di Puskesmas. Fase klinik ini akan kamu tempuh selama 1,5 sampai 2 tahun. Selanjutnya, untuk menyandang gelar Dokter, kamu harus menempuh Ujian Kompetensi Dokter Indonesia (UKDI).</p>\r\n<p>Kalau udah sah jadi Dokter, kamu harus mengikuti program internship selama 1 tahun agar bisa memperoleh Surat Ijin Praktik (SIP) dan Surat Tanda Register (STR). Setelah resmi mendapatkan surat-surat penting tersebut sobat karir dapat memutuskan apakah mau ambil spesialisasi atau langsung berkarir sebagai Dokter Umum. Ada banyak kampus keren yang menawarkan Program Pendidikan Dokter Spesialis (PPDS), bahkan ada juga lho yang membuka program sub spesialis seperti pendidikan dokter gigi, sobat karier tinggal sesuaikan dengan minatmu.</p>', 'pendidikan_dokter.jpg');
INSERT INTO `tb_m_jurusan` (`ID`, `NAMA_JURUSAN`, `DESKRIPSI`, `PENGETAHUAN_DAN_KEAHLIAN`, `KENAPA_HARUS_JURUSAN_INI`, `PROSPEK_KERJA`, `DUNIA_PERKULIAHAN`, `GAMBAR`) VALUES
(11, 'Psikologi', '<p>Jurusan Psikologi adalah salah satu bidang keilmuan yang mempelajari tentang manusia. Manusia yang dimaksud di sini tak sebatas pada perilakunya saja, melainkan mempelajari jiwa yang mempengaruhi tindakan tersebut. Misalnya pada konteks sosial, seperti mempelajari bagaimana manusia berinteraksi dengan lingkungannya, atau dalam konteks industri mempelajari bagaimana seseorang berperilaku terkait dengan posisinya di sebuah perusahaan.</p>\r\n<p>Jadi, mahasiswa akan diajak untuk meneliti alur pemikiran seseorang dan mencari tahu alasan yang ada di balik perilakunya. Artinya, mahasiswa akan belajar tentang \"manusia\" sebagai individu, dengan memperhatikan setiap latar belakang yang mengikutinya. Seperti yang kita ketahui bahwa manusia adalah makhluk yang unik, bahkan ketika diberi stimulus yang sama pun responnya bisa berbeda tergantung pada pengetahuan, pengalaman, perasaan, harapan, dan banyak faktor penentu lainnya.</p>\r\n<p>Terdapat beberapa peminatan yang bisa ditemukan, seperti Psikologi Klinis, Psikologi Pendidikan, Psikologi Sosial, Psikologi Industri dan Organisasi, serta Psikologi Perkembangan. Mata kuliah yang akan dipelajari akan tergantung dengan peminatan yang kamu ambil. </p>', '<ul>\r\n<li>Kemampuan komunikasi</li>\r\n<li>Kemampuan membaca data</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan melakukan asesmen</li>\r\n<li>Kemampuan menggunakan alat tes</li>\r\n<li>Kemampuan mengelola empati</li>\r\n</ul>', '<ul>\r\n<li>Institusi pemerintah, BUMN, maupun perusahaan swasta membutuhkan lulusan Psikologi pada bagian personalia untuk membantu mengelola SDM, melakukan penerimaan pegawai baru, serta menyelenggarakan program pendidikan dan berbagai pelatihan.</li>\r\n<li>Lulusan Psikologi memiliki fungsi asesmen yang kuat sehingga mampu memetakan personil berdasarkan potensi dan karakternya.</li>\r\n</ul>', '<p>Jurusan Psikologi kerjanya apa? Secara umum, calon mahasiswa psikologi mendambakan karier di bidang konseling. Tapi, faktanya prospek kerja lulusan psikologi itu nggak hanya di bidang konseling. Ada banyak sekali peluang kerja yang menanti lulusan psikologi, karena psikologi merupakan salah satu prodi yang paling banyak dicari di dunia kerja.</p>\r\n<p>Karena objek penelitiannya adalah manusia, tentu setiap bidang pekerjaan akan membutuhkan peran lulusan Psikologi bukan? Beberapa pilihan karier yang bisa kamu geluti setelah kuliah di jurusan ini adalah pekerjaan di bidang human resorces atau HRD, bidang pelatihan (learning &amp; development), rekruiter, serta assesor. Lulusan psikologi juga bisa bekerja sebagai tenaga pendidik atau konsultan karier.</p>\r\n<p>Jenis dan jenjang kariernya pun cukup bervariasi. Secara umum, rata-rata gaji awal lulusan Psikologi berada pada kisaran Rp4.000.000, tergantung pada kemampuan, area tempat bekerja, jenis pekerjaan, dan pengalaman yang dimiliki. Kalau kamu ingin terjun ke dunia klinis, lulus sarjana aja nggak cukup. Seorang sarjana psikologi biasanya hanya bisa menjadi asisten psikolog. Jadi, kalau kamu ingin menjadi psikolog ada baiknya melanjutkan studi Magister Psikologi Profesi. Setelah lulus profesi, baru deh kamu bisa praktek di ruang konseling.</p>', '<p>Selama 4 tahun atau 8 semester kamu akan belajar segala hal yang berkaitan dengan perilaku dan fungsi mental manusia secara ilmiah, hingga layak mendapatkan gelar Sarjana Psikologi. Kamu akan terbiasa melihat manusia dari sudut pandang yang berbeda, serta diminta menerima semua pribadi apa adanya. Selama menjadi mahasiswa psikologi, kamu diharapkan dapat mengasah kepekaan dan intuisi karena akan sangat berguna saat kamu melakukan asesmen nantinya. Selain itu, kamu juga harus punya rasa toleransi yang tinggi dan kemauan untuk menghargai sesama manusia bagaimanapun kondisi mereka. Kemampuan ini penting saat berhubungan dengan subjek atau klien.</p>\r\n<p>Mata kuliah yang akan kamu temui selama kuliah antara lain Psikologi Perkembangan, Psikologi Sosial, Psikologi Klinis, Psikologi Industri dan Organisasi, Psikologi Trauma dan Bencana, Psikologi Abnormal, Psikologi Pendidikan, Psikologi Faal, Psikodiagnostika, Psikometri, Kepribadian, Konstruksi Alat Ukur, dan sebagainya. Beberapa fokus studi atau peminatan yang bisa sobat karier ambil, misalnya Psikologi Perkembangan mempelajari perkembangan pola pikir dan tingkah laku manusia dari masa kecil hingga dewasa. Psikologi Kognitif mempelajari bagaimana menerima persepsi secara visual dan auditori. Psikologi Sosial mempelajari psikologi personal dalam kelompok, dan penyelesaian problematika mental manusia dalam Psikologi Klinis.</p>\r\n<p>Psikologi bisa dikatakan sebagai salah satu jurusan favorit. Peminatnya tinggi banget deh! Di beberapa kampus, Psikologi dikhususkan untuk pelajar SMA IPA. Tapi ada banyak juga kok kampus yang membuka jurusan ini untuk murid IPS, IPA, bahkan Bahasa maupun SMK. Sementara, untuk jenjang pascasarjana umumnya ada Magister Psikologi Profesi dan Magister Ilmu Psikologi. Nah, Magister Ilmu Psikologi ini biasanya menawarkan berbagai peminatan. Ada banyak sekali kampus yang bisa kamu jadikan referensi. Jadi kamu tinggal pilih deh mau kampus bergengsi di dalam atau di luar negeri.</p>', 'psikologi.jpg'),
(12, 'Pendidikan jasmani, Kesehatan dan rekreasi (PJKR)', '<p>Jurusan Pendidikan Jasmani, Kesehatan, dan Rekreasi (PJKR) tidak bisa dianggap remeh lho! Ingat, banyak kompetisi yang diselenggarakan di bidang olahraga, bahkan tak sedikit orang yang butuh les privat olahraga untuk mendalaminya.</p>\r\n<p>Pada jurusan yang satu ini, kamu akan belajar banyak hal terkait kesehatan fisik maupun mental. Mulai dari aturan dalam berolahraga, peningkatan fungsi fisik, nutrisi, strategi dan taktik, juga metode pengajaran olahraga. Maka ketika berkuliah di Program Studi Pendidikan Jasmani, Kesehatan, dan Rekreasi ini, kamu juga akan menjalani banyak praktik hampir semua jenis olahraga yang ada seperti renang, basket, voli, atletik, woodball, serta sepak bola yang tentunya selalu berada di luar kelas.</p>\r\n<p>Meski begitu, kamu juga akan dapat teori di kelas ya. Karena mau bagaimana pun, terdapat pengetahuan seputar olahraga yang perlu didalami.</p>', '<ul>\r\n<li>Pengetahuan dan Keahlian</li>\r\n<li>Kemampuan komunikasi</li>\r\n<li>Penguasaan cabang olahraga</li>\r\n<li>Kemampauan persuasif</li>\r\n<li>Penguasaan kurikulum</li>\r\n<li>Kreatif dan inovatif</li>\r\n</ul>', '<ul>\r\n<li>Hampir setiap sekolah dari tingkat dasar hingga menengah membutuhkan guru olahraga</li>\r\n<li>Peluang untuk jadi atlet profesional atau pelatih olahraga sangat terbuka lebar, karena kamu sudah tahu dasar dan praktiknya secara maksimal.</li>\r\n</ul>', '<p>Peluang kerja yang kamu bayangkan jika mendengar jurusan bidang pendidikan mungkin hanya menjadi guru. Padahal, bukan hanya guru saja satu-satunya profesi yang bisa kamu raih dalam dunia pendidikan bukan? Khususnya untuk jurusan yang sedang jadi topik bahasan kita kali ini yaitu Program Studi PJKR, karena sangat berhubungan dengan dunia kepelatihan dan kebugaran, maka banyak banget pilihan kariernya.</p>\r\n<p>Beberapa contoh pekerjaan yang bisa kamu pilih selain guru antara lain menjadi seorang penyiar olahraga, instruktur olahraga, dosen, dan terapis fisik . Sebenarnya ada banyak lagi prospek kerja lainnya, bahkan kamu juga bisa berwirausaha.</p>\r\n<p>Sekarang ini gaya hidup sehat kian populer, sehingga segala sesuatu yang berkaitan dengan gaya hidup sehat termasuk olahraga kian diminati oleh masyarakat. So, kebayang dong banyak sekali peluang usaha bidang olahraga yang bisa digeluti? Apalagi, lulusan PJKR tentu punya nilai plus jika menjadi seorang pengusaha bidang olahraga yakni punya pengetahuan yang cukup mendalam. Dengan begitu, usaha yang dibangun pun akan berlandaskan ilmu dan kemampuan yang mumpuni di bidang olahraga serta kesehatan. Contoh usaha yang bisa dikembangkan yakni fitness center atau reflexology.</p>', '<p>Pada dasarnya, jurusan PJKR bertujuan untuk melengkapi kebutuhan dari para tenaga kependidikan di sekolah, terkait olahraga. Adapun ada juga &lsquo;saudara&rsquo; dari PJKR yang biasa disebut dengan PKO (Pendidikan Kepelatihan Olahraga). Lalu apa bedanya? Nah, ternyata PKO adalah studi yang bertujuan dalam melengkapi kebutuhan adanya tenaga pelatih, baik di luar maupun dalam sekolah. PKO sendiri lebih diarahkan untuk mengelola kegiatan olahraga dan juga konsultan.</p>\r\n<p>Uniknya lagi, sebenarnya ada juga PGSD yang menawarkan bidang pendidikan jasmani. Jadi kamu bisa kira-kira sendiri mana yang membuatmu tertarik, dan memilih satu diantaranya? Karena baik itu PJKR, PKO, maupun pendidikan jasmani dalam PGSD semua sangat baik dan hampir sama. Hanya saja, dalam memilih mana yang paling pas untukmu, hendaknya kamu sesuaikan dengan cita-cita kamu pribadi.</p>\r\n<p>Apa saja yang akan dipelajari di Jurusan PJKR? Tentu bermacam-macam mulai dari psikomotorik, berbagai macam olahraga, melatih fisik agar tetap fit dan fresh, afektif, kognitif, hingga mempelajari kehidupan sosial dan lingkungan. Ada juga waktunya kamu mempelajari tentang gizi, fisiologi, kinesiologi, anatomi, dan sebagainya. Saat sudah lulus maka kamu akan dapat gelar Sarjana Pendidikan (S.pd).</p>\r\n<p>Lalu beberapa mata kuliah yang perlu diketahui yaitu seperti, Ilmu Kepelatihan Dasar, Pengukuran dan Tes, Pendidikan Kesehatan Sekolah, dan Pembinaan Prestasi. Kemudian juga ada teori dan praktik berbagai olahraga seperti voli, basket, bulu tangkis, renang, sepak takraw, pencak silat, sepak bola, dan lain sebagainya.</p>', 'pendidikan_jasmani,_kesehatan_dan_rekreasi_(pjkr).jpg'),
(13, 'Kedokteran hewan', '<p>Jurusan yang satu ini cocok&nbsp;<em>banget</em>&nbsp;untuk kamu para pecinta hewan. Kedokteran Hewan mempelajari pengobatan dan pencegahan penyakit pada hewan ternak dan hewan lainnya. sobat karir akan mempelajari hubungan antara hewan dengan masyarakat, termasuk cara mengidentifikasi suatu penyakit dan memastikan penyakit tersebut tidak menular ke manusia. Selain itu, bidang studi ini juga mempelajari tentang perkembangbiakan hewan, pengelolaan pengembangbiakan hewan, serta pengolahan produk peternakan.</p>', '<ul>\r\n<li>Kemampuan melakukan observasi</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan meneliti</li>\r\n<li>Kemampuan problem solving</li>\r\n<li>Kemampuan membuat keputusan</li>\r\n<li>Kemampuan berpikir kritis</li>\r\n<li>Kemampuan komunikasi</li>\r\n<li>Detil, Teliti, Tekun</li>\r\n</ul>', '<ul>\r\n<li>Seorang Dokter Hewan sangat dibutuhkan di Rumah Sakit Hewan, klinik kesehatan hewan, balai karantina hewan, maupun kebun binatang.</li>\r\n<li>Kamu juga bisa membuka praktik mandiri lho, jika sudah memiliki Surat Izin Praktik dan Surat Tanda Register.</li>\r\n<li>Kalau kamu punya jiwa wirausaha, bisa buka pet shop atau peternakan hewan. Dengan begitu, secara tidak langsung kamu membuka lapangan pekerjaan.</li>\r\n<li>Tetapi, jika tertarik untuk melakukan penelitian, kamu bisa bergabung dengan laboratorium maupun lembaga penelitian.</li>\r\n<li>Nantinya sobat karier bisa juga lho, jadi Dokter Hewan sekaligus Dosen, sehingga kamu dapat terus meng-update ilmu-ilmu baru dalam dunia kedokteran hewan.</li>\r\n</ul>', '<p>Kalau sobat karier sudah dilantik jadi Dokter Hewan, kamu bisa bekerja di Rumah Sakit Hewan, klinik kesehatan hewan atau membuka praktik pribadi. Kamu juga bisa kerja di balai karantina hewan, kebun binatang, laboratorium atau lembaga penelitian. Jadi, ada banyak sekali peluang karier yang menanti lulusan Kedokteran Hewan. Rata-rata gaji seorang Dokter Hewan berada pada kisaran Rp8.000.000. Selain terjun di dunia klinis, kamu pun bisa ikut mengelola institusi-institusi tersebut, menjadi bagian dalam tim manajemen. Peluang untuk mengembangkan potensi di sektor pendidikan juga terbuka&nbsp;<em>lho</em>, jika kamu ingin menjadi Dokter Hewan sekaligus Dosen dan Peneliti.</p>', '<p>Jurusan Kedokteran Hewan sangat cocok bagi sobat karier senang dengan biologi dan memiliki&nbsp;<strong>kecintaan pada hewan</strong>. Kamu akan belajar segala hal tentang kesehatan hewan. Mulai dari bagaimana cara melakukan pemeriksaan fisik dan laboratorik, membuat diagnosis, juga melakukan penangan dan pengobatan pada hewan melalui identifikasi terhadap kondisi hewan atas suatu penyakit serta penularannya ke manusia. Selain itu, kamu juga mempelajari berbagai macam bahan pembuat obat dan penggunaan obat untuk diberikan pada hewan, penyusunan nutrisi hewan, budidaya, peningkatan produksi, serta konservasi dan pemanfaatan satwa.</p>\r\n<p>Untuk jadi seorang Dokter Hewan, sobat karir harus melewati dua tahap pendidikan, yaitu&nbsp;<strong>tahap preklinik dan klinik</strong>. Tahap preklinik biasanya ditempuh paling cepat 3,5 tahun karena menggunakan metode&nbsp;<em>problem based learning</em>. Beberapa&nbsp;<strong>mata kuliah</strong>&nbsp;yang akan kamu temui antara lain Biokimia Veteriner; Osteologi, Miologi, Artrologi, dan Splanknologi; Kesrawan dan Etika Veteriner; Biostatistika; Fisiologi Veteriner; Angiologi dan Neurologi; Sitologi, Histologi Dasar dan Embriologi; Anatomi Terapan Veteriner; Histologi Sistem Organ Hewan; Bakteriologi dan Mikologi Veteriner; Epidemiologi dan Ekonomi Veteriner; Ilmu Pemuliaan Hewan; Ilmu Reproduksi dan Teknologi Reproduksi; Ilmu Penyakit Parasit Veteriner; dan sebagainya. Setelah lulus tahap preklinik, kamu akan menyandang gelar&nbsp;<strong>Sarjana Kedokteran Hewan</strong>.</p>\r\n<p>ada tahap klinik, kamu akan menjalani masa&nbsp;<em>Cooperative Assistant</em>&nbsp;atau yang dikenal dengan&nbsp;<strong>Koas</strong>&nbsp;selama kurang lebih 1 tahun. Kamu akan menerapkan ilmu dan keterampilan yang didapat selama masa preklinik. Jadi, pada tahap ini kamu akan diminta untuk menangani kasus yang terjadi di lapangan secara langsung. Misalnya, menangani kesehatan hewan di klinik, kesehatan sapi perah, kuda, unggas, serta melakukan penjaminan mutu pangan. Jika sobat karier berhasil melewati fase klinik, kamu akan mengucap sumpah Dokter Hewan. Setelah itu, kalau ingin melanjutkan studi ke jenjang pascasarjana, ada banyak pilihan kampus bergengsi di dalam maupun luar negeri yang bisa kamu jadikan referensi.</p>', 'kedokteran_hewan.jpg'),
(14, 'Teknik pertanian', '<p>Teknik Pertanian merupakan bagian dari ilmu pertanian yang fokus pada penggunaan teknologi dan manajemen dalam proses produksi massa hayati serta penanganan dan pengolahannya. Hal ini dilakukan agar kebutuhan manusia terpenuhi dengan tetap memperhatikan aspek keberlanjutan sumber daya dan kelestarian lingkungan.</p>', '<ul>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan berpikir logis</li>\r\n<li>Kemampuan manajerial</li>\r\n<li>Kemampuan meneliti</li>\r\n<li>Kemampuan problem solving</li>\r\n<li>Kreatif dan inovatif</li>\r\n</ul>', '<ul>\r\n<li>Indonesia sebagai negara agraris tentu membutuhkan Ahli Teknik Pertanian. Kamu sangat dinantikan oleh sektor pertanian untuk menciptakan dan mengembangkan teknologi baru untuk meningkatkan efisiensi dan efektivitas.</li>\r\n<li>Perusahaan-perusahaan partikelir sangat membutuhkan lulusan Teknik Pertanian untuk terus berinovasi dalam merancang berbagai peralatan dan mesin pertanian.</li>\r\n<li>Perusahaan perkebunan dalam pengelolaannya juga membutuhkan lulusan Teknik Pertanian mengingat banyaknya mesin dan peralatan perkebunan yang digunakan mulai dari pengelolaan lahan sampai penanganan pascapanen.</li>\r\n<li>Lulusan Teknik Pertanian punya peluang untuk kerja di jajaran pemerintahan seperti pada Dinas Pertanian dan instansi terkait.</li>\r\n<li>Ilmu memproduksi pangan kamu dapat mengambil&nbsp;<a href=\"https://campus.quipper.com/majors/id-agroteknologi\">jurusan agroteknologi</a>.</li>\r\n</ul>', '<p>Lulusan Teknik Pertanian memiliki peluang kerja yang cukup menjanjikan. Mulai dari instansi pemerintah, industri hasil pertanian, sampai lembaga penelitian membutuhkan lulusan jurusan ini. Jenis dan jenjang karier yang ditawarkan pun cukup bervariasi. Bahkan kamu bisa mencoba untuk mengembangkan potensi di sektor lain seperti perbankan, jasa keuangan, teknologi informasi, dan lainnya yang membutuhkan berbagai disiplin ilmu. Rata-rata gaji yang ditawarkan pada lulusan Teknik Industri untuk&nbsp;<em>entry level</em>&nbsp;bergantung pada kemampuan dan pengalaman yang dimiliki, serta area tempat bekerja.</p>', '<p>Di jurusan Teknik Pertanian, selama 4 tahun atau 8 semester sobat karir akan mengkaji ilmu pertanian dengan melakukan&nbsp;<strong>rekayasa atau transformasi sumber daya alam secara efektif dan efisien.</strong>&nbsp;Mulai dari bagaimana merencanakan, merancang, mengembangkan, menilai, sampai menerapkan berbagai unsur dalam sistem produksi di sektor pertanian. Kamu juga akan belajar bagaimana mengolah dan mengelola lahan dan air, bagaimana menanam, memelihara, memanen dan mengolah hasil pertanian pascapanen, serta bagaimana merancang berbagai mesin dan peralatan pengolahan lainnya. Tak ketinggalan ada materi tentang energi di sektor pertanian, teknik lingkungan, juga bangunan pertanian.</p>\r\n<p>Beberapa&nbsp;<strong>mata kuliah</strong>&nbsp;yang akan kamu jumpai di jurusan Teknik Pertanian antara lain Ilmu Lingkungan, Sistem Pertanian Industri, Energi dan Mesin Pertanian, Agroklimatologi, Rekayasa Lingkungan dan Bangunan Pertanian, Listrik dan Elektronika, Ekonomi Teknik, Pemetaan Wilayah, Perpindahan Panas, Perpindahan Massa, Fisika Hayati, Rancangan Percobaan Keteknikan, Teknik Biosistem, Teknik Pengukuran dan Instrumentasi, Teknologi Pascapanen, dan sebagainya. Nantinya, jika sudah lulus, sobat karier akan menyandang gelar&nbsp;<strong>Sarjana Teknologi Pertanian</strong>. Sementara itu, peminatan untuk jenjang pascasarjana cukup beragam, seperti Teknik Sumber Daya Lahan dan Air, Bio-Mekanika dan Informatika, juga Teknik Pangan dan Pascapanen.</p>\r\n<p>Saat ini banyak perguruan yang memiliki jurusan bidang pertanian seperti agroteknologi dan&nbsp;<a href=\"https://campus.quipper.com/majors/id-penyuluhan-dan-komunikasi-pertanian\">penyuluhan dan komunikasi pertanian</a>&nbsp;yang dapat menjadi pertimbangan kamu jika ingin mengambil jurusan kuliah bidang pertanian. </p>', 'teknik_pertanian.jpg'),
(15, 'Holtikultura dan agronomi', '<p><strong><span lang=\"EN-ID\">Jurusan Agronomi merupakan jurusan yang mempelajari cara mengelola tanaman di lahan pertanian untuk meningkatkan jumlah produksi panen dengan kualitas terbaik.</span></strong><span lang=\"EN-ID\">&nbsp;Lahan pertanian tersebut umumnya adalah kebun dan sawah. Kebun sendiri merupakan lahan kering yang ditanami tanaman semusim, seperti kapas, tebu, dan semangka. Sementara, sawah adalah lahan pertanian berpetak-petak yang dapat ditanami padi, palawija, dan lain-lain.</span></p>\r\n<p><span lang=\"EN-ID\">Di jurusan ini, kamu juga mempelajari pembudidayaan tanaman dengan lebih berfokus pada perawatan yang intensif. Selanjutnya, kamu pun akan dibimbing untuk memahami proses dan teknik pengelolaan tanaman pertanian, mulai dari pengolahan tanah, penanaman benih, pemupukan, penanganan hama, pengendalian penyakit tanaman, hingga pemanenan tanaman. Menariknya lagi, kamu pun akan bertemu dengan berbagai materi terkait isu-isu pelestarian lingkungan.</span></p>', '<ul>\r\n<li>Pemahaman Kimia</li>\r\n<li>Pemahaman Biologi</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan meneliti</li>\r\n<li>Kemampuan berpikir kritis</li>\r\n</ul>', '<ul>\r\n<li><strong>Menurut catatan Badan Pusat Statistik (BPS), pada tahun 2022, penyerapan tenaga kerja di sektor pertanian mengalami pertumbuhan positif.</strong>Hal ini dibuktikan dengan banyaknya penduduk yang bekerja di sektor pertanian, yaitu mencapai 29,96% atau sekitar 1,86 juta orang per tahun. Oleh karena itu, sebagai lulusan Agronomi, kamu memiliki kesempatan kerja yang terbuka lebar.</li>\r\n<li>Tak hanya itu,&nbsp;<strong>karier di bidang pertanian juga tidak akan lekang oleh zaman.</strong>Hal ini disebabkan karena pertanian merupakan salah satu bidang utama yang berkaitan dengan salah satu kebutuhan dasar manusia, yakni pangan.</li>\r\n<li>Selain mempelajari cara mengelola tanaman dan pertanian,<strong>kamu juga akan belajar tentang kelestarian lingkungan</strong>. Sebagai contoh, kamu akan mendalami konservasi tanah, yaitu usaha untuk mencegah dan memperbaiki kerusakan tanah akibat erosi.</li>\r\n<li>Serunya lagi, di sini&nbsp;<strong>sobat karier juga belajar tentang ekspor dan impor komoditas pertanian, proses karantina tanaman, hingga bioteknologi tanaman yang dibutuhkan oleh sektor pertanian di masa depan.</strong></li>\r\n<li><strong>Berbagai ilmu yang kamu dapat di jurusan ini pastinya bisa kamu manfaatkan untuk bercocok tanam secara mandiri di rumah.</strong>&nbsp;Selain dapat memenuhi kebutuhan makanmu, hal tersebut juga bermanfaat untuk mengurangi pengeluaran, menciptakan kesejukan di sekitar rumah, dan membantu melawan penyakit.</li>\r\n</ul>', '<p><strong>Pertanian merupakan salah satu andalan komoditas ekspor Indonesia, terutama karet, sawit, kakao, dan kopi yang sangat diminati oleh pasar internasional. Berdasarkan hal tersebut, kamu nggak perlu khawatir dengan prospek kerja Agronomi ya</strong>. Sebab, dengan memiliki kemampuan di bidang pertanian, tentunya kamu akan dibutuhkan oleh banyak perusahaan.</p>\r\n<p>Selain memiliki kesempatan untuk berkontribusi dalam memajukan pertanian Indonesia, sobat karir juga dapat bekerja di berbagai perusahaan, baik milik negara maupun swasta, seperti perkebunan sawit, kakao, atau kopi, serta perusahaan riset dan pengembangan hasil pertanian. Kamu juga bisa menjadi&nbsp;<em>entrepreneur</em>&nbsp;di bidang pertanian.</p>\r\n<p>Nah, jika kamu ingin bekerja di perusahaan perkebunan,<strong>&nbsp;salah satu profesi yang bisa kamu geluti adalah&nbsp;</strong><em><strong>agronomist.</strong></em><strong>&nbsp;Di posisi ini, kamu bertanggung jawab untuk mengidentifikasi dan menganalisis permasalahan mengenai budidaya tanaman, serta menyusun&nbsp;</strong><em><strong>Standard Operating Procedure&nbsp;</strong></em><strong>(SOP) yang berkaitan dengan teknis pelaksanaan budidaya tanaman</strong>. Di samping itu, kamu juga bertugas untuk merancang dan membangun sistem serta pemeliharaan konservasi tanah, serta melakukan uji terhadap berbagai jenis tanaman. Oh ya, di beberapa perusahaan terdapat&nbsp;<em>agronomist&nbsp;</em>yang dikhususkan untuk tanaman tertentu, lho, contohnya seperti&nbsp;<em>coffee agronomist.</em></p>\r\n<p>Selain bekerja di perusahaan,<strong>&nbsp;kamu pun berkesempatan untuk menjadi seorang Pegawai Negeri Sipil (PNS) di lingkungan Kementerian Pertanian (Kementan).</strong>&nbsp;Sebagai lulusan Agronomi, kamu memiliki peluang di beberapa posisi, seperti Pengawas Benih Tanaman, Analisis Potensi Perbenihan, Penata Kebun Percobaan, dan sebagainya.</p>\r\n<p><strong>Misalnya saja, kamu tertarik menempati posisi Pengawas Benih Tanaman, maka kamu bertugas untuk melaksanakan, mengevaluasi, serta melaporkan kegiatan pengawasan benih tanaman.</strong>&nbsp;Kegiatan tersebut terdiri dari penilaian kultivar (varietas hasil budidaya petani), sertifikasi, pengujian mutu benih, pengawasan peredaran benih tanaman, dan penerapan sistem manajemen mutu.</p>', '-', 'holtikultura_dan_agronomi.jpg'),
(16, 'Ilmu sosial', '<p>Sobat karir, jika kamu tertarik&nbsp; dengan bagaimana masyrakaya dalam satu komunitas tinggal Bersama dan berinteraksi satu sama lain, maka melanjutkan study ke bidang ilmu sosial bisa menjadi pilihan yang tepat. Ilmu sosial atau social science adalah study untuk memperhatikan hubungan antar individu di beragai bidang dalam suatu lingkungan sosial</p>\r\n<p>- Apa saja jurusan bidang ilmu sosial?</p>\r\n<ul>\r\n<li>Antropologi</li>\r\n<li>Arkeologi</li>\r\n<li>Ekonomi</li>\r\n<li>Geografi</li>\r\n<li>Sejarah</li>\r\n<li>Hukum</li>\r\n<li>Ilmu Bahasa</li>\r\n<li>Politik</li>\r\n<li>Psikologi</li>\r\n<li>Sosiologi</li>\r\n</ul>\r\n<p>Kamu bisa mempelajari ilmu sosial di jenjang sarjana (S1) maupun pascasarjana (S2 &amp; S3), karena ilmu sosial merupakan bidang yang luas dan mencakup banyak jurusan, system pembelajarannya pun bervariasi tergantung jurusan dan spesialisasi yang ingin kamu ambil.</p>', '<p>Sobat karier, Sebagai lulusan ilmu sosial, kamu akan menguasai berbagai macam&nbsp;<em>skills&nbsp;</em>yang dapat diaplikasikan ke banyak bidang. Hal ini sangat berguna jika kamu masih belum yakin apa yang ingin kamu lakukan setelah lulus kuliah.</p>\r\n<p>&nbsp;</p>\r\n<p>Berikut adalah daftar&nbsp;<em>skills&nbsp;</em>kerja yang dicari oleh perusahaan dan bisa kamu dapatkan dari ilmu sosial:</p>\r\n<ul>\r\n<li>Critical thingking</li>\r\n<li>Problem solving</li>\r\n<li>Kreatifitas dan komunikasi</li>\r\n<li>Berpikir logis</li>\r\n<li>Kecerdasan emosi</li>\r\n<li>Mandiri dalam berpikir</li>\r\n<li>Cultural awareness</li>\r\n<li>Kesadaran sosial</li>\r\n</ul>', '<p>Sobat karier, salah satu konsep utama yang dipelajari dalam bidang ilmu sosial adalah mencoba untuk memahami dan memperbaiki masyarakat. Jika kamu memiliki keinginan mulia untuk memperbaiki dunia tempat manusia tinggal, maka mendapatkan gelar pendidikan di bidang ilmu sosial akan membawamu selangkah lebih dekat dengan karir impian.</p>', '<p>Sudah tidak diragukan lagi bahwa lulusan bidang ilmu sosial memiliki prospek kerja yang luas. Berikut adalah contoh pekerjaan yang bisa kamu tekuni setelah lulus beserta gaji rata-rata per tahun untuk lulusan baru di 3 negara favorit mahasiswa internasional.</p>\r\n<p>&nbsp;</p>\r\n<table>\r\n<tbody>\r\n<tr>\r\n<td width=\"156\">\r\n<p>&nbsp;</p>\r\n</td>\r\n<td width=\"156\">\r\n<p><strong>USA</strong></p>\r\n</td>\r\n<td width=\"156\">\r\n<p><strong>KANADA</strong></p>\r\n</td>\r\n<td width=\"156\">\r\n<p><strong>UK</strong></p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td width=\"156\">\r\n<p>Arkeologis</p>\r\n</td>\r\n<td width=\"156\">\r\n<p>USD 56.904</p>\r\n</td>\r\n<td width=\"156\">\r\n<p>CAD 56,949</p>\r\n</td>\r\n<td width=\"156\">\r\n<p>GBP 36,198</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td width=\"156\">\r\n<p>Guru Ilmu Sosial</p>\r\n</td>\r\n<td width=\"156\">\r\n<p>USD 53,158</p>\r\n</td>\r\n<td width=\"156\">\r\n<p>CAD 52,916</p>\r\n</td>\r\n<td width=\"156\">\r\n<p>GBP 37,135</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td width=\"156\">\r\n<p>Pegawai Negeri</p>\r\n</td>\r\n<td width=\"156\">\r\n<p>USD 58,062</p>\r\n</td>\r\n<td width=\"156\">\r\n<p>CAD 60, 582</p>\r\n</td>\r\n<td width=\"156\">\r\n<p>GBP 29,584</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td width=\"156\">\r\n<p>Polisi</p>\r\n</td>\r\n<td width=\"156\">\r\n<p>USD 53,676</p>\r\n</td>\r\n<td width=\"156\">\r\n<p>CAD 76,146</p>\r\n</td>\r\n<td width=\"156\">\r\n<p>GBP 32,494</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td width=\"156\">\r\n<p>Ekonomis</p>\r\n</td>\r\n<td width=\"156\">\r\n<p>USD 87,284</p>\r\n</td>\r\n<td width=\"156\">\r\n<p>CAD 74,726</p>\r\n</td>\r\n<td width=\"156\">\r\n<p>GBP 47,800</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>', '-', 'ilmu_sosial.jpg'),
(17, 'Jurusan music', '<p>Siapa sih yang nggak suka mendengarkan musik? Kalau sobat karir nggak cuma suka mendengarkan tetapi ingin mempelajari musik lebih dalam dan secara serius kamu bisa masuk Jurusan Musik saat kuliah nanti. Di jurusan Musik kamu akan mempelajari bidang ilmu yang mempelajari teori musik dan membekalimu dengan keterampilan praktis seperti instrumen dalam musik, teknik vokal, dan komposisi. Selain itu, kamu juga akan mempelajari berbagai aliran musik seperti jazz, pop, musik tradisional, dan sebagainya. Kapan lagi kan bermain sambil belajar?</p>', '<ul>\r\n<li>Kemampuan bermusik</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan bekerja dalam tim</li>\r\n<li>Kemampuan mengelola pertunjukan</li>\r\n<li>Kemampuan mengekspresikan gagasan ke bentuk musik</li>\r\n<li>Kemampuan menyajikan musik secara kreatif</li>\r\n</ul>', '<ul>\r\n<li>Kerjanya cuma pentas di atas panggung? Jangan salah! Ada banyak banget pilihan pekerjaan yang menawarkan gaji besar pada Sarjana Musik, seperti Soundman, Music Director, Arranger, dan masih banyak lagi.</li>\r\n<li>Kamu punya kesempatan yang besar lho untuk berburu beasiswa ke luar negeri. Tentunya mau dong kayak Isyana Sarasvati yang dapet beasiswa sekolah musik di Singapura.</li>\r\n<li>Dengan musik, kamu bisa go international lho, sobat karier! Kamu punya kesempatan untuk bisa terlibat dalam konser penyanyi ternama.</li>\r\n<li>Dengan kemampuan yang mumpuni, bukan nggak mungkin kamu juga bisa berkarier sebagai Komponis, Konduktor, sekaligus Penata Musik, seperti Erwin Gutawa dan Addie MS.</li>\r\n<li>Jika tertarik dengan dunia pendidikan, kamu bisa menjadi Guru Vokal atau Guru Instrumen Musik. Nah, kamu tertarik dengan dunia bisnis, kamu bisa lho bisa membuka Sekolah Musik.</li>\r\n</ul>', '<p>Lulusan jurusan Musik rata-rata memilih berkarier di industri musik. Bidang pekerjaan yang ditawarkan industri musik sangat bervariasi, di antaranya Musisi, Musikolog Pencipta Musik, juga Pengajar Vokal/ Instrumen Musik. Kamu pun bisa terlibat dalam proyek produksi film sebagai Penata Musik. Dengan bekal keterampilan dan keilmuan yang dipelajari di bangku perkuliahan, sobat karier juga bisa menjajal peruntungan di industri musik mancanegara&nbsp;<em>lho</em>. Siapa tahu kamulah the next Sandhy Sandoro dan Anggun C. Sasmi? Bisa juga jadi seperti pianis jazz kebanggaan tanah air, Joey Alexander.</p>', '<p>urusan Musik akan menempamu selama 4 tahun atau 8 semester. Di sini kamu akan belajar segala hal tentang musik, mulai dari sistem notasi sampai&nbsp;<strong>aspek-aspek musikologis&nbsp;</strong>seperti melodi, ritme, dan harmoni. Kamu juga akan dibekali dengan teknik aransemen, teknik kombinasi nada, serta keterampilan memproduksi musik secara kolaboratif. Pada umumnya, kamu diminta&nbsp;<strong>memilih instrumen mayor</strong>&nbsp;yang akan kamu pelajari secara mendalam, seperti ; Piano, Gitar, Biola, Violin, Cello, Trumpet, Contra Bass, Flute, Saxophone, Clarinet, Perkusi, Vokal, dan lainnya. Biasanya pemilihan instrumen mayor ini tergantung sama minat dan bakatmu.&nbsp;<em>Eits</em>, tentu ada kelas praktiknya juga&nbsp;<em>lho</em>, sobat karier! Seru<em>&nbsp;deh</em>!</p>\r\n<p>&nbsp;</p>\r\n<p>Beberapa&nbsp;<strong>mata kuliah</strong>&nbsp;yang bisa kamu temui misalnya Teori Musik, Teori Bentuk Musik, Sejarah Musik, Koor/ Orkes/ Ensambel, Instrumen Dasar Piano, Baca Partitur, Solfegio, Kontrapung, Harmoni, Instrumen Mayor, Kondakting, Kritik Musik, Analisis Bentuk Musik, dan sebagainya. Sobat karier akan meraih gelar Sarjana Seni setelah menuntaskan studi. Kalau ingin melanjutkan ke jenjang&nbsp;<strong>pascasarjana</strong>&nbsp;bisa memilih program S2 Penciptaan dan Pengkajian Seni, S2 Tata Kelola Seni, atau lainnya.</p>\r\n<p>&nbsp;</p>\r\n<p>Selain jurusan Musik, kamu juga bisa belajar musik di jurusan Musik Pendidikan, Penciptaan Musik, atau Penyajian Musik. Nah, kalau ingin menjadi Guru Seni Musik, Guru Seni Budaya atau&nbsp;<a href=\"https://campus.quipper.com/careers/komposer\">Komposer</a>, kamu bisa mengambil jurusan Pendidikan Seni Musik atau Pendidikan Seni Drama, Tari, dan Musik. Paket komplit&nbsp;<em>deh</em>! Tinggal sesuaikan sama minatmu ya sobat karier! Dan jangan lupa persiapkan diri sebaik mungkin untuk ujian kompetensi ya!</p>', 'jurusan_music.jpg'),
(18, 'Teater dan drama', '<p>Sobat karier, yang suka menjadi bintang panggung atau bergabung dengan ekskul teater di sekolah dan ingin mendalami teater dengan serius, bisa bergabung dengan jurusan yang satu ini. Teater dan Drama adalah bidang yang mempelajari ilmu tentang pertunjukan seni seperti, pertunjukkan seni klasik, teatrikal, juga musikal. Di sini kamu akan membedah seni teater dan drama secara teori juga dari teknik berekspresi. Selain itu, kamu akan belajar tentang teori peran/akting, menari, menyanyi, berekspresi, menyutradarai, pencahayaan, juga tata kostum dan tata rias wajah.</p>', '<ul>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan memainkan peran</li>\r\n<li>Kemampuan mengekspresikan gagasan ke bentuk teater dan drama</li>\r\n<li>Kemampuan menciptakan teater dan drama</li>\r\n<li>Kemampuan mengelola pertunjukan seni</li>\r\n<li>Kemampuan bekerja secara tim</li>\r\n</ul>', '<ul>\r\n<li>Kamu yang memilih fokus pada bidang penciptaan maupun penyajian seni teater dan drama, bisa terlibat dalam produksi pentas teater. Nah, kalau kamu berhasil gabung dengan kelompok ternama, keren deh!</li>\r\n<li>Mau jadi artis? Bisa banget! Kalau kamu berhasil tampil di acara-acara reguler, dijamin deh pundi-pundi Rupiah yang terima akan begitu menggiurkan.</li>\r\n<li>Kalau suka sama bidang pengkajian seni, jelas bisa meniti karier sebagai peneliti seni, pengamat seni, juga kritikus seni.</li>\r\n<li>Masuk ke dunia pendidikan juga patut kamu coba. Misalnya dengan mengajar akting di akademi drama atau di sekolah akting.</li>\r\n<li>Suka bekerja dibalik layar? Tapi lulusan Teater dan Drama? Jangan takut nggak dapet pekerjaan ya! Selain jadi penulis naskah, penata artistik, bisa lho terlibat di tim marketing yang mempromosikan pertunjukkan teater milik komunitasmu.</li>\r\n</ul>', '<p>Ada banyak peluang karier yang menunggu lulusan Teater dan Drama. Variasi jenis pekerjaannya juga macam-macam lho. Berbekal keilmuan dan keterampilan yang didapat dari bangku kuliah, pada dasarnya kamu bisa jadi seniman pencipta, seniman pengkaji, ataupun seniman penyaji di dunia teater dan drama ini. Kamu bisa mulai berkarier dengan bergabung bersama sanggar profesional untuk terus mengasah kemampuanmu. Dari satu panggung ke panggung pentas lain, kamu akan semakin kaya dengan pengalaman. Dengan begitu, kamu punya nilai jual yang tinggi sebagai modal untuk menggepakkan sayap di bidang teater dan drama. Bukan&nbsp;<em>nggak</em>&nbsp;mungkin suatu saat nanti kamu akan terjun ke industri perfilman. Selain itu, kamu pun bisa mengembangkan potensi di sektor media&nbsp;<em>lho</em>, sobat karier!</p>', '<p>Kamu ingin kuliah di jurusan Teater dan Drama? Sudah tahu belum apa saja yang akan kamu pelajari di jurusan ini? Nanti selama 4 tahun atau 8 semester, sobat karier akan banyak melakukan kajian terhadap Seni Teater atau istilah kerennya adalah&nbsp;<strong>Dramaturgi</strong>. Selain itu, kamu juga akan belajar menciptakan pertunjukan teater, mulai dari bagaimana menulis naskah drama atau skenario, penataan artistik, penyutradaraan, sampai pemeranan. Nah, setelah lulus kamu akan menyandang gelar&nbsp;<strong>Sarjana Seni</strong>.</p>\r\n<p><strong>Mata kuliah</strong>&nbsp;yang bisa kamu temui misalnya Teknik Dasar Pemeranan, Teknik Dasar Penyutradaraan, Olah Tubuh, Olah Vokal, Penulisan Lakon, Penulisan Kreatif, Pemeranan Realis, Pemeranan Non Realis, Pemeranan Tradisi, Penyutradaraan Realis, Penyutradaraan Non Realis, Penyutradaraan Tradisi, Dramaturgi Realis, Dramaturgi Non Realis, Tata Artistik, Tata Kostum dan Make Up, Desain Musik, Analisis Fiksi, Manajemen Seni Pertunjukan Indonesia, Manajemen Teater, Videografi, Drama Televisi, Pembawaan Totalitas Keaktoran, Semiotika Teater, Kritik Teater, dan masih banyak lagi. Kalau sobat karier bercita-cita mengambil studi jenjang&nbsp;<strong>pascasarjan</strong>a, jangan bingung! Ada berbagai kampus yang membuka S2 Penciptaan dan Pengkajian Seni maupun S2 Tata Kelola Seni. Program tersebut menawarkan beberapa variasi peminatan yang bisa kamu pilih.</p>\r\n<p>Nah, kalau sobat karier bercita-cita jadi Guru Seni Budaya di sekolah, bisa&nbsp;<em>lho</em>&nbsp;kuliah di jurusan Pendidikan Seni Drama,&nbsp;<a href=\"https://campus.quipper.com/majors/id-tari\">Tari</a>, dan&nbsp;<a href=\"https://campus.quipper.com/majors/id-musik\">Musik</a>. Paket komplit&nbsp;<em>deh</em>! Jadi, kamu akan mempelajari seni drama, tari, dan musik plus belajar&nbsp;<em>gimana</em>&nbsp;cara mengajarkannya secara tepat. Setelah lulus dan meraih gelar Sarjana Pendidikan, bisa juga lanjut ke jenjang pascasarjana, misalnya ambil S2 Pendidikan Seni.</p>', 'teater_dan_drama.jpg'),
(19, 'Design grafis', '<p>Jurusan Desain Grafis ialah jurusan yang mempelajari tentang konsep, bentuk, dan komposisi suatu karya komunikasi visual berupa gambar, garis, maupun elemen grafis lainnya. Hasil dari karya desain diaplikasikan pada berbagai media.</p>\r\n<p>Karya desain grafis dapat dijumpai antara lain pada logo, poster, brosur, undangan, hingga kartu nama baik itu dalam bentuk cetak atau digital. Ilmu desain grafis juga dapat diterapkan untuk membuat desain tampilan antarmuka website bahkan aplikasi mobile.</p>\r\n<p>Jadi, Jurusan Desain Grafis ini berfokus pada representasi visual yang diambil dari konsep penting dalam metode komunikasi visual. Kemudian untuk belajar desain grafis, memerlukan perangkat lunak atau software yang berhubungan dengan desain. Software yang biasanya dibutuhkan seperti adobe photoshop, corel draw, dan adobe XD.</p>', '<ul>\r\n<li>Keterampilan menggambar teknis</li>\r\n<li>Kemampuan mengoperasikan software gambar</li>\r\n<li>Kemampuan berpikir kreatif dan terstruktur</li>\r\n<li>Kemampuan imajinasi</li>\r\n<li>Pemahaman artistik</li>\r\n<li>Pemahaman komposisi warna</li>\r\n</ul>', '<ul>\r\n<li>Cocok bagi yang tertarik pada dunia komunikasi dan seni serta membutuhkan wadah untuk menyalurkan kreativitas.</li>\r\n<li>Semakin banyak perusahaan di berbagai bidang yang membutuhkan lulusan Jurusan Desain Grafis. Hal ini dikarenakan pola komunikasi masa kini cenderung lebih ke bentuk visual dan audio dibandingkan tekstual.</li>\r\n<li>Menjadi seorang desainer grafis tidak harus bekerja sebagai karyawan suatu perusahaan. Desainer grafis juga bisa bekerja sebagai freelancer atau membuka usaha sendiri dengan potensi penghasilan yang tak kalah dengan bekerja kantoran</li>\r\n<li>Bukan hanya perusahaan besar, usaha kecil, mikro, kecil, dan menengah (UMKM) juga membutuhkan jasa desainer grafis untuk membantu dalam hal menyiapkan media promosi dan branding.</li>\r\n</ul>', '<p>Prospek kerja para alumni Jurusan Desain Grafis memang terbilang sangat bagus, hal itu karena kebutuhan akan komunikasi visual yang mengalami peningkatan. Ada banyak peluang baik di industri media, periklanan, bisnis, dan masih banyak lagi yang membutuhkan jasa graphic designer. Bahkan, seorang desainer grafis bisa mengambil pekerjaan secara terikat atau kantoran, bisa juga memilih pekerjaan freelance yang lebih fleksibel tapi tetap berpenghasilan tinggi. Penghasilan di bidang ini cukup tinggi karena memang tanggung jawabnya juga cukup berat</p>', '<p>Tak sedikit generasi muda yang berminat dengan dunia seni, teknologi, dan komunikasi dengan tingkat kreativitas yang tinggi. Seiring dengan banyaknya peminat, sekarang sudah banyak perguruan tinggi yang menyediakan jurusan ini.</p>\r\n<p>Proses perkuliahan atau pembelajaran Jurusan Desain Grafis tentu saja seru dan banyak hal baru yang dipelajari. Materi yang diberikan pada mahasiswa dimulai dari dasar graphic design yang meliputi elemen desain. Setelah itu juga akan mendalami prinsip desain yaitu keseimbangan, kesatuan, ritme, kontras, proporsi, repetisi, dan masih banyak lagi.</p>\r\n<p>Bidang lain yang masih berhubungan dengan desain grafis yang juga diajarkan selama perkuliahan salah satunya adalah fotografi. Ilmu yang akan didapatkan mahasiswa Jurusan Desain Grafis yakni seputar teknik fotografi serta desain yang berhubungan dengan fotografi.</p>\r\n<p>Beragam teknik desain akan diajarkan melalui materi serta praktik. Jadi, mahasiswa jurusan ini akan banyak mendapatkan tugas membuat suatu karya setelah mempelajari sebuah teknik dan peralatan yang digunakan dalam dunia graphic design. Agar ada bayangan apa saja yang dipelajari, mata kuliah yang masuk dalam Jurusan Desain Grafis antara lain Dasar Seni Rupa dan Desain, Rupa Dasar 2D, Pengantar Rekayasa &amp; Desain, Kreativiti dan Humanita, Rupa Dasar 3D, DKV Dasar, dan Tipografi Dasar.</p>\r\n<p>Selain itu, mahasiswa jurusan ini juga akan dibekali dengan ilmu Ilustrasi Dasar, Fotografi Dasar, DKV Aplikatif, Tipografi Aplikatif, Ilustrasi Aplikatif, Fotografi Aplikatif, Metode Produksi, Komunikasi Visual, Komunikasi Visual Multimedia, hingga Animasi. Bahkan, materi seputar periklanan seperti Narasi Visual, Komunikasi Visual Periklanan, dan Visual Branding juga akan didapatkan.</p>\r\n<p>Tugas kuliah yang akan didapatkan cukup beragam. Misalnya, untuk semester awal mahasiswa Jurusan Desain Grafis biasanya diminta untuk mengumpulkan logo apa saja yang ditemukan dalam kehidupan sehari-hari yang bertujuan untuk memperluas referensi mahasiswa. Pada semester lanjut, tugas-tugas yang diberikan sudah sampai pada mendesain poster, sampul buku, kartu ucapan, dan lain sebagainya.</p>\r\n<p>Secara umum, konten mata kuliah yang ada di jurusan ini mirip dengan mata kuliah yang ada di&nbsp;<a href=\"https://campus.quipper.com/majors/id-desain-komunikasi-visual\">Jurusan Desain Komunikasi Visual</a>&nbsp;(DKV), bahkan mempelajari tentang DKV dasar. Namun, Jurusan Desain Grafis jelas berbeda dengan Jurusan DKV. Jurusan Desain Grafis fokus utamanya pada teknis pembuatan elemen grafis utama dari suatu komunikasi visual, tidak mengarah pada strategi penggunaan konten grafis untuk suatu tujuan tertentu. Sedangkan Jurusan DKV, fokus pada penciptaan karya yang bersifat komunikatif, informatif, dan efektif karena tujuan penggunaan konten atau karya tersebut untuk mempengaruhi perilaku seseorang. Misalnya, menumbuhkan minat beli, mempermudah seseorang memahami peraturan yang disosialisasikan, dan lain-lain.</p>', 'design_grafis.jpg'),
(20, 'Kesejahteraan sosial', '<p>Kesejahteraan Sosial mengajarkan tentang pengetahuan dasar pekerjaan sosial, nilai, prinsip, dan etikanya. Kamu juga akan belajar kebijakan dan pelayanan sosial di tingkat lokal, nasional, dan internasional. Jurusan ini sangat cocok dengan kamu yang memiliki jiwa sosial tinggi dan serius mendalami bidang tersebut, terlebih jika kamu suka kegiatan di luar ruangan untuk berinteraksi dengan masyarakat secara langsung.</p>', '<ul>\r\n<li>Kemampuan komunikasi</li>\r\n<li>Kemampuan advokasi</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan meneliti</li>\r\n<li>Kemampuan melakukan observasi</li>\r\n<li>Kemampuan berpikir logis</li>\r\n<li>Kemampuan problem solving</li>\r\n<li>Peka dan Empati</li>\r\n</ul>', '<ul>\r\n<li>Instansi pemerintah pusat maupun daerah membutuhkan lulusan Kesejahteraan Sosial terutama untuk membidangi urusan sosial.</li>\r\n<li>Kamu juga bisa bekerja di organisasi nirlaba ataupun lembaga swadaya masyarakat yang berfokus pada bidang pengembangan masyarakat maupun pembangunan sosial.</li>\r\n</ul>', '<p>Lulusan Kesejahteraan Sosial dibutuhkan baik di instansi pemerintahan, perusahaan swasta, lembaga internasional, sampai organisasi nirlaba yang bergerak dalam bidang pemberdayaan masyarakat. Lulusan Kesejahteraan Sosial dianggap memiliki kemampuan advokasi yang baik, juga kepekaan dan empati yang tinggi. Bidang pekerjaannya sangat cocok bagi kamu yang suka bekerja dengan terjun langsung ke tengah-tengah masyarakat. Selain itu, kamu juga bisa jadi konsultan dalam berbagai program pengembangan masyarakat. Masing-masing bidang pekerjaan menawarkan jenjang karier yang bervariasi, begitu pula dengan gaji. Namun, besaran gaji biasanya akan bergantung pada kemampuan, area tempat bekerja, jabatan, dan pengalaman yang dimiliki</p>', '<p>Di beberapa kampus, Jurusan Kesejahteraan Sosial disebut dengan Jurusan Sosiatri. Meski berbeda nama tapi secara umum ilmu yang didapatkan tetap sama, jadi kamu nggak perlu bingung dengan penamaan jurusan ini. Selama 4 tahun atau 8 semester berkuliah di Jurusan ini, sobat karir dibekali dengan berbagai pengetahuan guna mengurangi ketidakadilan dan kesenjangan sosial. Kamu akan belajar banyak seputar teori kebijakan sosial, proses penyusunan strategi, implementasi, evaluasi dan monitoring kebijakan sosial, juga pengembangan masyarakat melalui berbagai program yang sifatnya preventif, rehabilitatif, kuratif, maupun developmental.</p>\r\n<p>&nbsp;</p>\r\n<p>Mata kuliah yang akan kamu pelajari di jurusan Kesejahteraan Sosial misalnya Dasar-Dasar Pembangunan Sosial, Manajemen Organisasi Pelayanan, Manajemen Penanggulangan Bencana, Filsafat dan Etika Kesejahteraan Sosial, Sistem Usaha Kesejahteraan Sosial, Teori Sosiologi bagi Kesejahteraan Sosial, Tingkah Laku Manusia dan Lingkungan Sosial, Metode Intervensi Sosial, Masalah Kemiskinan, Intervensi Komunitas dan Pengembangan Masyarakat, Dampak Sosial Pembangunan dan Globalisasi, Kebijakan dan Perencanaan Sosial, Perencanaan Partisipatoris dalam Intervensi Komunitas, dan lain sebagainya. Selama kuliah juga akan ada banyak praktik, salah satunya praktik merencanakan program pemberdayaan masyarakat. Nah, setelah lulus, sobat karir berhak menyandang gelar Sarjana Sosial. Kamu juga bisa lho melanjutkan studi ke jenjang pascasarjana untuk lebih mendalami bidang ini. </p>', 'kesejahteraan_sosial.jpg'),
(21, 'Ilmu Administrasi ', '<p>Jurusan Ilmu Administrasi fokus pada aspek perencanaan, pengendalian, dan pengorganisasian suatu instansi publik maupun swasta agar mencapai tujuan akhir yang telah ditetapkan. Kamu akan banyak melakukan kajian terhadap berbagai kebijakan di sektor bisnis, publik, atau fiskal, sesuai dengan fokus studimu, sobat karier.</p>', '<ul>\r\n<li>Kemampuan manajerial</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan berpikir strategis</li>\r\n<li>Kemampuan komunikasi</li>\r\n<li>Kemampuan mengelola organisasi</li>\r\n<li>Pemahaman matematika</li>\r\n</ul>', '<p>Bidang pekerjaan yang dapat digeluti oleh lulusan Ilmu Administrasi sangat beraneka ragam, sobat karir tinggal sesuaikan dengan passion masing-masing.</p>\r\n<p>Kamu yang nggak berminat kerja kantoran dan cenderung lebih tertarik dengan dunia bisnis, bisa banget lho jadi Pengusaha selepas lulus dari jurusan Administrasi Niaga (Bisnis).</p>', '<p>Peluang karier yang menanti lulusan Ilmu Administrasi bisa dibilang banyak banget dan sangat beragam. Setiap bidang pekerjaan untuk lulusan Ilmu Administrasi menawarkan jenjang karier yang cukup bervariasi. Keterampilan ilmu administrasi yang didapatkan dari masa perkuliahan dapat menjadi modal kamu untuk bersaing di dunia kerja. Jadi, tinggal pilih deh mau kerja di instansi pemerintah, perusahaan, organisasi nirlaba, berbisnis, atau terjun ke dunia politik? Kalau masih bingung, berikut ini terdapat beberapa pilihan karier yang bisa kamu tekuni: Pegawai Negeri Sipil (PNS), Tata Usaha (Admin) Bagian Penjualan (sales), product manager, bagian personalia. Konsultan pajak, sekretaris, market researcher, administrasi rumah sakit dan lainnya.</p>', '<p>Ilmu Administrasi Niaga (Bisnis) mempelajari proses pengelolaan entitas bisnis ataupun organisasi nirlaba agar tetap stabil dan semakin berkembang. Di jurusan ini sobat karier akan belajar mulai dari operasi, logistik, keuangan, pemasaran, bahkan sumber daya manusia. Materi kuliah yang kamu temui seputar perilaku organisasi, kebijakan dan strategi operasi, perilaku konsumen, perencanaan dan pengendalian keuangan, kapita selekta bisnis, kepemimpinan bisnis, manajemen pelayanan, dll.</p>\r\n<p>&nbsp;</p>\r\n<p>Ilmu Administrasi Negara (Publik) fokus pada tiga elemen penting kehidupan bernegara, yaitu legislatif, eksekutif, dan yudikatif. Selain itu, kamu juga membahas bagaimana mengelola organisasi sektor publik, baik lingkup pemerintahan maupun swasta, dalam hal menyusun dan menerapkan suatu kebijakan. Sobat karier akan belajar teori organisasi, teori pembangunan, sistem perencanaan pembangunan, penganggaran, ekonomi sektor publik, reformasi administrasi, e-governance, kebijakan publik, kepemimpinan, manajemen pelayanan publik, dan masih banyak lagi.</p>\r\n<p>&nbsp;</p>\r\n<p>Ilmu Administrasi Fiskal (Pajak) mempelajari penatausahaan dan pelayanan terhadap kewajiban dan hak wajib pajak orang pribadi maupun badan. Pembahasan selama kuliah di jurusan Administrasi Fiskal tidak lepas dari pajak penghasilan, pajak pertambahan nilai, pajak internasional ketika ada transaksi lintas negara, serta macam-macam pajak daerah. Kamu akan belajar juga lho seputar ketentuan umum perpajakan dan peradilan pajak. Jadi sobat karier diharapkan tidak hanya sekadar ahli menghitung pajak, tapi juga memahami kebijakan pemerintah dari segi teoritis, misalnya apabila terjadi perubahan kebijakan diharapkan mengerti betul bagaimana mengimplementasikan kebijakan itu. Selain ketiga bidang Ilmu Administrasi tersebut, ada juga lho cabang lain yang bisa jadi pilihan untukmu, misalnya Administrasi Rumah Sakit, Administrasi Asuransi dan Aktuaria, serta Administrasi Keuangan dan Perbankan.</p>', 'ilmu_administrasi_.jpg');
INSERT INTO `tb_m_jurusan` (`ID`, `NAMA_JURUSAN`, `DESKRIPSI`, `PENGETAHUAN_DAN_KEAHLIAN`, `KENAPA_HARUS_JURUSAN_INI`, `PROSPEK_KERJA`, `DUNIA_PERKULIAHAN`, `GAMBAR`) VALUES
(22, 'Hubungan Internasional ', '<p>Hubungan Internasional berkaitan erat dengan upaya suatu negara menghadapi tantangan internasional seperti ketidakseimbangan perdagangan dunia, isu keamanan, masalah lingkungan secara global, dan kemiskinan melalui kerja sama antarnegara. Kuliah di jurusan ini memungkinkanmu untuk merasakan atmosfer internasional melalui berbagai simulasi pertemuan-pertemuan penting di dunia, salah satunya sidang PBB.</p>', '<ul>\r\n<li>Kemampuan komunikasi</li>\r\n<li>Kemampuan bahasa asing</li>\r\n<li>Kemampuan berpikir kritis</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan negosiasi dan persuasi</li>\r\n<li>Kemampuan problem solving</li>\r\n</ul>', '<ul>\r\n<li>Seorang lulusan Hubungan Internasional tak jarang memiliki peluang untuk bergabung dengan lembaga internasional seperti PBB, terlebih jika kamu memiliki kemampuan berbahasa Arab, Tionghoa, Inggris, Perancis, Rusia, dan Spanyol. Kemampuan bahasa ini menjadi peluang untuk bergabung dengan lembaga internasional.</li>\r\n<li>Lulusan Hubungan Internasional menjadi salah satu prioritas bagi Kementerian Luar Negeri dalam merekrut calon Diplomat.</li>\r\n</ul>', '<p>Pilihan karier yang menanti lulusan Hubungan Internasional sangat beragam dengan jenis dan jenjang karier yang cukup bervariasi. Gaji yang ditawarkan untuk entry level terbilang sangat kompetitif, tergantung area bekerja, serta kemampuan dan pengalaman yang kamu miliki. Namun, rata-rata lulusan Hubungan Internasional biasanya menempatkan Diplomat sebagai pilihan pertama dalam daftar karier impiannya. Menjadi bagian dari Kementerian Luar Negeri RI memang sangat menarik sobat karier karena kamu berkesempatan untuk keliling dunia dengan menjadi representasi Indonesia. Tapi, bukan berarti bidang lain tidak menarik untuk didalami ya! Berikut ini berapa pilihan karier yang bisa kamu geluti setelah lulus dari jurusan Hubungan Internasional: arsiparis, system analyst, editor,chocolatier, jurnalis (reporter), penyiar, konsultan pendidikan dan lainnya.</p>', '<p>Kuliah di jurusan Hubungan Internasional selama 4 tahun atau 8 semester akan banyak mempelajari hubungan antarnegara, politik dan keamanan global, perdamaian dan konflik, maupun ekonomi politik dan pembangunan internasional. Cakupan materi di Hubungan Internasional sangat luas, sobat karier. Mulai dari globalisasi, organisasi internasional, sistem politik internasional, keuangan global, gerakan sosial global, hukum internasional, hak asasi manusia, konflik etnik, dan sebagainya.</p>\r\n<p>Lalu, apa aja sih bidang kajiannya? Salah satunya kamu bisa memilih studi Perdamaian Internasional jika tertarik menganalisis bagaimana keterlibatan aktor-aktor dalam perang dan isu keamanan internasional, dan bagaimana konteks dan norma baru (seperti gender, human security, dan hukum humaniter internasional) membantu membentuk dan memperkaya proses bina damai (peace-building) di level internasional. Minat kajian lain yang bisa kamu pilih antara lain Kerjasama dan Pembangunan Internasional, serta Politik Internasional.</p>\r\n<p>Beberapa mata kuliah yang akan kamu temui di jurusan Hubungan Internasional antara lain Sejarah Hubungan Internasional, Politik Internasional, Organisasi Internasional, Sejarah Diplomasi, Hukum Internasional, Politik Luar Negeri Indonesia, Hubungan Internasional di Amerika, Hubungan Internasional di Eropa, Hubungan Internasional di Asia Timur, Hubungan Internasional di Timur Tengah dan Afrika. Ekonomi Politik Internasional, dll. Setelah lulus dari jurusan ini, gelar kesarjanaannya pun beragam, tergantung di kampus mana kamu menempuh pendidikan. Ada kampus yang memberikan gelar Sarjana Hubungan Internasional, ada Sarjana Ilmu Politik, ada pula Sarjana Sosial. Jika sobat karier ingin melanjutkan studi ke jenjang pascasarjana, peminatannya pun sangat beragam dengan berbagai pilihan kampus bergengsi di luar negeri yang bisa kamu jadikan referensi.</p>', 'hubungan_internasional_.jpg'),
(23, 'Jurnalistik', '<p>Jurusan Jurnalistik mengajak mahasiswa mendalami dunia jurnalistik beserta karakter dan dinamika yang terjadi di berbagai media massa (televisi, radio, cetak, dan online). Mahasiswa akan mempelajari bagaimana suatu informasi didistribusikan melalui media massa, dan mengetahui karakter masing-masing media beserta perubahannya. Dalam perkuliahan, mahasiswa akan belajar berbagai hal termasuk mencari, menulis, serta menyunting berita. Kemampuanmu menyampaikan pesan melalui berbagai media massa akan terus diasah selama mengenyam pendidikan di jurusan ini. Umumnya, Jurnalistik menjadi salah satu pilihan konsentrasi di Jurusan Ilmu Komunikasi. Namun, di beberapa kampus Jurusan Jurnalistik bisa berdiri sendiri.</p>', '<ul>\r\n<li>Kemampuan analisis</li>\r\n<li>Kemampuan komunikasi</li>\r\n<li>Kemampuan berpikir terstruktur</li>\r\n<li>Kemampuan menulis</li>\r\n<li>Kemampuan membaca</li>\r\n<li>Kemampuan menguasai teknologi informasi dan komunikasi</li>\r\n</ul>', '<ul>\r\n<li>salah satu hal yang istimewa dari jurusan ini adalah mahasiswa bisa belajar tentang liputan dengan turun langsung ke lapangan. Saat turun ke lapangan, mahasiswa akan bertemu dengan berbagai narasumber dengan latar belakang yang berbeda-beda. Setiap narasumber yang ditemui pasti akan memberikan banyak pengalaman dan pembelajaran. Jika memungkinkan saat liputan juga bisa sambil jalan-jalan. Menarik bukan?</li>\r\n<li>Bagi kamu yang memang sudah memiliki hobi menulis sejak masih sekolah, akan sangat membantu jika kamu melanjutkan pendidikan di jurusan ini. Jurusan Jurnalistik memberikan wadah dan peluang yang lebih besar bagi kamu untuk mengeksplor kemampuan menulismu menjadi lebih terarah dan profesional tentunya.</li>\r\n</ul>', '<p>Kuliah di Jurusan Jurnalistik tidak melulu harus menjadi jurnalis kok! Prospek kerja lulusan jurusan jurnalistik cukup luas. So, pastikan pemahaman, wawasan, dan skill yang kamu peroleh selama mengenyam bangku kuliah cukup mumpuni. Hal tersebut menjadi dasar agar kamu tidak kalah saing. Beberapa pilihan karier lulusan Jurnalistik yaitu : 1. Jurnalis 2. Content writer 3. Copywriter 4. Scriptwriter 5. Editor 6. Marketing communication 7. Fotografer 8. Humas</p>', '<p>Di jurusan ini, kamu akan mempelajari banyak hal tentang teknik-teknik jurnalistik. Teknik yang dipelajari akan membantu mahasiswa ketika turun ke lapangan untuk melakukan peliputan dan memperoleh data atau informasi dari orang-orang yang ditemui.</p>\r\n<p>Selama masa studi di jurusan ini, kamu akan mempelajari bagaimana mencari, menulis, menyunting, dan mendistribusikan suatu informasi atau berita di media massa baik cetak maupun elektronik. Kamu juga akan memperoleh materi tentang pengenalan karakter dan manajemen media serta berbagai perubahannya.</p>\r\n<p>Mata kuliah yang akan dipelajari antara lain Pengantar Ilmu Komunikasi, Dasar-dasar Jurnalistik, Bahasa Jurnalistik, Psikologi Komunikasi, Penulisan Berita, Penulisan Feature, Jurnalistik Online, dan Manajemen Media Massa. Jurusan Jurnalistik tersedia dalam jenjang Diploma (D3) hingga Sarjana (S1). Lulusan D3 akan mendapatkan gelar A.Md. Sementara lulusan sarjana Jurnalistik atau Ilmu Komunikasi umumnya mendapatkan gelar S.I.Kom.</p>', 'jurnalistik.jpg'),
(24, 'Manajemen ', '<p>Jurusan Manajemen merupakan bidang keilmuan yang mempelajari tentang kegiatan perusahaan atau korporasi, yang masih memiliki keterkaitan dengan ilmu ekonomi dan bisnis. Jika sobat karir mendalami Ilmu Manajemen maka akan belajar menjadi seorang &ldquo;pengendali&rdquo; layaknya tokoh Aang pada serial Avatar. Jika Aang mengendalikan elemen bumi, kamu akan mengendalikan roda perusahaan berupa kegiatan yang meliputi kebijakan manajemen perusahaan, organisasi, strategi bisnis, ketenagakerjaan dan kepegawaian, manajemen produksi, pemasaran, administrasi, hingga organisasi nirlaba.</p>\r\n<p>Oleh karena setiap hal memiliki tata cara pengelolaan tertentu yang perlu diperhatikan, membuat ilmu manajemen menjadi terus berkembang dan dipelajari secara lebih spesifik. Berikut adalah macam-macam jurusan manajemen yang bisa kamu temui di Indonesia dari berbagai jenjang.</p>\r\n<table style=\"width: 637px;\">\r\n<tbody>\r\n<tr>\r\n<td style=\"width: 112.6px;\">\r\n<p>Jenjang</p>\r\n</td>\r\n<td style=\"width: 511.4px;\">\r\n<p>Jurusan</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"width: 112.6px;\">\r\n<p>S1</p>\r\n</td>\r\n<td style=\"width: 511.4px;\">\r\n<p>Manajemen, manajemen keuangan, manajemen dan bisnis syariah, manajemen dakwah, manajemen industri</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"width: 112.6px;\">\r\n<p>D3</p>\r\n</td>\r\n<td style=\"width: 511.4px;\">\r\n<p>Manajemen informatika, manajemen tata boga, manajemen perpajakan, manajemen usaha perjalanan wisata, manajemen agribisnis, manajemen pemasaran.</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"width: 112.6px;\">\r\n<p>D4</p>\r\n</td>\r\n<td style=\"width: 511.4px;\">\r\n<p>Manajemen Rekayasa Konstruksi, Manajemen produksi pertanian, manajemen sumber daya manusia,</p>\r\n</td>\r\n</tr>\r\n<tr>\r\n<td style=\"width: 112.6px;\">\r\n<p>S2 &amp; S3</p>\r\n</td>\r\n<td style=\"width: 511.4px;\">\r\n<p>Manajemen ekowisata dan jasa lingkungan, manajemen teknologi, manajemen Pendidikan islam, manajemen koperasi,</p>\r\n</td>\r\n</tr>\r\n</tbody>\r\n</table>', '<ul>\r\n<li>Kemampuan mengatur manusia</li>\r\n<li>Kemampuan mengelola keuangan</li>\r\n<li>Kemampuan berkomunikasi</li>\r\n<li>Kemampuan bersosialisasi</li>\r\n<li>Kemampuan manajerial</li>\r\n<li>Kemampuan menganalisis</li>\r\n<li>Sikap kepemimpinan</li>\r\n</ul>', '<ul>\r\n<li>Setiap jenjang karier di tiap-tiap bidang pasti membutuhkan seorang manajer. Hal ini menjadi bukti bahwa Ilmu Manajemen dibutuhkan di setiap lini yang ada di perusahaan.</li>\r\n<li>Sangat mudah bagi kamu untuk bisa bekerja di bidang apapun jika kamu mengambil jurusan ini sebagai pilihan.</li>\r\n<li>Peluang karier yang bisa kamu bisa dapatkan akan semakin luas.</li>\r\n<li>Sumber referensi dari Ilmu Manajemen sangat luas. Kamu bisa mempelajari lebih dalam tentang ilmu ini dari berbagai sumber, seperti buku, internet, youtube, atau jurnal ilmiah.</li>\r\n<li>Kamu akan mendapatkan kesempatan yang sangat luas untuk terus mengembangkan diri di berbagai bidang keilmuan.</li>\r\n</ul>', '<p>Peluang karier yang dimiliki lulusan manajemen bisa bilang sangat luas karena bisa mencakup berbagai jenis pekerjaan dan beragam jenjang karier. Dengan bekal keilmuan yang dipelajari di bangku perkuliahan, pada umumnya penguasaan ilmu manajemen dapat menjadi nilai jual yang patut dibanggakan. Oleh karena itu, kamu tidak perlu bingung akan bekerja apa dan di mana setelah lulus nanti.</p>\r\n<p>Secara umum, rata-rata gaji awal lulusan manajemen berada pada kisaran Rp4.000.000, dengan pekerjaan pada level staf dari bidang tertentu di suatu perusahaan. Meskipun begitu, besaran ini sangat bergantung pada kemampuan, area tempat bekerja, level yang dimasuki, dan pengalaman yang dimiliki.</p>\r\n<p>Karier di sektor ekonomi dan keuangan menjadi pilihan utama bagi lulusan jurusan ini. Meskipun begitu, pada dasarnya banyak sekali potensi yang bisa kamu kembangkan dengan mencoba untuk bekerja di sektor lainnya, seperti pendidikan, media, kreatif, dll. Terlebih lagi, setiap bidang di perusahaan membutuhkan seorang yang memiliki pemahaman mumpuni di bidang manajemen. Kamu juga berpeluang untuk menjadi seorang pengusaha dan merintis bisnis kamu sendiri yang sesuai dengan minat dan bakat kamu</p>', '<p>Dengan memilih Manajemen sebagai program studi selanjutnya, kamu akan mempelajari banyak hal terkait dunia ekonomi dan bisnis. Saat kuliah di prodi Manajemen, sobat karir akan belajar bagaimana caranya mengelola perusahaan baik dalam aspek finansial, operasional, promosi, maupun mengatur struktur organisasi perusahaan. Terdapat beberapa elemen yang bisa kamu pilih untuk mendalami Ilmu Manajemen, seperti Manajemen Keuangan, Manajemen Pemasaran, Manajemen Sumber Daya Manusia, Manajemen Organisasi, Manajemen Operasi, Manajemen Pendidikan, dan lainnya. Umumnya, kamu akan ditempa selama 4 tahun atau 8 semester dan meraih gelar Sarjana Manajemen atau Sarjana Ekonomi setelah menuntaskan studi.</p>\r\n<p>Beberapa mata kuliah yang bisa kamu temui misalnya Pengantar Bisnis, Pengantar Teori Ekonomi, Matematika, Statistika, Akuntansi Manajemen, Akuntansi Biaya dan beberapa mata kuliah yang sangat spesifik seperti, Manajemen Kinerja dan Balas Jasa, Bisnis Ritel, Etika Bisnis, Analisis Laporan Keuangan, Studi Perencanaan dan Kelayakan Bisnis, Manajemen Operasi, Manajemen Strategis, Manajemen Risiko, Manajemen Mutu dan Produktivitas, dan Manajemen Kuantitatif.</p>\r\n<p>&nbsp;</p>\r\n<p>Saking hits dan tingginya minat pada jurusan ini, kamu akan dengan mudah menemukan kampus yang membuka Jurusan Manajemen semudah menemukan franchise minimarket yang tersebar di penjuru kota. Mengacu data dari Kementerian Riset Teknologi dan Pendidikan Tinggi, tidak kurang dari 2.500 jurusan Manajemen dengan variasi konsentrasi dan jenjang yang dapat kamu pilih. Selain itu, peminatan untuk jenjang pascasarjana pun sangat banyak dengan berbagai pilihan kampus bergengsi di luar negeri yang bisa kamu jadikan referensi.</p>\r\n<p>&nbsp;</p>\r\n<p>Oleh karena pilihan kampus yang menawarkan pendidikan pada Prodi Manajemen sangatlah banyak, kamu perlu melakukan riset cukup dan mempelajari detail kurikulum yang ditawarkan di masing-masing kampus. Selain itu, pelajari juga rekam jejak lulusannya ya!</p>', 'manajemen_.jpg'),
(25, 'Ilmu Komputasi', '<p>Program studi Ilmu Komputasi memiliki fokus dibidang pengaplikasian komputer dalam bidang matematika. Mulai dari memodelkan masalah, merancang susunan kimia, hingga mensimulasikan cara kerja sebuah alat yang belum pernah dibuat sebelumnya. Ilmu komputasi juga mempelajari arsitektur komputer dan komputasi kinerja tinggi untuk melakukan perhitungan skala besar yang tidak mungkin dilakukan oleh sebuah komputer umum.</p>', '<ul>\r\n<li>Teliti</li>\r\n<li>Tekun</li>\r\n<li>Detil</li>\r\n<li>Kritis</li>\r\n<li>Observan</li>\r\n<li>Independen</li>\r\n<li>Senang berhitung</li>\r\n<li>Berwawasan luas</li>\r\n<li>Senang menganalisis</li>\r\n<li>Senang melakukan riset</li>\r\n<li>Keterampilan interpersonal</li>\r\n<li>Senang memecahkan masalah</li>\r\n<li>Bisa bekarjasama dengan team</li>\r\n</ul>', '<p>Perkembangan teknologi yang semakin cepat setiap tahunnya membuat lulusan dari program studi ini sangat banyak dicari, lulusan ilmu komputasi tidak hanya memiliki kemampuan dasar di bidang komputer tetapi juga logika matematika yang dapat membantu berbagai perusahaan menemukan solusi dari sebuah masalah. Program studi ini sangat sesuai bagi kalian yang menyukai matematika dan komputer secara umum.</p>', '<p>Lulusan Ilmu Komputasi dapat bekerja diberbagai sektor industri. Mulai dari perbankan hingga pertanian. Lulusan Ilmu Komputasi dapat menjadi seorang programmer, ahli simulator, peneliti, ahli jaringan, keamanan sistem, hingga riset biologi. Lulusan Ilmu Komputasi umumnya bekerja dalam organisasi dan masing-masing departemen untuk mengembangkan berbagai sistem; ordering system, inventory system, billing system, HR dan payroll system, jaringan dan infrastruktur TI sebuah perusahaan. untuk mengembangkan dan membuat saran tentang arah teknis.</p>', '<p>Sobat karier, Ketika kamu memilih jurusan ini akan beberapa mata kuliah yang harus kamu kuasai untuk menyelesaikan prodi ini, diantaranya adalah pemrograman dasar, statistika 1, statistika 2, data mining, probabilitas dan statistika, kecerdasan buatan (Artifical Intelegence) Fisika, Bahasa Inggris, Organisasi dan Arsitektur Komputer, Metode Komputasi, Pengantar Ilmu Komputasi, Persamaan Differensial dan Aplikasi, Pemodelan Stokastik, Komputasi Paralel, Pemodelan dan Simulasi, Komputasi Kinerja TInggi (High Performance Computing), Ekonometrik, Komputasi Finansial, Aljabar Linear, Matematika Diskret, Soft Computing, Machine Learning). Bagaimana sobat karier, sudah cukup tertarik dengan jurusan ini?</p>', 'ilmu_komputasi.jpg'),
(26, 'Ilmu komunikasi ', '<p>Komunikasi adalah suatu kajian ilmu yang sangat luas dan intens, pasalnya dalam kehidupan sehari-hari kita tidak pernah lepas dari komunikasi. Tapi jangan kira kalau ilmu komunikasi itu cuma pelajaran ngomong doang! Tahu nggak, kalau komunikasi itu ada banyak macam nya, mulai dari komunikasi intrapersonal (dengan diri sendiri), komunikasi interpersonal (dengan orang lain), komunikasi kelompok, komunikasi organisasi, hingga komunikasi massa. Ilmu Komunikasi ini adalah induk dari ilmu turunannya yang lain seperti Jurnalistik, Penyiaran, Hubungan Masyarakat (Public Relation), Komunikasi Pemasaran, Desain Komunikasi Visual, Periklanan (Adveritising), Performing Arts Communication, dan lain-lain. Pada program studi Ilmu Komunikasi kita diajarkan tentang bagaimana proses penyampaian pesan agar menjadi efektif dan dapat mencapai sasaran yang dituju. Lulusan program studi Ilmu Komunikasi akan mendapatkan gelar Sarjana Ilmu Komunkasi (S.I.Kom).</p>', '<ul>\r\n<li>Kritis</li>\r\n<li>Berwawasan luas</li>\r\n<li>Senang menganalisis</li>\r\n<li>Senang melakukan riset</li>\r\n<li>Keterampilan komunikasi</li>\r\n<li>Keterampilan interpersonal</li>\r\n<li>Bisa bekarjasama dengan team</li>\r\n</ul>', '<p>Di program studi Ilmu Komunikasi, yang dipelajari bukan hanya cara mengobrol dengan orang lain. Ilmu komunikasi tidak hanya diperuntukkan untuk orang yang suka ngomong atau ekstrovert saja, karena Ilmu Komunikasi sangat luas cakupannya. Kamu yang suka menulis, desain grafis, dan fotografi juga cocok jadi mahasiswa Ilmu Komunikasi. Pelajaran yang di suguhkan di program studi ini juga sangat seru-seru, seperti public speaking, menulis berita, fotografi, desain dan animasi, membuat iklan, film, dan masih banyak lagi. Dalam jurusan Ilmu Komunikasi, kamu akan belajar secara lebih dalam mengenai aspek-aspek komunikasi, baik secara teori dan praktik. Kita bisa juga bilang kalau Ilmu Komunikasi itu adalah gabungan antara ilmu dan seni dalam mengolah pesan. Dengan belajar Ilmu Komunikasi, kamu akan belajar memahami apa saja yang terjadi selama komunikasi itu berlangsung.</p>', '<p>Komunikasi dibutuhkan dalam segala hal yang kita lakukan. Karena pada dasarnya ilmu komunikasi itu lahir dari berbagai disiplin ilmu sosial seperti sosiologi, ilmu politik, antropologi, dan hubungan internasional, nggak heran kalau prospek lulusan Ilmu Komunikasi juga sangat luas. Lulusan Ilmu Komunikasi nggak hanya bisa berkecimpung di industri media, tapi di berbagai macam organisasi. Sebagai humas atau PR di perusahaan atau di pemerintahan, pengamat komuikasi politik, pengamat media, masih banyak, deh pokoknya</p>', '<p>Hai sobat karier, pasti banyak banget ni dari kalian yang penasaran gimana sih kuliah di jurusan Ilmu Komunikasi? Apa ajasih yang bakal dipelajari dijurusan ini, yuk kita Simak beberapa mata kuliah yang harus kamu selesaikan untuk mendapat gelar S.Ikom!! beberapa mata kuliahnya yaitu: Pengantar Ilmu Komunikasi, Teori Ilmu Komunikasi, Sosiologi Komunikasi, Komunikasi Massa, Psikologi Komunitas, Komunikasi Keorganisasian, Komunikasi Antar Pribadi, Teknologi Komunikasi, Metode Penelitian Komunikasi, Pengantar Ilmu Jurnalistik, Filsafat Komunikasi, Komunikasi Politik, Hukum Etika Pers, Public Relations, Media Relations, Manajemen Media Massa, Komunikasi Lintas Budaya, Komunikasi Internasional, Public Speaking, Teknik Wawancara Cetak dan Elektronik, Penulisan Naskah Film dan TV, Ekonomi Politik Media, Jurnalistik Online, Penulisan Feature, Komunikasi Grafis, Komunikasi Pemasaran, Fotografi, Jurnalistik Radio, Kajian Iklan, Teknik Presentasi dan Negosiasi, Perkembangan Teknologi Komunikasi. Wah cukup beragam ya sobat karier. Yukk siapin diri kamu untuk jadi mahasiswa ilmu komunikasi!!</p>', 'ilmu_komunikasi_.jpg'),
(27, 'Pariwisata', '<p>Program studi Pariwisata adalah program studi yang mempelajari semua hal yang berkaitan dengan pariwisata. Biasanya meliputi manajemen destinasi, tour and travel, dan perhotelan. Para lulusan jurusan ini diharapkan mampu memberikan pelayanan hospitalitas yang berkualitas. Selain itu, mahasiswa diharapkan memiliki ketertarikan pada kebudayaan Indonesia sekaligus bisnis</p>', '<ul>\r\n<li>Observan</li>\r\n<li>Independen</li>\r\n<li>Berwawasan luas</li>\r\n<li>Senang bekerja sendiri</li>\r\n<li>Senang melakukan riset</li>\r\n<li>Keterampilan komunikasi</li>\r\n<li>Keterampilan interpersonal</li>\r\n<li>Bisa bekarjasama dengan team</li>\r\n</ul>', '<p>Pariwisata adalah jurusan yang paling menyenangkan, terutama bagi kamu yang punya hobi jalan-jalan. Tapi, jangan berpikir bahwa dengan memilih jurusan ini kamu hanya akan jalan-jalan melulu. Kamu harus bekerja dengan sangat serius. Pariwisata adalah bidang yang tak akan pernah surut, dan saat ini sedang mengalami pertumbuhan yang cukup bagus.</p>', '<p>Saat ini sektor pariwisata Indonesia sedang bergairah. Pemerintah sedang gencar meningkatkan kualitas industri pariwisata. Oleh karena itu, peluang bekerja pun juga semakin lebar. Lulusan program studi Pariwisata dapat bekerja sebagai pemandu wisata, hotelier, pengusaha akomodasi pariwisata seperti hotel dan penginapan, manajer pusat rekreasi, event organizer, dan masih banyak lagi.</p>', '<p>Sobat karier untuk kamu yang kurang begiru suka belajar didalam ruangan dan senang bertemu orang baru jurusan ini cocok nih buat kamu. Yuk kita Simak mata kuliah apa saja yang akan kamu pelajari di jurusan ini: Psikologi Jasa, Dasar-dasar Ilmu Budaya, Pengantar Ilmu Pariwisata, Kepurbakalaan Indonesia, Ekonomi Pariwisata, Sejarah Indonesia, Bahasa Korea, Bahasa Prancis, Bahasa Belanda, Hukum Pariwisata, Pengantar Hospitalitas, Globalisasi dan Dampak Terhadap Pariwisata, Sistem Informasi Pariwisata, Geografi Pariwisata Nasional, MICE, Manajemen Seni Pertunjukan, Manajemen Pengolahan Makanan &amp; Minuman, Seni &amp; Kebudayaan Indonesia, Geografi Pariwisata Internasional, Statistik Pariwisata, Pariwisata Berkelanjutan, Bisnis Pariwisata. Gimana sobat karier, cukup beragam dan menarik banget kan? Yuk siapin diri kamu untuk jadi bagian dari mahasiswa pariwisata!</p>', 'pariwisata.jpg'),
(28, 'Ilmu computer', '<p>Ilmu Komputer merupakan bidang studi yang identik dengan&nbsp;<em>computer programming</em>. Sobat karier akan dibekali keterampilan menyusun algoritma dan&nbsp;<em>programming&nbsp;</em>untuk mengembangkan sebuah aplikasi maupun sistem perangkat lunak. Jadi, pada dasarnya kamu akan belajar bagaimana cara agar komputer mampu melakukan berbagai hal yang diinginkan penggunanya. Di jurusan ini, ide-ide kreatifmu bisa diwujudkan apalagi di dunia informasi digital yang semakin tak terbatas ini!</p>', '<ul>\r\n<li>kemampuan programming</li>\r\n<li>Kemampuan berpikir sistematis</li>\r\n<li>Kemampuan berpikir logis</li>\r\n<li>Kemampuan problem solving</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan riset</li>\r\n<li>Pemahaman matematika</li>\r\n<li>Kreatif, Detail, Tekun</li>\r\n</ul>', '<ul>\r\n<li>Lapangan kerja sangat luas dengan beragam jenis pekerjaan yang keren, bergengsi, juga menawarkan gaji yang menggiurkan. Menarik kan,sobat karier ?</li>\r\n<li>Di era revolusi industri 4.0 seperti sekarang ini, lulusan Ilmu Komputer banyak dibutuhkan baik di instansi pemerintah, BUMN, maupun swasta</li>\r\n<li>Kamu bisa bekerja sebagai programmer atau pengembang perangkat lunak seperti web, aplikasi mobile, aplikasi e-learning, juga game setelah lulus dari jurusan Ilmu Komputer.</li>\r\n<li>Kalau kamu memiliki jiwa bisnis, kenapa tidak mencoba peruntungan dengan mendirikan perusahaan start-up? Dengan begitu, kamu juga berkontribusi dalam menciptakan lapangan kerja baru.</li>\r\n<li>Kamu bisa berkreasi dengan bebas untuk mewujudkan ide-idemu di dunia informasi digital ini.</li>\r\n</ul>', '<p>Peluang karier yang menanti lulusan Ilmu Komputer itu ada banyak sekali,sobat karier . Seluruh sektor membutuhkan lulusan Ilmu Komputer agar dapat bertahan dan bersaing di era revolusi industri 4.0. Jadi, berbekal keilmuan yang kamu pelajari di bangku perkuliahan, lulusan Ilmu Komputer punya nilai jual yang patut dibanggakan.&nbsp;<em>Nggak</em>&nbsp;heran&nbsp;<em>deh</em>&nbsp;kalau jenis dan jenjang kariernya yang ditawarkan sangat bervariasi.</p>\r\n<p>secara umum, rata-rata&nbsp;<strong>gaji awal lulusan Ilmu Komputer berada pada kisaran Rp5.000.000</strong>, dengan pekerjaan sebagai staf dari bidang tertentu di suatu perusahaan. Besaran ini sangat bergantung pada kemampuan dan pengalaman yang kamu dimiliki, area tempatmu bekerja, posisi saat bekerja.</p>', '<p>&nbsp;Kuliah selama 4 tahun atau 8 semester di jurusan Ilmu Komputer akan sering bersentuhan dengan&nbsp;<em>computer programming</em>. Sobat karier akan dibekali kemampuan agar bisa membuat sebuah komputer bisa menjalankan semua fungsi yang diinginkan. Di jurusan ini kamu akan dituntut berpikir secara sistematis, tahapan demi tahapan, agar komputer mampu melakukan berbagai hal sebagaimana keinginanmu. Nah, tahapan demi tahapan ini kamu pelajari lebih dalam di algoritma. Kamu akan&nbsp;<strong>menerjemahkan algoritma menjadi kode-kode di bahasa pemrograman</strong>. Jadi, kuliah di Ilmu Komputer ini sangat memungkinkan untuk kamu mewujudkan ide-ide kreatif. Seru&nbsp;<em>kan</em>,sobat?</p>\r\n<p>Beberapa&nbsp;<strong>mata kuliah</strong>&nbsp;yang akan kamu temui di jurusan Ilmu Komputer antara lain Teori dan Bahasa Automata, Rekayasa Perangkat Lunak, Pemrograman Sistem, Sistem Digital, Sistem Cerdas, Jaringan Komputer,&nbsp;<em>Data Science and Analytics</em>, Analisis Numerik, Desain dan Analisis Algoritma, dan sebagainya. Jurusan ini menawarkan beberapa bidang minat, seperti Arsitektur dan Infrastruktur TI, Teknologi Perangkat Lunak, Pengolahan Informasi Multimedia, juga Kecerdasan Komputasional.</p>\r\n<p>Jurusan Ilmu Komputer terbilang salah satu yang favorit di rumpun sains dan teknologi. Selain itu, tidak banyak kampus yang memiliki jurusan ini dan terakreditasi A. Jadi, kalau kamu benar-benar ingin mengambil jurusan Ilmu Komputer di kampus bergengsi, persiapkan dirimu dengan baik! Setelah lulus dan menyandang gelar&nbsp;<strong>Sarjana Ilmu Komputer</strong>, kamu juga bisa melanjutkan studi ke jenjang pascasarjana. Ada banyak sekali pilihan kampus bergengsi di luar negeri yang bisa kamu jadikan referensi.</p>', 'ilmu_computer.jpg'),
(29, 'Sastra dan Bahasa daerah', '<p>Sastra &amp; Bahasa Daerah merupakan bidang ilmu yang mempelajari sastra dan bahasa daerah yang ada di Indonesia. Misalnya Jawa, Sunda, Bali, Melayu, Batak, Minangkabau, Bugis, dan lainnya. Di jurusan ini, sobat karier akan mempelajari norma dan kaidah dasar pengkajian sastra, bahasa, serta filologi. Kamu pun akan belajar&nbsp;<em>gimana</em>&nbsp;menafsirkan teks dari berbagai variasi zaman dan tradisi masyarakat.</p>', '<ul>\r\n<li>Kemampuan komunikasi lisan</li>\r\n<li>Kemampuan komunikasi tertulis</li>\r\n<li>Kemampuan memahami bacaan</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan berpikir kritis dan rasional</li>\r\n<li>Keterampilan interpersonal</li>\r\n</ul>', '<ul>\r\n<li>Kamu akan mampu menggunakan bahasa daerah dalam berbagai konteks. Selain itu, kamu juga mahir dalam meneliti kebahasaan, sastra, juga pernaskahan. Jadi cocok sekali kalau bekerja di Kementerian Pendidikan dan Kebudayaan, Balai Bahasa, Arsip Nasional, dan sebagainya.</li>\r\n<li>budaya merupakan salah satu daya tarik bagi wisatawan, karenanya lulusan Sastra &amp; Bahasa Daerah bisa terjun ke industri pariwisata.</li>\r\n<li>Kamu juga bisa terjun ke industri media dan kreatif. Misalnya menjadi pembawa acara di stasiun televisi ataupun penyiar radio.</li>\r\n<li>Kamu memiliki kreativitas dalam menuangkan ide sastra menjadi puisi, cerpen, atau karya sastra lainnya menggunakan bahasa daerah. Dengan begitu, selain melestarikan bahasa daerah yang dianggap oleh sebagian orang sudah kuno, kamu bisa jadi terkenal lho.</li>\r\n<li>Kamu juga bisa bepergian ke luar negeri dengan mudah, sobat karier. Misalnya dengan mengikuti misi kebudayaan ke luar negeri, kamu akan memperkenalkan budaya daerah yang ada di Indonesia.</li>\r\n</ul>', '<p>Di era sekarang ini, lulusan Sastra &amp; Bahasa Daerah sangat dibutuhkan untuk melestarikan bahasa dan budaya daerah. Jangan sampai hanya warga negara asing tertarik untuk meneliti bahasa dan budaya di Indonesia, sementara kita sendiri justru malah tidak. Ada banyak peluang karier yang bisa kamu coba untuk mengembangkan potensi diri. Selama kuliah, kamu juga akan belajar mengenai kebudayaan terkait sehingga kamu memiliki banyak pengetahuan terkait budaya yang kamu pelajari termasuk tata cara pernikahan. Selain pada bidang kebudayaan, kamu bisa&nbsp;<em>lho</em>&nbsp;bekerja di sektor perbankan. Karena beberapa masyarakat ada yang menginginkan pelayanan menggunakan bahasa daerah. Selain itu kamu juga bisa menjadi penerjemah lisan, penerjemah tulisan, wedding organizer, pemandu wisata, jurnalis, event planner, guru sekolah dasar, dosen, penulis, editor, peneliti dan sastrawan.</p>', '<p>Sobat karier yang ingin mendalami sastra dan bahasa daerah tertentu di bangku perkuliahan punya beberapa pilihan nih. Di antaranya ada Sastra Jawa, Jawa Kuno, Sunda, Bugis, Melayu, Minangkabau, Batak, juga Bali. Ada juga kampus yang menawarkan jurusan Pendidikan Bahasa dan Sastra Daerah&nbsp;<em>lho</em>&nbsp;untuk menyiapkanmu menjadi Guru Bahasa Daerah. Dengan mengambil jurusan Sastra &amp; Bahasa Daerah sebagai pilihan studi selanjutnya, kamu akan mempelajari banyak hal yang berhubungan dengan ilmu kebahasaan, kesusastraan, juga kebudayaan daerah. Umumnya, kamu akan ditempa selama 4 tahun atau 8 semester untuk meraih gelar<strong>&nbsp;Sarjana Sastra</strong>&nbsp;atau<strong>&nbsp;Sarjana Humaniora</strong>&nbsp;tergantung dengan fakultas dan kampus kamu menuntut ilmu.</p>\r\n<p>Beberapa&nbsp;<strong>mata kuliah</strong>&nbsp;seperti Fonetik, Fonologi, Morfologi, Sintaksis, Semantik, Pragmatik, juga pengkajian puisi, prosa, drama pasti akan sobat karier jumpai di Sastra &amp; Bahasa Daerah. Perbedaannya, kalau kamu mengambil memilih Jurusan&nbsp;<strong>Sastra Jawa</strong>, kamu akan&nbsp;<em>ketemu</em>&nbsp;mata kuliah seperti Tradisi Lisan Jawa, Pranata Jawa, Dinamika Kesusastraan Jawa, Kesenian Jawa, Bahasa Sansekerta, Bahasa Jawa Kuno, Aksara Daerah, Kritik Teks Jawa, Kritik Sastra Jawa, Religi Jawa, dan lainnya. Kalau kuliah Sastra Sunda, kamu akan jumpa dengan mata kuliah Khazanah Sastra Sunda, Bahasa Sunda Kuno, Aksara Sunda, Transliterasi dan Rekonstruksi Teks, Kemahiran Bahasa Sunda, Etnografi, dan sebagainya. Nah, kalau melanjutkan studi&nbsp;<strong>Sastra Bali</strong>, kamu akan<em>&nbsp;ketemu&nbsp;</em>dengan mata kuliah Kebudayaan Bali, Aksara Bali, Kesusastraan Bali Purwa, Kesusastraan Bali Anyar, Bahasa Bali Kawi Gancaran, Bahasa Bali Kawi Tembang, Pranata Bali, Apresiasi Sastra Parwa/Kakawin, Apresiasi Sastra&nbsp;<em>Geguritan</em>/Kidung, dan lain-lain.</p>\r\n<p>Kalau kuliah&nbsp;<strong>Sastra Bugis</strong>, kamu akan jumpa dengan mata kuliah seperti Kapita Selekta Kebudayaan Bugis-Makassar, Seni Pertunjukkan Tradisional, Analisis Wacana Bahasa Bugis-Makassar, Kritik Sastra Bugis-Makassar, Etnografi Sulawesi Selatan, Telaah Pranata Sosial, Politik dan Religi, Kajian&nbsp;<em>La Galigo</em>, Terjemahan&nbsp;<em>Lontaraq</em>, dan sebagainya. Kalau ambil&nbsp;<strong>Sastra Batak</strong>, kamu akan&nbsp;<em>ketemu</em>&nbsp;dengan mata kuliah Aksara Batak (Toba, Angkola/Mandailing, Simalungun, Karo, Pakpak/Dairi), Struktur Masyarakat Batak, Upacara Adat Batak, Analisis Wacana Batak,&nbsp;<em>Foklore</em>&nbsp;Batak, dan lainnya. Kalau memilih Sastra Minangkabau, kamu akan jumpa dengan mata kuliah Etnografi Minangkabau, Dialektika Minangkabau, Peribahasa dan Petatah-Petitih Minangkabau, Wacana Budaya Minangkabau, Bahasa Minangkabau, Pidato Adat dan Alur Pasambahan, dan masih banyak lagi.</p>', 'sastra_dan_bahasa_daerah.jpg'),
(30, 'Arsitektur', '<p>Arsitektur merupakan salah satu jurusan yang cukup populer di Indonesia. Para mahasiswa di program studi Arsitektur mempelajari desain dan rancangan konstruksi bangunan. Arsitektur lebih cenderung menuangkan ide, konsep, dan desain di atas kertas, sedangkan realisasi pembangunannya akan dikerjakan oleh Teknik Sipil. Dalam mendalami arsitektur, para mahasiswa harus mempelajari kekuatan bangunan (firmitas), estetika atau keindahan bangunan (venustas), dan fungsi bangunan (utilitas).</p>', '<ul>\r\n<li>Teliti, tekun dan detail</li>\r\n<li>Kemampuan berhitung</li>\r\n<li>Kemampuan menganalisis</li>\r\n<li>Kemampuan melakukan riset</li>\r\n</ul>', '<p>Pada umumnya, Arsitektur menjadi bagian dari Fakultas Teknik. Uniknya, jurusan ini tidak melulu mengajarkan hal-hal teknik, tapi juga seni dan estetika. Jika kamu melihat bangunan-bangunan indah, itu tidak lepas dari tangan dingin para arsitek hebat yang bisa menggabungkan fungsi, keindahan, dan kekuatan bangunan. Jurusan Arsitektur bisa menjadi pilihan yang tepat bagi kamu yang punya ketertarikan pada desain dan rancang bangunan. Untuk menjadi mahasiswa Arsitektur, kamu paling tidak punya ketertarikan pada matematika, menggambar, seni, humaiora, sains, dan teknologi.</p>', '<p>Profesi arsitek mempunyai prospek yang bagus. Hampir semua perusahaan properti dan konstruksi pasti menggunakan jasa arsitek. Tren properti yang masih melaju kencang menunjukkan bahwa kebutuhan terhadap tenaga arsitek masih tinggi.</p>', '<p>Sobat karier, jurusan arsitektur adalah jurusan yang cukup terkenal dengan penghasilan yang cukup tinggi lho! Kamu bakal belajar banyak hall oh waktu kuliah jurusan ini, matakuliahnya cukup beragam dan menarik. Yukk cari tahu matakuliah apa saja di jurusan ini: Matematika Arsitektur, Estetika Bentuk, Teknik Komunikasi Arsitektur, Gambar Teknik, Arsitektur &amp; Lingkungan, Ilmu Bahan Bangunan Tata Ruang, Mekanika Teknik, Arsitektur Etnik, Pencahayaan, Seni Rupa, Kalkulus, Hukum Lingkungan, Psikologi Arsitektur, Azas &amp; Metoda Perancangan, Perkembangan Arsitektur, Struktur &amp; Konstruksi, Fisika Bangunan, Teknologi Bahan, Perancangan Arsitektur, Fotografi Arsitektur, Utilitas.</p>', 'arsitektur.jpg'),
(31, 'DESAIN KOMUNIKASI VISUAL', '<p>Jurusan Desain Komunikasi Visual atau DKV adalah bagian dari ilmu desain yang mempelajari tentang konsep komunikasi dan ungkapan kreatif, dengan memanfaatkan elemen visual untuk menyampaikan pesan dengan tujuan tertentu. Karena unsur pesan memiliki peran yang sangat penting, lulusan jurusan DKV diharapkan mampu mengeloah pesan tersebut menjadi sesuatu yang menarik, informatif, dan komunikatif, sehingga bisa disampaikan secara efektif.</p>\r\n<p>Mahasiswa jurusan ini bukan hanya dituntut jago gambar, tetapi juga harus mampu menghasilkan karya seni agar dapat mencapai tujuan yang telah ditetapkan, seperti mempengaruhi perilaku seseorang. Sebagai bagian dari cabang ilmu desain, pada jurusan ini mahasiswa akan dibantu untuk bisa mengembangkan bahasa visual dalam bentuk gambar, sekaligus mengolah pesan dalam bentuk kata, agar pesan tersebut mampu diterima oleh sasaran dengan baik.</p>', '<ul>\r\n<li>Kemampuan komunikasi verbal, visual, dan tekstual</li>\r\n<li>Keterampilan menggambar teknis</li>\r\n<li>Kemampuan mengoperasikan software gambar</li>\r\n<li>Kreatif dan inovatif</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan berpikir kritis</li>\r\n</ul>', '<ul>\r\n<li>Kamu akan mendalami ilmu yang lebih spesifik lagi ketika memasuki perkuliahan di tahun ke-3. Konsentrasi minat yang bisa kamu pilih yakni: Komunikasi Grafis, Komunikasi Visual Periklanan, dan Komunikasi Multimedia</li>\r\n<li>Dengan mengambil jurusan DKV kamu juga akan menguasai ilmu desain dari sudut pandang bisnis, karena karya yang kamu buat harus mampu disampaikan sesuai dengan tujuan tertentu, khususnya tujuan perusahaan.</li>\r\n<li>Tak hanya mempelajari&nbsp;<a href=\"https://campus.quipper.com/majors/id-desain-grafis\">desain grafis</a>dua dimensi (2D), kamu juga akan belajar desain untuk diaplikasikan pada media-media baru secara tiga dimensi (3D).</li>\r\n<li>Bekerja sesuai passion menjadi keuntungan utama bagi lulusan DKV. Enak banget kan bisa mendapatkan penghasilan dengan mengerjakan sesuatu yang memang menjadi hobimu</li>\r\n<li>Terdapat banyak software yang bakal kamu kuasai seperti Adobe Photoshop, Adobe Illustrator, Adobe InDesign, Adobe Premier, CorelDraw, SketchUp, dll.</li>\r\n</ul>', '<p><strong>Prospek pekerjaan</strong>&nbsp;untuk sarjana DKV tidak pernah sepi, karena di setiap industri membutuhkan seseorang yang mampu menyampaikan pesan secara visual. Selain itu, sobat karier juga bisa bekerja secara mandiri sebagai freelancer atau entrepreneur seperti, illustrator, fotografer, animator, web designer, dan layouter.</p>\r\n<p>Terdapat beberapa&nbsp;<strong>bidang utama</strong>&nbsp;yang umumnya digeluti lulusan Jurusan Desain Komunikasi Visual, seperti industri media massa, percetakan dan penerbitan, biro konsultan desain, periklanan, production house, film production, serta industri game.</p>\r\n<p>Meskipun begitu, persaingan yang terjadi juga cukup ketatsobat karier. Oleh karena itu, pastikan kamu memiliki portofolio yang beragam, agar peluang kerja yang bisa kamu peroleh juga semakin besar. Dari sisi penghasilan, besaran yang bisa diperoleh juga sangat variatif, bergantung pada kemampuan, area tempat bekerja, jabatan yang diterima, dan pengalaman yang dimiliki.</p>', '<p>Sebelum memasuki&nbsp;<strong>dunia perkuliahan</strong>, umumnya kamu akan menjalani tes khusus yakni tes menggambar. Tes ini merupakan syarat awal bagi calon mahasiswa yang memilih jurusan di fakultas seni rupa, dan salah satunya adalah Jurusan Desain Komunikasi Visual. Jadi, kemampuan dasar menggambar memang sering menjadi tolak ukur untuk bisa menekuni bidang inisobat karier.</p>\r\n<p><strong>Selama 4 tahun atau 8 semester</strong>&nbsp;masa perkuliahan, kamu akan mendapatkan banyak tugas yang akan membuat kamu terbiasa menggunakan beberapa&nbsp;<strong>software</strong>&nbsp;yang berhubungan dengan desain grafis seperti, Adobe Photoshop, Adobe Illustrator, Adobe InDesign, Adobe Premier, CorelDraw, SketchUp, dll. Oleh karena itu, pastikan kamu memiliki perangkat dengan spesifikasi yang cukup dalam membantu kamu melewati masa perkuliahan tersebut.</p>\r\n<p>Mengutip informasi dari usm.itb.ac.id, Setelah melalui berbagai mata kuliah dasar komunikasi visual, pada semester 6, sobat akan dijuruskan pada 3&nbsp;<strong>jalur minat</strong>&nbsp;yaitu: Komunikasi Grafis, Komunikasi Visual Periklanan, dan Komunikasi Multimedia. Selain penjurusan tersebut, beberapa kampus lain juga mempunyai penjurusan lain seperti Desain Ilustrasi, yang akan kamu temukan di Institut Kesenian Jakarta.</p>\r\n<p>Pada dasarnya Komunikasi Grafis dan Komunikasi Visual Periklanan mengolah bahasa visual pada media statis/diam. Kemampuan komunikasi, tipografi, ilustrasi, fotografi menjadi faktor yang harus dikuasai. Desainer Grafis mampu membuat logo, desain majalah/surat kabar, rambu (sign system), desain kemasan, paket promosi produk dan lain-lain dengan keahliannya tersebut.</p>\r\n<p>Desainer Iklan mampu bermain visual dengan menarik dan efisien untuk tujuan persuasi. Mengemas citra sebuah produk/program/kampanye dengan bahasa visual yang baik, yang bermuara pada perubahan perilaku sasaran yang dituju.</p>\r\n<p>Sementara Komunikasi Multimedia mengarah pada media dinamis berbasis waktu dan suara (audio). Animasi, desain web, media interaktif hingga peyutradaraan film adalah contoh pekerjaan desainer multimedia. Dasar-dasar komunikasi visual teraplikasikan secara dinamis dalam karya multimedia.</p>', 'desain_komunikasi_visual.jpg'),
(32, 'Penerbangan (Pendidikan pilot)', '<p>Penerbangan merupakan jurusan yang mempelajari ilmu pengoperasian anekaragam jenis pesawat terbang. Untuk dapat menempuh pendidikan di jurusan ini ada beberapa ketentuan dan pesyaratan baik fisik maupun akademisi yang harus dipenuhi seperti tinggi badan, sehat jasmani dan rohani, kemampuan bahasa, kemampuan matematika, hingga fisika.</p>', '<ul>\r\n<li>lulusan jurusan ini dapat mengerjakan pekerjaan dengan teliti, detil, dan terstruktur.</li>\r\n<li>Lulusan jurusan ini mampu mengobservasi dan melakukan analisa sebelum melakukan tindakan.</li>\r\n<li>Lulusan jurusan penerbangan juga punya wawasan yang luas di bidang penerbangan dan pengoperasioan peswat terbang.</li>\r\n<li>Lulusan jurusan penerbangan memiliki keterampilan interpersonal dan mampu berpikir secara rasional.</li>\r\n<li>Lulusan jurusan penerbangan mampu menjadi problem solver ketika dibutuhkan dan mampu bekerja sama dalam tim.</li>\r\n</ul>', '<ol>\r\n<li>Pilot memiliki ratarata gaji yang tinggi</li>\r\n</ol>\r\n<p>Profesi seorang pilot bukanlah sembarang profesi. Sebab pilot memiliki tanggungjawab terhadap keselamatan penumpang dan awak kabin pesawat. Oleh karena itu, bayaran atau gaji seorang pilot juga tinggi mengingat risiko pekerjaannya. Gaji seorang pilot bisa mencapai puluhan juta untuk sekali terbang, lho.</p>\r\n<ol start=\"2\">\r\n<li>Memiliki profesi yang menjanjikan dan diinginkan banyak orang</li>\r\n</ol>\r\n<p>Siapa di antara Sobat karier yang sejak kecil punya cita-cita menjadi pilot? Profesi ini memang kelihatan menyenangkan ya. Selain keren karena bisa bepergian ke mana-mana kamu juga digaji tinggi. Sangat menjanjikan bukan.</p>\r\n<p>&nbsp;</p>\r\n<ol start=\"3\">\r\n<li>Salah satu jurusan dengan Tingkat seleksi ketat</li>\r\n</ol>\r\n<p>Pendidikan penerbangan merupakan salah satu jurusan yang punya seleksi cukup ketat. Sebab lulusannya dituntut untuk menjadi pribadi yang kuat dan sehat secara jasmani rohani dan punya kemampuan terbaik. Oleh karena itu, sobat karier yang ingin menjajal jurusan ini persiapkan diri sebaik mungkin.</p>', '<p>Gelar yang diperoleh lulusan jurusan Penerbangan (Pendidikan Pilot) di Indonesia adalah Sarjana Terapan Transportasi (S.Tr.Tra). Prospek kerja progam studi ini diantaranya, Ahli Antariksa, Pilot, Kopilot dan Ahli Penerbangan.</p>', '<ul>\r\n<li>Lulusan jurusan ini dapat mengerjakan pekerjaan dengan teliti, detil, dan terstruktur.</li>\r\n<li>Lulusan jurusan ini mampu mengobservasi dan melakukan analisa sebelum melakukan tindakan.</li>\r\n<li>Lulusan jurusan penerbangan juga punya wawasan yang luas di bidang penerbangan dan pengoperasioan peswat terbang.</li>\r\n<li>Lulusan jurusan penerbangan memiliki keterampilan interpersonal dan mampu berpikir secara rasional.</li>\r\n<li>Lulusan jurusan penerbangan mampu menjadi problem solver ketika dibutuhkan dan mampu bekerja sama dalam tim.</li>\r\n</ul>', 'penerbangan_(pendidikan_pilot).jpg'),
(33, 'Seni kriya', '<p>Seni kriya adalah seni kerajinan tangan yang sangat bernilai karena lahir dari kultur budaya dan memperkaya identitas Indonesia sehingga wajib dipelihara keberadaannya. Beberapa contoh karya seni kriya yaitu anyaman, tembikar, dan topeng. Sering diidentikkan dengan kerajinan, sesungguhnya seni kriya sangat berbeda karena produknya bersifat eksklusif.</p>\r\n<p>Jurusan Seni Kriya mungkin tidak begitu populer dibanding jurusan seni lainnya. Meski begitu, jurusan ini tak bisa diremehkan begitu saja. Di jurusan ini kamu akan diberikan ilmu seni dan desain untuk menghasilkan suatu karya seni atau produk yang memiliki nilai estetika tetapi tak meninggalkan nilai fungsionalnya. Hal ini terlihat dari produk kriya yang memiliki kualitas desain orisinal yang mengandung pesan filosofi, sehingga tak mengherankan apabila produknya bernilai estetis tinggi dan diagungkan.</p>\r\n<p>Produk seni kriya menyerap nilai serta unsur tradisional untuk melestarikan citra tradisi Indonesia. Umumnya, proses pembuatan kriya berlangsung dalam waktu yang lama dan mengandalkan tenaga manusia. Oleh karena itu produknya sulit untuk ditiru dan dibajak sebab memiliki keunikan tersendiri.</p>', '<ul>\r\n<li>Kemampuan berpikir kritis dan analitis</li>\r\n<li>Kemampuan mengekspresikan perasaan melalui seni</li>\r\n<li>Kemampuan mengorganisir kegiatan seni kriya</li>\r\n<li>Kemampuan menyajikan karya seni</li>\r\n<li>Kemampuan bekerja secara individu dan tim</li>\r\n<li>Kreatif dan artistik</li>\r\n</ul>', '<ul>\r\n<li>Selain mendalami seni, kamu juga akan dibekali keterampilan mendesain. Mengingat seni kriya adalah gabungan dari ilmu seni dan desain. Keterampilan mendesain inilah yang akan berguna saat kamu membuat produk kriya yang bernilai estetika tinggi.</li>\r\n<li>Meskipun masuk dalam cabang seni rupa, yang akan kamu pelajari di jurusan ini sangat luas. Selain seni, kamu juga akan mempelajari desain, kebudayaan, filsafat, sosiologi, digital dan masih banyak lagi.</li>\r\n<li>Jika kamu menyukai seni rupa, maka cocok sekali untuk masuk jurusan ini. Di jurusan in kamu bisa mendalami minatmu dalam bidang seni rupa. Banyak tugas dan mata kuliah yang akan berkaitan dengan menggambar.</li>\r\n<li>Umumnya karya seni kriya memiliki desain yang menyerap nilai-nilai budaya tradisional. Dengan kamu masuk prodi ini, secara tak langsung kamu telah membantu melestarikan budaya tradisional yang hampir tergerus budaya modern.</li>\r\n<li>Jurusan bidang seni memang tidak mendidik mahasiswanya untuk menjadi pekerja kantoran, melainkan sebagai orang yang kreatif dan mandiri. Di program studi seni kriya kamu akan dibiasakan untuk menjadi individu yang selalu penuh dengan ide-ide kreatif, sehingga diharapkan nantinya dapat bekerja secara mandiri dengan memanfaatkan keterampilan serta pengetahuannya.</li>\r\n<li>Jika sebelumnya kamu adalah peminat karya seniman, maka dengan masuk jurusan ini kamu dapat menjadi seorang seniman itu sendiri. Selama kuliah, pengetahuan kamu terhadap seni akan semakin luas dan mendalam. Sehingga sangat mungkin sekali bagi kamu untuk menciptakan karya seni yang digemari masyarakat.</li>\r\n<li>Ketika kamu berhasil menciptakan karya seni yang dikenal sampai kancah domestik hingga internasional, tentu meningkatkan kemungkinan kamu untuk travelling keliling Indonesia bahkan luar negeri. FYI, orang-orang dari negara lain sangat menghormati seorang seniman lho!</li>\r\n<li>Pilihan karier setelah lulus kuliah tidak sesulit yang kamu bayangkan. Kamu dapat bekerja di banyak industri kreatif, menjadi konsultan desainer bahkan bekerja mandiri. Dengan pengetahuan, keterampilan serta kreativitas yang kamu miliki, kamu pun dapat membangun bisnis sendiri yang sesuai dengan jurusan kamu.</li>\r\n</ul>', '<p>Prospek kerja lulusan Jurusan Seni Kriya cukup luas, mengingat industri kreatif masih membutuhkan ahli dalam bidang seni kriya. Misalnya saja, lulusan Jurusan Seni Kriya dapat bekerja di perusahaan fashion sebagai&nbsp;<strong>fabric designer</strong>. Tugasnya adalah mengolah, mengaplikasikan serta menggabungkan beberapa teknik dalam menghasilkan bahan yang sesuai untuk proses desain selanjutnya.</p>\r\n<p>Selain itu, kamu juga bisa berkarier sebagai sebagai konsultan designer. Dalam menjalani profesi ini kamu bisa menjalaninya dengan bergabung di suatu perusahaan atau bekerja secara mandiri. Kemampuan kamu dalam bidang desain yang dipelajari selama perkuliahan akan sangat terpakai ketika menjalan profesi ini.</p>\r\n<p>Pengetahuan bidang kesenian yang cukup komplit bisa menjadi modal besar juga untukmu jika ingin berkarier sebagai&nbsp;<strong>kurator seni</strong>&nbsp;dan bekerja di museum atau tempat penyimpanan koleksi seni lainnya. Namun, kamu juga harus memperkaya referensi dengan beberapa pengetahuan pendukung seperti, ilmu sejarah.</p>\r\n<p>Lalu, bekerja sebagai&nbsp;<strong>wiraswasta</strong>&nbsp;pun bisa kamu lakukan. Pilihan bisnisnya cukup banyak, baik itu sebagai pengusaha kerajinan tenun, gerabah, anyaman, patung, wayang kulit, dan masih banyak lagi. Produk yang kamu hasilkan bisa disesuaikan dengan target pasar, entah itu sebagai peralatan yang dapat digunakan sehari-hari maupun sebagai hiasan. Dengan perencanaan bisnis yang tepat, kamu bisa menghasilkan omzet yang lumayan</p>', '<p>Umumnya, mahasiswa yang memilih kuliah di Jurusan Seni Kriya adalah mahasiswa dengan bakat dan minat yang tinggi terhadap seni rupa, lalu memutuskan kuliah di jurusan ini karena seni kriya dianggap&nbsp;<strong>lebih aplikatif dan fungsional</strong>&nbsp;dari seni rupa. Sekalipun demikian, untuk kuliah di jurusan ini kamu tidak diwajibkan harus mahir menggambar.</p>\r\n<p>Pada semester awal, kamu akan fokus&nbsp;<strong>mempelajari ilmu</strong>&nbsp;yang mendasar seperti sejarah fashion, budaya daerah, dan juga dasar seni rupa &amp; desain. Kemudian di semester berikutnya kamu mulai mendalami lebih jauh tentang kriya tekstil, sosiologi kriya, celup rintang, dan lain-lain.</p>\r\n<p>Maka dari itu, dari segi tugas pun untuk semester pertama terbilang cukup santai, masih seputar gambar bentuk dan seni kriya dasar. Pada semester lanjut,&nbsp;<strong>tugas-tugasnya</strong>&nbsp;juga semakin variatif, yakni menggambar teknik, teknik produksi kriya, seni batik, dan masih banyak lagi.</p>\r\n<p>FYI, Jurusan Seni Kriya juga terbagi menjadi beberapa jenis&nbsp;<strong>peminatan</strong>. Umumnya, tersedia empat program peminatan yaitu Kriya Kayu, Kriya Keramik, Kriya Logam, dan Kriya Tekstil. ada juga alternatif jurusan masih erat tentang seni yaitu&nbsp;<a href=\"https://campus.quipper.com/majors/id-rias-dan-busana\">tata rias</a>.</p>', 'seni_kriya.jpg');
INSERT INTO `tb_m_jurusan` (`ID`, `NAMA_JURUSAN`, `DESKRIPSI`, `PENGETAHUAN_DAN_KEAHLIAN`, `KENAPA_HARUS_JURUSAN_INI`, `PROSPEK_KERJA`, `DUNIA_PERKULIAHAN`, `GAMBAR`) VALUES
(34, 'Seni tari', '<p>Kuliah di jurusan Tari nggak hanya membuatmu menjadi seorang penari yang andal tapi juga bisa menciptakan tarian mu sendiri. Tari adalah bidang ilmu yang mengajarkan mu upaya untuk mengungkapkan perasaan dan pikiran dalam gerak tubuh yang menyesuaikan dengan irama. Nggak hanya itu kamu juga akan belajar bagaimana menghayati dan mempelajari filosofi tarian sehingga tarian akan lebih &ldquo;bernyawa&rdquo; saat kamu pentaskan nanti. Dalam seni tari, kamu akan mempelajari bagaimana memadukan berbagai unsur seperti raga, irama, dan rasa. Selain itu, sobat karier juga akan mempelajari koreografi dari berbagai jenis tarian mulai dari tari tradisional sampai tari modern.</p>', '<ul>\r\n<li>Kemampuan meneliti fenomena seni-budaya</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan menciptakan tarian</li>\r\n<li>Kemampuan mengekspresikan gagasan dalam bentuk tarian</li>\r\n<li>Kemampuan menyajikan tarian yang kreatif dan inovatif</li>\r\n<li>Kemampuan mengelola pertunjukan seni</li>\r\n</ul>', '<ul>\r\n<li>kapan lagi bisa mendapatkan penghasilan dari hobi yang kamu tekuni dengan serius? Ya, ternyata hobi menari kalau ditekuni bisa menghasilkan pundi-pundi Rupiah. Ada beragam variasi profesi yang bisa kamu tekuni. Apalagi kalau kamu punya latar belakang pendidikan Tari, wah makin dicari dan tentunya makin menggiurkan penghasilan mu.</li>\r\n<li>Kesempatan yang luas untuk bekerja sebagai Koreografer. Siapa tahu suatu saat nanti kamu bisa dipercaya untuk mengatur dan membuat tarian bagi penari latar di konser penyanyi terkenal.</li>\r\n<li>Kalau kamu suka akting di depan kamera, bisa terlibat dalam produksi pentas teater atau sendratari lho. Apalagi kalau bergabung di kelompok ternama, wow take home pay yang kamu terima sangat menggiurkan deh.</li>\r\n<li>Kamu juga bisa bepergian ke luar negeri dengan mudah,sobat karier . Misalnya ikut misi kebudayaan dari satu negara ke negara lain, di sana kamu akan memperkenalkan budaya Indonesia, khususnya tarian daerah.</li>\r\n<li>Lulusan jurusan Tari juga memiliki kesempatan yang besar untuk berburu beasiswa S2 ke luar negeri, apalagi di Eropa banyak banget lembaga pendidikan tinggi yang memiliki jurusan Seni Tari.</li>\r\n</ul>', '<p>Lulusan Tari punya peluang karier yang sangat luas. Berbekal keilmuan yang dipelajari di bangku perkuliahan juga pengalaman yang kamu punya, bisa jadi nilai tambah untuk melamar pekerjaan, apalagi jika kamu ingin bergabung ke kelompok tari profesional. Rata-rata gaji awal Koreografer berada pada rentang Rp4.000.000 sampai Rp10.000.000, sobat karir. Selain jadi Penari atau Koreografer, lulusan Tari bisa mengembangkan potensi dan bakat di bidang pekerjaan yang lain. Bahkan kamu bisa jadi Pengajar Seni di berbagai kantor perwakilan Indonesia di luar negeri.&nbsp;<em>Go international</em>! Nah, berikut ini beberapa pilihan karier yang bisa kamu geluti:</p>', '<p>Di jurusan Tari, kamu akan belajar selama 4 tahun atau 8 semester untuk&nbsp;<strong>mengkaji, menciptakan, dan mengelola seni tari</strong>&nbsp;yang selaras dengan perubahan sosial-budaya.&nbsp;<em>Nggak</em>&nbsp;heran kalau kamu bukan hanya diajak untuk sekadar melestarikan seni tari tapi juga bisa mengembangkan tari dari daerahmu sesuai dengan kreativitasmu. Biasanya saat tugas akhir sebagai syarat kelulusan kamu bisa menyajikan karya seni tari yang kamu ciptakan atau menyusun penelitian yang berisi kajian atas suatu karya. Nah kalau sudah lulus, kamu berhak atas gelar&nbsp;<strong>Sarjana Seni</strong>.</p>\r\n<p><strong>Mata kuliah</strong>&nbsp;yang bisa kamu temui di jurusan Tari misalnya Sosiologi Tari, Antropologi Tari, Manajemen Seni, Produksi Tari, Manajemen Seni, Sejarah Seni, Sejarah Tari, Seni Pertunjukkan Indonesia, Analisis Tari (Struktural, Koreografi, dan Semiotika), Analisis Gerak (Karakter dan Laban), Olah Tubuh, Kritik Tari, Etnokoreologi, Musik Tari, Teknik Tari dan Kreativitas, Tata Rupa Pentas, Tari Yogyakarta, Tari Surakarta, Tari Bali, Tari Sunda, Tari Sumatra, Tari Banyumas, Tari Jawa Timur, Dokumentasi Tari, dan lain-lain.</p>\r\n<p>Kalau sobat karir. ingin lanjut ke jenjang&nbsp;<strong>pascasarjana</strong>, ada berbagai pilihan kampus yang bisa dijadikan referensi. Kalau di Indonesia, pilihan programnya ada S2 Penciptaan dan Pengkajian Seni juga S2 Tata Kelola Seni. Nah di dalamnya terdapat beberapa variasi peminatan yang bisa kamu pilih. Oh iya, jika bercita-cita ingin jadi Guru, bisa&nbsp;<em>lho</em>&nbsp;mengambil jurusan Pendidikan Seni Tari. Di beberapa kampus ada pula yang menawarkan paket komplit, namanya jurusan Pendidikan Seni Drama, Tari, dan Musik. Komplit kan? Jadi, selain mempelajari&nbsp;<a href=\"https://campus.quipper.com/majors/id-teater-drama\">teater drama</a>, tari, dan musik kamu juga akan belajar bagaimana mengajarkannya secara tepat. Kamu juga bisa melanjutkan program pascasarjana, misalnya mengambil S2 Pendidikan Seni.</p>', 'seni_tari.jpg'),
(35, 'Rias dan Busana', '<p>Sobat karir, siapa nih yang suka mengikuti perkembangan informasi dari para&nbsp;<em>beauty blogger</em>&nbsp;atau<em>&nbsp;fashion influencer</em>? Bidang rias dan busana memang bidang yang seru<em>&nbsp;banget</em>&nbsp;untuk diikuti, bahkan bisa&nbsp;<em>lho</em>&nbsp;dipelajari dengan serius jika kamu kuliah di Jurusan&nbsp;<a href=\"https://campus.quipper.com/majors/id-tata-rias-dan-kecantikan\">Tata Rias</a>&nbsp;maupun Tata Busana. Rias dan Busana adalah bidang yang fokus pada keahlian menghias wajah dan pakaian. Di jurusan ini, sobat karir&nbsp; akan mempelajari struktur wajah, jeni-jenis alat kecantikan, dan tentu saja teknik menghias wajah. Sementara, menghias pakaian menitik beratkan pada pembelajaran teknik penyempurnaan hiasan pakaian.</p>', '<ul>\r\n<li>Kemampuan menuangkan gagasan dalam karya</li>\r\n<li>Kemampuan manajerial</li>\r\n<li>Kemampuan berpikir rasional</li>\r\n<li>Kemampuan meneliti</li>\r\n<li>Detil, teliti, tekun</li>\r\n<li>Kreatif dan Inovatif</li>\r\n</ul>', '<ul>\r\n<li>Kamu nggak harus bekerja pada orang lain lho, sobat karis. Dengan bekal ilmu dan keterampilan yang kamu miliki, bisa banget menciptakan lapangan pekerjaan. Buka usaha modiste, butik, salon kecantikan, spa, dan sebagainya.</li>\r\n<li>Kamu bahkan bisa meraup pundi-pundi Rupiah sejak duduk di bangku kuliah, buka jasa make up untuk acara wisuda, pasti laris manis. Jadi jangan lupa untuk menunjukan portofolio di akun media sosialmu, sobat karir.</li>\r\n<li>Sekarang jamannya banyak bermunculan beauty vlogger, nah kamu juga bisa lho mengikuti jejak mereka. Semakin ramai channel-mu, katanya akan semakin besar uang yang dihasilkan.</li>\r\n<li>Perusahaan yang bergerak di industri fashion juga membutuhkanmu untuk membuat rancangan dan pattern untuk produksi pakaian secara massal.</li>\r\n<li>Terjun ke dunia media juga tidak ada salahnya untuk dicoba. Kamu bisa jadi jurnalis untuk bidang beauty and fashion.</li>\r\n</ul>', '<p>Prospek kerja lulusan Rias dan Busana&nbsp;<em>nggak</em>perlu diragukan lagi karena akan banyak banget! Bahkan sebelum kamu lulus kuliah kamu bisa mulai meniti karier mu. Keterampilan juga ilmu merias wajah dan menata rambut yang kamu dapat bisa jadi modal berharga untuk jadi<em>&nbsp;Make Up Artist</em>&nbsp;(MUA) Mulai dari jasa&nbsp;<em>make-up&nbsp;</em>wisuda lama-lama bisa jadi perias pengantin bahkan nggak menutup kemungkinan kamu bisa jadi penata rias para selebriti. Sementara, kamu yang punya keahlian&nbsp;<a href=\"https://campus.quipper.com/majors/id-fashion-design\">merancang busana</a>&nbsp;bisa mengaplikasikan ilmu dengan membuat pakaianmu, siapa tahu kan ada yang tertarik juga? Lama-lama juga bisa&nbsp;<em>dong</em>&nbsp;punya&nbsp;<em>clothing brand</em>. Nah, selepas kuliah, banyak banget peluang karier yang menanti lulusan Rias dan Busana. Jenisnya sangat beragam.</p>', '<p>Nggak cuma punya prospek karier yang asyik, perkuliahan di jurusan Rias dan Busana pun asyik banget nih. Program pendidikan yang ditawarkan oleh jurusan ini juga beragam. Ada&nbsp;<strong>program vokasi</strong>&nbsp;jurusan&nbsp;<strong>Tata Rias</strong>&nbsp;juga&nbsp;<strong>Tata Busana</strong>&nbsp;yang ditempuh dalam waktu&nbsp;<strong>3 tahun atau 6 semester</strong>. Ada pula program yang menyiapkanmu menjadi Guru di SMK, namanya jurusan Pendidikan Tata Rias serta Pendidikan Tata Busana yang umumnya ditempuh dalam waktu&nbsp;<strong>4 tahun atau 8 semester</strong>. Lalu apa&nbsp;<em>sih</em>&nbsp;bedanya Tata Rias dan Tata Busana itu?</p>\r\n<p><strong>Tata Rias</strong>&nbsp;fokus mempelajari tata rias wajah dan rambut. Cara menyanggul, menata rambut, memotong rambut, merias wajah, sampai perawatan kulit dan rambut akan jadi makan sehari-hari. Beberapa&nbsp;<strong>mata kuliah</strong>&nbsp;yang akan kamu jumpai di jurusan Tata Rias antara lain Tata Rias Wajah, Tata Rias Fantasi, Desain Tata Rias, Perawatan Kulit Wajah, Ilmu Kesehatan Kulit dan Rambut, Kosmetologi, Tata Rias Pengantin Indonesia, Tata Rias Pengantin Internasional, Dekorasi Rias, Penataan Rambut dan Sanggul Tradisional, Penataan Rambut dan Sanggul Modern, Pewarnaan Rambut, Pangkas Rambut Dasar, Keriting dan Pelurusan Rambut, Solus per Aqua, Pengelolaan Usaha Tata Rias, dan sebagainya.</p>\r\n<p>&nbsp;</p>\r\n<p>Nah, kalau<strong>&nbsp;Tata Busana</strong>&nbsp;fokus pada segala proses dalam merancang busana, mulai dari gambar desain, bikin pola, memotong pola, menjahit, sampai benar-benar jadi pakaian. Puncaknya, biasanya ada f<em>ashion show</em>, sobat karir! Beberapa&nbsp;<strong>mata kuliah</strong>&nbsp;yang bakal kamu temui di jurusan Tata Busana misalnya Konstruksi Pola Busana, Teknik Menjahit, Busana Anak, Busana Kerja, Busana Pria, Busana Pesta, Kriya Tekstil, Desain Sulaman, Desain Mode, Analisis Pola Busana, Tren Mode,&nbsp;<em>Draping</em>,&nbsp;<em>Tailoring</em>,&nbsp;<em>Grading</em>, Manajemen Usaha Busana, dan lainnya.</p>', 'rias_dan_busana.jpg'),
(36, 'Ilmu Keperawatan', '<p><span lang=\"EN-ID\">Ilmu Keperawatan merupakan bidang studi yang menyiapkan kamu menjadi seorang perawat. Di jurusan ini sobat karir akan mempelajari teori dan teknologi baru untuk mengembalikan dan merawat kesehatan mental dan fisik seseorang yang mengidap suatu penyakit dan penyandang disabilitas. Bidang spesialisasi untuk setiap kelas perawat antara lain perawat dewasa, perawat anak-anak, perawat manula, perawat untuk mental, dan perawatan jalan.</span></p>', '<ul>\r\n<li>Kemampuan komunikasi</li>\r\n<li>Kemampuan berpikir kritis</li>\r\n<li>Kemampuan problem solving</li>\r\n<li>Kemampuan bekerja secara tim</li>\r\n<li>Keterampilan interpersonal</li>\r\n<li>Teliti, detail, tekun</li>\r\n</ul>', '<ul>\r\n<li>Kebutuhan masyarakat akan pelayanan dan asuhan kesehatan yang semakin meningkat secara tidak langsung juga berimplikasi pada meningkatnya kebutuhan tenaga medis, salah satunya perawat. Jadi, sobat karir, tak perlu risau ya akan peluang kerjanya.</li>\r\n<li>Lapangan kerja lulusan Ilmu Keperawatan sangat luas, mulai dari di rumah sakit, puskesmas, klinik kesehatan, home care, panti jompo, dan sebagainya.</li>\r\n<li>Menjadi seorang perawat, memungkinkanmu untuk go international lho! Karena perawat merupakan salah satu profesi yang diikutsertakan dalam pasar bebas ASEAN. Jadi persiapkan dirimu agar mampu bersaing dengan perawat-perawat dari negara-negara di ASEAN.</li>\r\n<li>Tenaga perawat Indonesia juga dibutuhkan oleh Negeri Sakura. Kalau kamu lulus seleksi maka akan dikirim sebagai kandidat nurse (perawat klinis) juga careworker yang ditempatkan di rumah sakit maupun panti jompo di berbagai wilayah.</li>\r\n<li>Orang lain aja dirawat dengan sepenuh hati, bagaimana keluarga? Wah idaman banget deh lulusan Ilmu Keperawatan.</li>\r\n</ul>', '<p>Sobat karir tak perlu khawatir soal prospek kerja lulusan Ilmu Keperawatan. Sekalipun setiap tahun ada lulusan baru, lapangan kerja yang tersedia masih luas. Karena saat ini kebutuhan masyarakat akan pelayanan kesehatan juga meningkat. Selain di Rumah Sakit, lulusan perawat bisa praktik di Puskesmas, Klinik Kesehatan, Panti Jompo, dan menjadi perawat pribadi di suatu keluarga. Secara umum, rata-rata gaji awal seorang perawat berada pada kisaran Rp4.000.000, dengan mempertimbangkan kemampuan, area tempat bekerja, level yang dimasuki, dan pengalaman yang dimiliki. Bergabung menjadi tim gawat darurat yang terjun ke lokasi bencana juga tidak kalah mulia&nbsp;<em>lho</em>, sobat karir. Nah, kamu pun bisa mengeksplorasi bakatmu dengan bekerja di perusahaan asuransi atau menjadi akademisi dan peneliti.</p>', '<p>Kalau sobat karir memutuskan untuk melanjutkan studi di jurusan Ilmu Keperawatan, selama 4 tahun atau 8 semester kamu akan fokus pada perawatan individu agar bisa mencapai, mempertahankan, atau memulihkan kesehatan yang optimal juga kualitas hidupnya. Kamu akan belajar tentang pemenuhan kebutuhan dasar manusia, termasuk bio, psiko, sosio, spiritual dan kultural. Nantinya setelah lulus, jika sobat karir menjadi seorang perawat, kamu akan bertugas mendampingi dokter dan bertanggungjawab pada proses pemulihan kesehatan pasien.</p>\r\n<p>Beberapa&nbsp;<strong>mata kuliah</strong>&nbsp;yang bisa kamu temui misalnya Dasar-Dasar Ilmu Keperawatan, Keperawatan Dewasa, Keperawatan Maternitas, Keperawatan Jiwa, Keperawatan Anak, Keperawatan Gerontik, Keperawatan Gawat Darurat, Keperawatan Keluarga, Keperawatan Komunitas, Keperawatan Kesehatan Daerah Pantai, Psikologi dalam Keperawatan, Manajemen Keperawatan, dan sebagainya. Setelah lulus dengan gelar&nbsp;<strong>Sarjana Keperawatan</strong>, jika kamu ingin menjadi perawat di Rumah Sakit maka kamu harus menempuh Studi Profesi&nbsp;<em>Ners</em>&nbsp;selama 1 tahun.</p>\r\n<p>&nbsp;</p>\r\n<p><strong>Pendidikan profesi*</strong>&nbsp;ners<em>&nbsp;biasanya dilaksanakan melalui praktik di pusat pelayanan kesehatan. Jadi sobat karir. akan dibekali dengan pengalaman profesional dengan belajar secara langsung di rumah sakit ataupun klinik kesehatan lainnya. Selama menempuh pendidikan profesi&nbsp;</em>ners* ini, kamu akan menerapkan segala teori dan konsep yang telah dipelajari di bangku kuliah. Kamu pun akan melaksanakan asuhan keperawatan serta mengelola pelayanan keperawatan. Nah, kalau ingin melanjutkan studi ke jenjang&nbsp;<strong>pascasarjana</strong>&nbsp;juga ada banyak sekali kampus bergengsi yang bisa kamu jadikan referensi.</p>', 'ilmu_keperawatan.jpg'),
(37, 'Gizi', '<p>Jurusan Ilmu Gizi adalah bidang ilmu yang mempelajari pentingnya nutrisi pada kehidupan manusia, terutama hubungan antara asupan makanan dengan kesehatan. Hal lain yang juga akan dipelajari meliputi pemahaman tetang pola makan sehat, gaya hidup, hingga cara memproses makanan. Di jurusan ini mahasiswa akan mempelajari zat gizi apa saja yang dibutuhkan dan bagaimana takaran idealnya sesuai dengan ilmu pengetahuan.</p>\r\n<p>Seperti kita ketahui, masalah kekurangan gizi masih belum mampu dituntaskan. Di samping itu, masalah kesehatan akibat kelebihan gizi seperti diabetes dan obesitas juga meningkat. Di tambah lagi, pertumbuhan yang sangat pesat di sektor industri pangan turut mendorong tingginya kebutuhan akan ahli gizi yang profesional.</p>', '<ul>\r\n<li>Kemampuan komunikasi</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan meneliti</li>\r\n<li>Kemampuan berpikir rasional dan terstruktur</li>\r\n<li>Kemampuan problem solving</li>\r\n<li>Kemampuan bekerja secara tim</li>\r\n<li>Keterampilan interpersonal</li>\r\n</ul>', '<ul>\r\n<li>Pemerintah senantiasa membutuhkan tenaga ahli gizi di banyak sektor.</li>\r\n<li>Instansi layanan kesehatan sangat membutuhkan lulusan Ilmu Gizi untuk merencanakan menu pasien juga memperhitungkan kandungan gizi dari menu yang dibuat.</li>\r\n<li>Perusahaan-perusahaan di industri makanan dan minuman juga membutuhkan ahli gizi untuk ditempatkan pada bagian research and development dan bertugas menganalisis kandungan gizi dari produk yang dihasilkan. Di bidang ini ahli gizi juga bisa lho sebagai staf penjamin mutu.</li>\r\n<li>Lulusan Ilmu Gizi juga punya kesempatan yang luas untuk membuka usaha, salah satunya usaha catering. Dengan berwirausaha, kamu pun ikut menciptakan lapangan kerja.</li>\r\n<li>Kamu juga bisa bekerja sebagai perencana program pangan dan gizi di lembaga swadaya masyarakat maupun international non-government organization</li>\r\n</ul>', '<p>Bagaimana&nbsp;<strong>prospek kerja</strong>&nbsp;Jurusan Ilmu Gizi? Tidak usah khawatir, karena Sarjana Gizi memiliki prospek kerja sebagai konsultan gizi baik di klinik, rumah sakit, dan puskesmas. Selain itu, kamu juga bisa bekerja di berbagai bidang, mulai dari menjadi staf penjamin mutu di industri makanan dan minuman, menjadi perencana menu dan gizi di pusat pelayanan kesehatan, peneliti di lembaga penelitian gizi dan kesehatan, menjadi akademisi, maupun menjadi pengusaha. Jenis dan jenjang kariernya juga cukup bervariasi.</p>\r\n<p><strong>Gaji awal</strong>&nbsp;yang ditawarkan tergolong sangat kompetitif dengan memperhatikan aspek kemampuan dan pengalaman yang dimiliki, area tempat bekerja, dan posisi pekerjaan. Lulusan dari Prodi Ilmu Gizi juga bisa mengembangkan potensi di sektor lain yang membutuhkan berbagai disiplin ilmu.</p>', '<p>Kuliah di jurusan Ilmu Gizi selama&nbsp;<strong>4 tahun atau 8 semester</strong>, sobat karier akan belajar tentang asupan gizi pada berbagai kondisi. Jadi, kamu akan mempelajari berbagai jenis penyakit juga ilmu dasar patofisiologi dan anatomi tubuh manusia. Kemudian kamu akan mengaitkannya dengan interaksi makanan, organ tubuh, obat-obatan, juga fitokimia. Nah, ketika datang klien yang dalam kondisi tidak sehat, kamu akan fokus menganalisa asupan makanannya terlebih dulu, setelah itu menyusul obat-obatan. Selama kuliah kamu juga akan dilatih bagaimana menghadapi klien melalui&nbsp;<em>skill lab</em>, tutorial, dan Praktek Kerja Lapangan.</p>\r\n<p><strong>Mata kuliah</strong>&nbsp;yang bisa kamu temui misalnya Gizi dalam Daur Kehidupan, Imunologi Gizi, Metabolisme Zat Gizi Makro, Metabolisme Zat Gizi Mikro, Patogenesis Penyakit Degeneratif, Patogenesis Penyakit Defisiensi dan Infeksi, Mikrobiologi Pangan, Gizi Kerja dan Olahraga, Penentuan Status Gizi, Manajemen Pelayanan dalam Makanan, Promosi Gizi, Konseling Gizi, Dietetika Penyakit Degeneratif, Analisa Pangan, Pengendalian Mutu Makanan, dan lainnya. Lulus dari Prodi Ilmu Gizi, sobat karier akan menyandang gelar&nbsp;<strong>Sarjana Gizi (S.Gz.)</strong>. Nah, kalau sobat karier ingin melanjutkan studi ke jenjang&nbsp;<strong>pascasarjana</strong>, ada banyak pilihan kampus bergengsi dengan variasi konsentrasi yang bisa kamu jadikan referensi.</p>\r\n<p><strong>Kompetensi lulusan</strong>&nbsp;dari prodi gizi diharapkan mampu berpikir secara luas dengan landasan ilmiah; mampu menjelaskan teori dasar, iptek gizi, dan ilmu secara terstruktur; mampu mengaplikasikan ilmu yang dipelajari untuk memecahkan masalah gizi; mampu berkomunikasi dengan efektif dalam pelayanan konseling dan edukasi; mampu mendasin pendidikan gizi yang disesuikan dengan kebutuhan; serta mampu mendesain penyelenggaraan makanan di tingkat institusi dengan menerapkan konsep manajemen.</p>', 'gizi.jpg'),
(38, 'Bimbingan dan konseling ', '<p><span lang=\"EN-ID\">Apabila Kamu mempunyai sifat penyabar, mudah bersosialisasi, bisa bersikap tenang ketika menghadapi masalah, ini merupakan alasan yang tepat untuk memilih Jurusan Bimbingan Konseling. Jurusan Bimbingan Konseling adalah jurusan yang mempelajari ilmu pendidikan, yang berhubungan dengan cara pembelajaran, pemahaman pendidikan, dan pemahaman terhadap peserta didik. Ilmu pendidikan ini dipakai sebagai dasar dalam melakukan bimbingan bagi peserta didik.</span></p>\r\n<p><span lang=\"EN-ID\">Kamu pasti pernah mendengar profesi guru BK di sekolah kan? Guru ini mempunyai tugas yaitu untuk memberikan bimbingan dan arahan secara psikologi kepada siswa. Kasus-kasus seperti kenakalan remaja, penyalahgunaan narkoba, tawuran, nilai yang jelek dan semua hal negatif tersebut perlu penanganan dari seorang konselor lulusan dari Jurusan Bimbingan Konseling.</span></p>\r\n<p><span lang=\"EN-ID\">Konselor dibutuhkan untuk menyelesaikan masalah dari para siswa dan juga berperan dalam memandu siswa dalam mengarahkan minat dan bakat agar menjadi hal yang positif. Untuk menyelesaikan hal itu biasanya konselor memberikan tes psikologi. Layanan Bimbingan Konseling dibutuhkan oleh sekolah dan masyarakat. Untuk di tingkatan SMA biasanya Bimbingan Konseling dijadikan sarana konsultasi siswa untuk merencanakan jurusan perkuliahan yang akan dipilih hingga karier yang dicita-citakan. Sedangkan di masyarakat, Bimbingan Konseling diperlukan untuk memberi pemahaman terkait perilaku-perilaku negatif yang merugikan kehidupan baik sebagai individu maupun sebagai anggota masyarakat. Selain itu juga untuk memberikan layanan pendidikan bagi anak-anak jalanan, dan mengupayakan pencegahan atas kasus-kasus sosial lainnya.</span></p>', '<ul>\r\n<li>Kemampuan komunikasi</li>\r\n<li>Kemampuan melakukan observasi</li>\r\n<li>Kemampuan analisis</li>\r\n<li>Kemampuan interpersonal</li>\r\n<li>Kemampuan berpikir sistematis</li>\r\n</ul>', '<ul>\r\n<li>Karena seorang konselor dituntut memahami karakter muridnya, di jurusan ini kamu akan dibekali materi bagaimana cara mengajar yang ideal sehingga diminati dan disenangi oleh semua murid.</li>\r\n<li>Dengan memilih kuliah di jurusan ini kamu akan selalu update terhadap perkembangan pendidikan dan memahami mengenai perkembangan pendidikan yang sedang berjalan.</li>\r\n<li>Dengan menjadi seorang calon konselor, kamu akan diberi arahan untuk memahami karakter dan bagaimana cara menyikapi atau berkomunikasi secara efektif dengan murid. So, siapkan dirimu menjadi konselor yang paling dikagumi siswa ya, bukan malah dijauhi.</li>\r\n<li>Karena jurusan ini memiliki kaitan yang erat dengan cabang ilmu psikologi, mahasiswa tidak hanya belajar terkait pelajaran umum, tetapi juga mempelajari karakter mental seseorang.</li>\r\n<li>Di perkuliahan nanti, kamu akan diberi materi mengenai penanganan masalah dengan cara bijak sehingga tidak mudah menghakimi murid yang tengah mengalami masalah.</li>\r\n<li>Di jurusan ini kamu juga akan diajarkan metode untuk menjadi tempat curhat yang menyenangkan dan menenangkan. Sehingga semua murid leluasa bercerita dan berkeluh kesah tentang banyak hal bahkan meminta saran untuk menyelesaikan masalah.</li>\r\n<li>Kamu bisa memiliki kemampuan untuk memperbaiki kepribadian murid, dengan dibekali berbagai ilmu yang telah dipelajari selama menjalani perkuliahan dibekali berbagai ilmu yang telah dipelajari selama menjalani perkuliahan.</li>\r\n<li>Dengan belajar di jurusan ini, maka kamu akan dapat memahami karakter orang-orang di sekelilingmu sehingga terjalin hubungan yang lebih baik karena adanya rasa saling memahami.</li>\r\n</ul>', '<p>Setelah lulus dari jurusan ini, saatnya kamu memilih karier. Lulusan jurusan ini bisa memiliki prospek karier yang sangat luas. Banyak sekali profesi yang bisa kamu jalani. Prospek utama dari lulusan ini adalah sebagai pengajar dan guru BK. Kamu juga bisa memilih berkarier sebagai seorang konsultan pendidikan di lembaga-lembaga bimbingan belajar. Lalu, jika kamu ingin bergabung di perusahaan, kamu juga memiliki kesempatan untuk berkarier menjadi seorang konsultan pengembangan Sumber Daya Manusia atau SDM. Kemampuan psikologi kepribadian yang diajarkan di bangku kuliah tentu saja dapat kamu manfaatkan dengan baik di bidang pekerjaan satu ini.</p>', '<p>Jurusan Bimbingan Konseling biasanya tergabung pada Fakultas Keguruan dan Ilmu Pendidikan walaupun kalau dirunut sebenarnya jurusan ini lebih dekat dengan rumpun psikologi. Oleh karena itu, ketika ingin mendaftar di jurusan ini jangan bingung jika diarahkan ke fakultas tersebut dan ketika lulus kamu juga akan diberi gelar Sarjana Pendidikan (S.Pd).</p>\r\n<p>Kuliah di jurusan ini akan kamu tempuh selama 8 semester dan pada semester 5 kamu mulai menjalani peminatan. Setiap kampus biasanya menentukan beberapa program peminatan, tetapi secara garis besarnya peminatan Jurusan Bimbingan Konseling dibagi menjadi dua yaitu Peminatan Pendidikan dan Peminatan Non Pendidikan. Pada Peminatan Pendidikan, kamu akan mengkaji hal-hal yang berhubungan dengan program pendidikan anak baik di dalam maupun di luar sekolah, mulai dari perencanaan hingga metode konseling yang tepat untuk setiap tingkatan pendidikan, termasuk bagi siswa yang berkebutuhan khusus. Sedangkan pada Peminatan Non Pendidikan, kamu akan melakukan kajian-kajian yang berhubungan dengan lingkungan sosial, karena dominan permasalahan yang membutuhkan pendekatan bimbingan dan konseling adalah masalah sosial. Misalnya, cara melakukan konseling yang tepat bagi anak jalanan atau mendesain program konseling yang tepat bagi para korban kekerasan dan korban ketergantungan obat.</p>\r\n<p>Selama mengikuti perkuliahan, kamu akan berhadapan dengan dua jenis mata kuliah, yakni mata kuliah wajib dan mata kuliah pilihan. Sebagai gambaran, mata kuliah yang akan kamu hadapi di Jurusan Bimbingan Konseling antara lain Psikologi Pendidikan, Teori dan Pendekatan Konseling, Media Bimbingan dan Konseling, Psikologi Kepribadian, Psikologi Kelompok, Wawancara Konseling, Modifikasi Perilaku, Kesehatan Mental, Psikoedukasi, Konseling Karier, dan masih banyak lagi.</p>\r\n<p>Kemudian jika ingin melanjutkan pendidikan ke jenjang Magister, kamu tidak perlu khawatir karena kampus-kampus di Indonesia juga sudah banyak yang menyediakan Program Magister Bimbingan Konseling. Kamu hanya perlu memastikan jika nilai yang kamu peroleh selama menjalani program sarjana setidaknya minimal B, sehingga semakin memperbesar peluangmu lulus di universitas impian.</p>', 'bimbingan_dan_konseling_.jpg'),
(39, 'Peternakan ', '<p>Peternakan merupakan bidang ilmu yang mempelajari ilmu hewan-hewan ternak yang bisa diolah dalam skala industri. Mulai dari bagaimana tata cara dalam produksi ternak yang baik, perkembangbiakan hewan ternak dan pengelolaannya, penanganan penyakit pada hewan ternak, mengatur kecukupan nutrisi pada makanan ternak, mengelola hasil produksi agar efisien dari hulu sampai hilir, serta bagaimana mengolah hasil ternak agar memiliki nilai tambah.&nbsp;<em>Eits</em>, kamu juga akan dibekali cara mengembangkan penelitian menggunakan bioteknologi&nbsp;<em>lho</em>, sobat karier!</p>', '<ul>\r\n<li>Kemampuan manajerial</li>\r\n<li>Kemampuan meneliti</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan teknik pemasaran</li>\r\n<li>Pemahaman biologi</li>\r\n<li>Pemahaman kimia</li>\r\n</ul>', '<ul>\r\n<li>Lulusan jurusan Peternakan dibutuhkan kontribusinya untuk mencegah terjadinya &ldquo;darurat pangan hewani.&rdquo;</li>\r\n<li>Selama kuliah, bisa dibilang kamu mempelajari berbagai bidang ilmu selain peternakan, misalnya ekonomi, teknik, gizi, juga kesehatan hewan ternak. Hal ini tentu saja jadi nilai plus bagi lulusan Peternakan untuk masuk ke dunia kerja.</li>\r\n<li>Setelah lulus dari jurusan Peternakan, sobat karier bisa lho menjadi abdi negara di Kementerian Pertanian sebagai pengawas bibit ternak, pengawas mutu pakan, pengawas mutu hasil pertanian, peneliti, dan sebagainya.</li>\r\n<li>Berbekal ilmu peternakan yang dipelajari di bangku kuliah, kamu juga bisa memulai untuk membuka usaha peternakan atau usaha pengolahan hasil ternak. Ya, hitung-hitung sekalian membuka lapangan pekerjaan, kan?</li>\r\n<li>Perusahaan-perusahaan di industri pengolahan makanan juga membutuhkan lulusan Peternakan untuk memperkuat divisi research and development maupun sebagai quality control dan quality assurance.</li>\r\n</ul>', '<p>Sebagai lulusan Jurusan Peternakan, kamu bisa&nbsp;<em>banget nih</em>&nbsp;membuka lapangan kerja dan&nbsp;<em>nggak</em>&nbsp;bergantung untuk kerja dengan orang lain. Kamu bisa mengaplikasikan ilmu di bangku perkuliahan dengan buka usaha peternakan. Selain itu, prospek kerja untuk lulusan Peternakan juga cukup bervariasi&nbsp;<em>lho</em>, salah satunya di industri makanan. Kamu juga bisa mengembangkan diri di sektor pendidikan. Soal gaji, tentu saja besarannya tergantung pada kemampuan dan pengalaman yang dimiliki, jenis pekerjaan, juga area tempat kerjanya. Berikut ini beberapa pilihan karier yang bisa kamu geluti:</p>', '<p>Sebagai lulusan Jurusan Peternakan, kamu bisa&nbsp;<em>banget nih</em>&nbsp;membuka lapangan kerja dan&nbsp;<em>nggak</em>&nbsp;bergantung untuk kerja dengan orang lain. Kamu bisa mengaplikasikan ilmu di bangku perkuliahan dengan buka usaha peternakan. Selain itu, prospek kerja untuk lulusan Peternakan juga cukup bervariasi&nbsp;<em>lho</em>, salah satunya di industri makanan. Kamu juga bisa mengembangkan diri di sektor pendidikan. Soal gaji, tentu saja besarannya tergantung pada kemampuan dan pengalaman yang dimiliki, jenis pekerjaan, juga area tempat kerjanya. Berikut ini beberapa pilihan karier yang bisa kamu geluti:</p>\r\n<p><strong>Pemuliaan dan reproduksi</strong>&nbsp;banyak membahas&nbsp;<em>gimana</em>&nbsp;caranya agar menghasilkan bibit ternak yang baik dan unggul. Jadi kamu akan belajar tentang genetika, organ reproduksi ternak, teknologi reproduksi ternak, pemuliaan ternak seperti kawin silang dan sebagainya. Kalau produksi berhubungan&nbsp;<em>sama farm management</em>.sobat karier &nbsp;<em>bakal</em>&nbsp;fokus tentang&nbsp;<em>gimana sih</em>&nbsp;mengelola peternakan supaya kegiatan operasionalnya efektif dan efisien. Misalnya, cara&nbsp;<em>bikin</em>&nbsp;pakan yang bagus hingga cara desain tempat pakan supaya saat makan nanti ternak&nbsp;<em>nggak ngebuang-buang</em>&nbsp;pakannya. Di fokus ini kamu juga akan belajar mendesain kandang supaya ternak bisa merasa nyaman serta pengetahuan dan ilmu agar ternak bisa efisien dalam reproduksi</p>\r\n<p><strong>Teknologi hasil ternak</strong>&nbsp;belajar tentang&nbsp;<em>gimana sih</em>&nbsp;caranya mengolah produk-produk hasil peternakan aobat karier <em>&nbsp;bakal</em>&nbsp;dibekali ilmu dan keterampilan&nbsp;<em>bikin</em>&nbsp;sosis, bakso, es krim, yoghurt, gelatin, kulit samak, biogas sampai pupuk kandang. Selain itu, belajar teknologi packaging dan ilmu gizi manusia,&nbsp;<em>lho</em>. Nah, kalau&nbsp;<strong>sosial ekonomi</strong>&nbsp;ini ibarat anak ekonomi-nya peternakan. Karena kamu bakal banyak membahas manajemen agribisnis, pemasaran, pemberdayaan masyarakat, psikologi industri, dan lain sebagainya. Intinya di sosial ekonomi itu kamu belajar tentang industri peternakan dari sisi ekonomi.</p>', 'peternakan_.jpg'),
(40, 'Kelautan', '<p>Kelautan merupakan cabang dari ilmu bumi yang mempelajari lautan. Topik pembahasan di jurusan ini antara lain meliputi organisme laut, dinamika ekosistem laut, geologi dasar laut, arus samudera, gelombang, dan dinamika cairan geofisika. Selain itu, bidang ini juga berhubungan dengan atmosfer&nbsp;<em>lho</em>. Tak heran jika nantinya kamu juga akan membahas isu-isu mengenai perubahan iklim, potensi pemanasan global, dan masalah biosfer terkait.</p>', '<ul>\r\n<li>Kemampuan melakukan observasi</li>\r\n<li>Kemampuan problem solving</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan berpikir rasional</li>\r\n<li>Kemampuan bekerja dalam tim</li>\r\n<li>Detil, teliti, tekun</li>\r\n</ul>', '<ul>\r\n<li>Berwawasan luas, karena Kelautan merupakan bidang multidisipliner jadi kamu akan belajar ilmu lain yang terkait untuk memahami lautan dan segala proses yang terjadi di dalamnya.</li>\r\n<li>Sarjana Kelautan sangat dibutuhkan untuk mengkaji pemanfaatan laut dan memastikan bahwa aktivitas yang dilakukan oleh manusia di lautan adalah aman.</li>\r\n<li>Lulusan Kelautan memiliki peluang untuk bekerja di perusahaan minyak lho. Seorang oseanograf dibutuhkan untuk mengumpulkan data dalam mendesain dan membangun pengeboran minyak lepas pantai.</li>\r\n<li>Kamu bisa bekerja di Kementerian Kelautan dan Perikanan sebagai analis data dan informasi, analis kelautan, ataupun analis konservasi kawasan.</li>\r\n<li>Kamu pun bisa bekerja sebagai Konsultan di bidang perikanan dan kelautan atau Konsultan di bidang pemetaan.</li>\r\n</ul>', '<p>Sobat karier tinggal di negara yang memiliki laut yang luas dan berpotensi, jadi&nbsp;<em>nggak</em>&nbsp;perlu khawatir soal prospek kerja lulusan Kelautan. Ada banyak peluang karier yang akan menantimu nanti. Jenis dan jenjang karier yang ditawarkan cukup bervariasi. Secara umum, gaji yang ditawarkan juga sangat kompetitif dengan memperhatikan aspek kemampuan dan pengalaman yang kamu miliki. Selain itu, kamu bisa bekerja secara mandiri dengan menjadi seorang konsultan independen. Kamu juga bisa menjadi wirausaha di bidang wisata bahari&nbsp;<em>lho</em>. Meskipun begitu, pada dasarnya banyak potensi yang bisa kamu kembangkan dengan mencoba untuk bekerja di sektor lainnya, seperti pendidikan, media, kreatif, dll. Nah, kalau masih bingung, berikut ini terdapat beberapa pilihan karier yang bisa kamu geluti:</p>', '<p>Selama 4 tahun atau 8 semester kuliah di Jurusan Kelautan sobat karier akan diajak untuk mempelajari ilmu bumi khususnya lautan secara mendalam. Kamu akan banyak membahas tumbuhan, hewan, dan mikroba laut juga interaksi ekologinya dengan samudera di&nbsp;<strong>Oseanografi Biologi</strong>. Sobat karier akan mengkaji kimia lautan dan interaksinya dengan atmosfer di&nbsp;<strong>Oseanografi Kimia&nbsp;</strong>serta mempelajari geologi dasar samudera di&nbsp;<strong>Oseanografi Geologi</strong>. Kamu juga akan meneliti atribut fisik lautan di&nbsp;<strong>Oseanografi Fisik</strong>.</p>\r\n<p><strong>Mata kuliah</strong>&nbsp;yang akan kamu temui antara lain Ichtyologi, Zoologi Laut, Ekologi Perairan, Ekologi Laut Tropis, Mikrobiologi Laut, Oseanografi, Pemetaan Sumber Daya Hayati Laut, Meteorologi Laut, Geologi Laut, Koralogi, Dinamika Ekosistem Laut, Pencemaran Laut, Penginderaan Jauh Kelautan, Instrumentasi Kelautan, Konservasi Sumber Daya Kelautan dan Perikanan, Pengelolaan Wilayah Pesisir dan Laut Terpadu, Bioteknologi Laut, dan sebagainya. Nantinya setelah berhasil menyelesaikan studi, sobat karier akan menyandang gelar&nbsp;<strong>Sarjana Kelautan</strong>. Jika sobat karier ingin mempelajari Kelautan secara lebih spesifik pada bidang minat tertentu, kamu bisa menempuh pendidikan pascasarjana. Ada banyak peminatan untuk jenjang pascasarjana dengan berbagai pilihan kampus bergengsi di dalam maupun luar negeri yang bisa dijadikan referensi. Selain itu, beasiswa yang ditawarkan juga tak kalah beragam,<em>&nbsp;lho</em>!</p>\r\n<p>Selain jurusan kelautan, bagi kamu yang tertarik untuk memahami seluruh aspek dalam ekosistem laut yuk cek tentang&nbsp;<a href=\"https://campus.quipper.com/majors/id-oseanografi\">jurusan oseanografi</a></p>', 'kelautan.jpg'),
(41, 'Kehutanan', '<p>Kehutanan adalah ilmu yang secara komprehensif mempelajari fungsi dan penggunaan dari ekosistem hutan seperti, keanekaragaman hayati, konservasi lingkungan, teknologi kehutanan, hukum penebangan hutan, dll. Selain itu, kamu juga akan belajar bagaimana memanfaatkan hasil hutan tanpa merusak ekosistem hutan itu sendiri. Cocok&nbsp;<em>deh</em>&nbsp;dengan sobat karier yang punya jiwa petualang dan hobi mendaki gunung! Karena kamu bisa menikmati keindahan gunung termasuk hutan, sekaligus belajar&nbsp;<em>gimana&nbsp;</em>cara memelihara hutan yang baik.</p>', '<ul>\r\n<li>Kemampuan melakukan observasi</li>\r\n<li>Kemampuan meneliti</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan berpikir terstruktur</li>\r\n<li>Pemahaman biologi</li>\r\n<li>Pemahaman kimia</li>\r\n</ul>', '<ul>\r\n<li>Perusahaan-perusahaan yang beroperasi di industri hulu kehutanan membutuhkanmu sebagai ahli bibit tanaman hutan.</li>\r\n<li>Tentunya kamu juga bisa bekerja di sektor swasta, misalnya di biro konsultan kehutanan, lembaga penelitian, hutan tanaman industri.</li>\r\n<li>Kalau kamu memiliki jiwa berwirausaha, bisa banget membuka usaha kayu maupun rotan. Selain itu, kamu bisa juga mengembangkan usaha mebel. Apalagi kalau bisa menjangkau pasar mancanegara, wih mantap deh!</li>\r\n<li>Organisasi nirlaba yang bergerak dalam perlindungan dan pemanfaatan hutan secara lestari juga membutuhkan lulusan Kehutanan. Jadi, kamu berkesempatan untuk mengembangkan diri bersama CIFOR, World Wildlife Fund, Wildlife Conservation Society, dan sebagainya.</li>\r\n<li>Jika ingin jadi abdi negara bisa juga lho memilih Kementerian Lingkungan Hidup dan Kehutanan. Nanti kamu akan bertugas sebagai pengendali ekosistem hutan maupun polisi kehutanan.</li>\r\n</ul>', '<p>Indonesia merupakan salah satu negara tropis yang memiliki hutan sangat luas. Jadi, lulusan Kehutanan sangat dibutuhkan untuk mengelola kawasan hutan agar terjaga ekosistemnya dan tetap lestari. Pokoknyasobat karier &nbsp;<em>nggak</em>&nbsp;perlu khawatir soal prospek kerja lulusan Kehutanan. Ada banyak peluang dengan jenjang karier yang cukup bervariasi. Secara umum, rata-rata gaji awal seorang ahli kehutanan berada pada kisaran Rp4.000.000. Meskipun begitu, besaran ini sangat bergantung pada kemampuan, area tempat bekerja, jabatan, dan pengalaman yang dimiliki. Berikut ini beberapa pilihan karier yang bisa kamu geluti:</p>', '<p>Kuliah di jurusan Kehutanan selama&nbsp;<strong>4 tahun atau 8 semester</strong>, kamu akan belajar bagaimana mengelola ekosistem hutan yang lestasri, meningkatkan produktivitas hutan, memanfaatkan dan hasil hutan, megelola dan mengolah hasil hutan secara efisien. Selain itu, kamu juga mempelajari upaya penyelamatan, perlindungan, pengelolaan dan pemanfaatan sumberdaya hutan secara bijaksana. Untuk meraih gelar&nbsp;<strong>Sarjana Kehutanan</strong>, sobat karier bisa memilih untuk mendalami bidang Manajemen Hutan, Silvikultur, Teknologi Hasil Hutan, atau Konservasi Sumberdaya Hutan.</p>\r\n<p><strong>Mata kuliah</strong>&nbsp;yang akan kamu temui misalnya Pengukuran Sumberdaya Hutan, Inventarisasi Sumberdaya, Manajemen Sumberdaya, Ilmu Tanah Hutan, Fitogeografi, Silvikultur, Anatomi dan Identifikasi Kayu, Sifat-sifat Dasar Kayu, Ekologi Hutan, Dasar-dasar Konservasi Sumber Daya Hutan, Konservasi Tanah Air, dll. Selain perkuliahan di dalam kelas, ada juga&nbsp;<em>lho</em>&nbsp;<strong>praktikum di laboratorium dan praktikum lapangan</strong>&nbsp;untuk mahasiswa jurusan Kehutanan. Sementara untuk memperkaya khasanah keilmuan mahasiswa Kehutanan juga melaksanakan praktek, seperti pengenalan hutan, tipe dan pemanfaatan hutan, serta pengelolaan hutan lestari. Seru kansobat karier? Jadi kamu&nbsp;<em>nggak cuma</em>&nbsp;belajar teori&nbsp;<em>aja</em>.</p>', 'kehutanan.jpg'),
(42, 'Hukum', '<p>Jurusan Ilmu Hukum adalah studi yang mempelajari berbagai sistem hukum yang berkaitan dengan kehidupan kemasyarakatan. Di Prodi Ilmu Hukum, mahasiswa juga belajar mengenai perundang-undangan termasuk di dalamnya hukum dasar (konstitusi, hukum perdata, hukum dagang, hukum tata negara, hukum pidana, hukum tata pidana) hingga hukum internasional dengan cakupan yang cukup luas. Pada akhir masa kuliah, biasanya mahasiswa jurusan ini dituntut untuk mengaplikasikan ilmu yang telah diperoleh selama kuliah melalui magang di berbagai firma hukum, lembaga pengadilan, dan juga kantor kejaksaan.</p>\r\n<p>Mahasiswa yang telah menuntaskan pendidikan di jurusan ini diharapkan dapat menguasai dengan baik hukum dan sistem hukum di Indonesia, mempunyai keterampilan dan pengetahuan ilmiah untuk mengembangkan hukum, peka terhadap permasalahan keadilan dan masyarakat, mampu mengenali dan menganalisis permasalahan hukum, serta mampu menerapkan hukum dan peraturan perundang-undangan untuk menyelesaikan masalah hukum.</p>', '<ul>\r\n<li>Kemampuan menghafal</li>\r\n<li>Kemampuan berpikir kritis</li>\r\n<li>Kemampuan menganalisis</li>\r\n<li>Kemampuan menyelesaikan masalah</li>\r\n<li>Komunikatif</li>\r\n<li>Kemampuan mengutarakan pendapat secara lugas</li>\r\n</ul>', '<ul>\r\n<li>Lulus dari jurusan ilmu hukum, kamu bisa menjadi pribadi yang kritis lugas dan memiliki kemampuan analisis yang cukup baik</li>\r\n<li>Prospek kerja jurusan ini yang sangat terbuka lebar</li>\r\n<li>Menjadi sarjana hukum membuat kamu memiliki kemungkinan untuk terlibat dalam pengkajian peraturan undang-undang loh!</li>\r\n</ul>', '<p>Lulusan Jurusan Ilmu Hukum kerja apa? Tidak perlu bingung, karena&nbsp;<strong>prospek kerja</strong>&nbsp;yang menanti lulusan jurusan ini sangat bervariasi. Akan tetapi, beberapa pilihan karier mengharuskanmu untuk menempuh studi lanjut setelah lulus S1. Misalnya, kamu yang ingin jadi pengacara harus ambil Pendidikan Khusus Profesi Advokat. Kalau kamu bercita-cita jadi notaris maka harus menempuh S2 Kenotariatan.</p>\r\n<p>Meskipun begitu, bukan berarti lulusan sarjana atau S1 Ilmu Hukum tidak bisa langsung bekerja, karena terdapat beberapa pilihan karier yang bisa kamu geluti, seperti sebagai staf legal di perusahaan, pekerjaan di bidang personalia atau HRD, management trainee, hingga bagian keuangan di perusahaan. Jurusal Ilmu Hukum juga dapat berkarier sebagai jaksa atau hakim di lembaga pengadilan.</p>\r\n<p><strong>Rata-rata gaji awal</strong>&nbsp;yang ditawarkan pada lulusan Ilmu Hukum sangat bervariasi, umumnya mulai dari kisaran Rp4.000.000, tergantung pada kemampuan, area tempat bekerja, tingkatan saat diterima, dan pengalaman yang kamu miliki.</p>', '<p>Jurusan Ilmu Hukum bisa dikatakan sebagai jurusan favorit di rumpun sosial humaniora. Bahkan, hampir seluruh Perguruan Tinggi di Indonesia menawarkan jurusan Ilmu Hukum. Daya tampung yang ditawarkan oleh Perguruan Tinggi di tiap tahun umumnya sangat besar. Jadi, peluangmu untuk menjadi mahasiswa di kampus impian dan diterima kuliah di jurusan Ilmu Hukum cukup tinggi.</p>\r\n<p>Apa yang akan kamu pelajari di jurusan ini? Semua yang kamu pelajari di jurusan Ilmu Hukum selama&nbsp;<strong>4 tahun atau 8 semester</strong>&nbsp;sampai akhirnya meraih gelar&nbsp;<strong>Sarjana Hukum (S.H.)</strong>, terpusat pada praktek hukum dan tata peraturan perundang-undangan. Kamu akan banyak melakukan kajian terhadap berbagai kasus hukum baik secara yuridis maupun normatif. Di jurusan ini kamu juga akan dibentuk sebagai seseorang yang memiliki keberanian. Hal ini mengingat kamu terbiasa untuk menyelesaikan berbagai kasus hingga mentalmu menjadi tangguh.</p>\r\n<p><strong>Mata kuliah</strong>&nbsp;yang akan kamu temui di jurusan Ilmu Hukum antara lain Hukum Pidana, Hukum Perdata, Hukum Tata Negara, Hukum Administrasi Negara, Hukum Agraria, Hukum Perdagangan, Hukum Adat, Hukum Internasional, Hukum Waris, Hukum Lingkungan, Hukum dan Hak Asasi Manusia, dll. Ilmu hukum merupakan program studi yang mempelajari seluruh aspek hukum, saat ini ada juga jurusan yang lebih spesifik seperti&nbsp;<a href=\"https://campus.quipper.com/majors/id-kriminologi\">kriminologi</a>,&nbsp;<a href=\"https://campus.quipper.com/majors/id-hukum-tata-negara\">hukum tata negara</a>&nbsp;dan&nbsp;<a href=\"https://campus.quipper.com/majors/id-hukum-ekonomi-syariah\">hukum ekonomi syariah</a>, dapat menjadi opsional jika ingin kuliah bidang hukum</p>', 'hukum.jpg'),
(43, 'Ilmu sosial dan politik', '<p>Ilmu Politik merupakan bidang ilmu yang banyak mengkaji gejala maupun fenomena sosial politik sehingga nantinya mampu menerapkan teori-teori ilmu politik untuk menawarkan solusi dari permasalahan sosial politik. Jurusan ini tidak hanya mempelajari bagaimana politik di Indonesia, tapi juga politik di berbagai negara. Dijamin deh wawasanmu akan semakin luas kalau kuliah di Jurusan Ilmu Politik.</p>', '<ul>\r\n<li>Kemampuan komunikasi</li>\r\n<li>Kemampuan melakukan observasi</li>\r\n<li>Kemampuan meneliti</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan berpikir rasional</li>\r\n<li>Kemmapuan problem solving</li>\r\n<li>Kemampuan negosiasi</li>\r\n</ul>', '<ul>\r\n<li>Lulusan Ilmu Politik umumnya memiliki wawasan yang luas dan peka terhadap isu-isu politik nasional maupun global. Dengan kemampuan tersebut kamu memiliki peluang terjun ke dunia jurnalistik sebagai jurnalis bidang politik.</li>\r\n<li>Lulusan ilmu politik bisa juga lho berkarier sebagai Diplomat, apalagi kalau kamu tertarik pada upaya menjalin dan merawat hubungan politik antarnegara.</li>\r\n<li>Kamu juga bisa menjajal beberapa bidang pekerjaan yang membutuhkan tenaga dari berbagai disiplin ilmu, umumnya lewat jalur management trainee atau program development officer</li>\r\n<li>Kamu punya kesempatan yang luas untuk melanjutkan studi jenjang pascasarjana dengan beasiswa lho.</li>\r\n</ul>', '<p>Orang awan banyak yang menganggap kalau lulusan Ilmu Politik pasti akan jadi politisi, anggota partai politik, atau anggota legislatif. Tapi sebenarnya banyak sekali potensi yang bisa kamu kembangkan. Karena peluang karier yang menanti lulusan Ilmu Politik cukup beragam. Kamu bisa masuk ke instansi pemerintah, menjajal dunia media, jadi akademisi, aktivis lembaga swadaya masyarakat, bahkan masuk ke perusahaan sebagai staf bagian&nbsp;<em>government relations</em>. Jenjang karier yang ditawarkan tiap pekerjaan juga cukup bervariasi, lho. Secara umum, rata-rata gaji awal lulusan Ilmu Politik berada pada kisaran Rp4.000.000, dengan pekerjaan sebagai staf dari bidang tertentu. Meskipun begitu, besaran ini sangat bergantung pada kemampuan, area tempat bekerja, jabatan, dan pengalaman yang dimiliki.</p>', '<p>Jika kuliah di jurusan Ilmu Politik, kamu akan sering membahas teori dan praktik politik, sistem politik, dan perilaku politik. Topik-topik seperti demokrasi, ideologi politik, partisipasi politik, pemilihan umum, komunikasi politik dan opini publik, budaya dan sosialisasi politik juga akan dibahas di Ilmu Politik. Kamu&nbsp; juga akan mempelajari tentang kekuasaan, sejarah, maupun sistem politik di Indonesia dan negara lainnya. Jadi, selain meneliti bagaimana politik di Indonesia, bisa nih memilih topik penelitian perbandingan politik.</p>\r\n<p><strong>Mata kuliah</strong>&nbsp;yang akan kamu lahap selama 4 tahun atau 8 semester diantaranya Sistem Politik Indonesia, Pemikiran Politik Indonesia, Pemikiran Politik Kontemporer, Politik Kebijakan Publik, Ekonomi Politik, Nasionalisme dan Resolusi Konflik, Perbandingan Politik, Sistem Perwakilan Politik, Perempuan dan Politik, Pembangunan Politik dan Studi Demokratisasi, Masyarakat dan Politik di Asia Tenggara, Bisnis dan Politik, dan sebagainya. Setelah lulus, kamu berhak atas gelar&nbsp;<strong>Sarjana Ilmu Politik</strong>&nbsp;atau&nbsp;<strong>Sarjana Sosial</strong>.</p>', 'fisip.jpg'),
(44, 'Seni rupa', '<p>Seni Rupa adalah bidang seni yang bermula dari pemahaman tradisi &ldquo;<em>fine art</em>,&rdquo; sebuah wacana dari modernisme yang dikembangkan dalam kesadaran nilai-nilai lokal juga global. Kamu akan diajari cara berekspresi melalui melukis, seni grafis, seni pahat, kerajinan, dan sebagainya. Kuliah di jurusan ini juga akan mempelajari sejarah seni, komposisi, dan tematik dalam karya seni</p>', '<ul>\r\n<li>Kemampuan berpikir kritis dan analis</li>\r\n<li>Kemampuan mengekspresikan perasaan melalui seni</li>\r\n<li>Kemampuan mengorganisir kegiatan seni rupa</li>\r\n<li>Kemampuan menyajikan karya seni</li>\r\n<li>Kemampuan bekerja secara individual dan tim</li>\r\n<li>Kreatif dan artistic</li>\r\n</ul>', '<ul>\r\n<li>Kamu akan jadi orang yang terampil dan kreatif</li>\r\n<li>Peluang pekerjaan yang cukup banyak</li>\r\n<li>Berpeluang menghasilkan usaha sendiri baik di bidang jasa ataupun barang</li>\r\n</ul>', '<p>Kuliah di jurusan seni nggak hanya bisa meniti karier menjadi seniman. Ada banyak peluang karier yang menanti lulusan Seni Rupa. Jenis pekerjaannya sangat beragam. Selain masuk ke industri kreatif, kamu juga sangat dibutuhkan di ranah media juga bidang periklanan. Mau terjun ke dunia pendidikan pun bisa&nbsp;<em>banget</em>. Karena bekal keilmuan dan keterampilan yang kamu dapatkan dari bangku perkuliahan bisa jadi modal berharga masuk ke pasar tenaga kerja. Secara umum, rata-rata gaji lulusan Seni Rupa berada pada kisaran Rp4.000.000 untuk<em>&nbsp;entry level</em>. Nah besaran ini sangat tergantung pada kemampuan pengalaman yang dimiliki juga area tempatmu bekerja.</p>', '<p>Kuliah di jurusan Seni Rupa, kamu akan dibekali sama&nbsp;<strong>keterampilan artistik, ekspresi proses kreatif, juga praktik seni</strong>. Selama 4 tahun atau 8 semester kuliah nanti, kamu akan banyak belajar tentang dasar dalam tradisi artistik melalui media yang mapan juga baru. Menggambar, melukis dan memahat akan jadi aktivitasmu sehari-hari. Dengan begitu kapasitasmu untuk berekspresi semakin kaya.</p>\r\n<p><strong>Mata kuliah</strong>&nbsp;yang bisa kamu temui, beberapa di antaranya adalah Gambar, Rupa Dasar 2D, Rupa Dasar 3D, Studio Seni Rupa, Media Seni, Estetika, Kritik Seni Rupa, Sosiologi Seni, Tinjauan Seni Rupa, Sejarah Seni Rupa Indonesia, Sejarah Seni Rupa Modern, Seni dan Ruang Publik, Seni Eksperimental, dan sebagainya, selain itu ada juga beberapa matakuliah peminatan diantaranya Seni Rupa Dwimatra, Seni Rupa Trimatra, Seni Rupa Intermedia, dan Kajian Seni.&nbsp;Setelah lulus, kamu akan mendapatkan gelar sarjana seni.</p>', 'seni_rupa.jpg');
INSERT INTO `tb_m_jurusan` (`ID`, `NAMA_JURUSAN`, `DESKRIPSI`, `PENGETAHUAN_DAN_KEAHLIAN`, `KENAPA_HARUS_JURUSAN_INI`, `PROSPEK_KERJA`, `DUNIA_PERKULIAHAN`, `GAMBAR`) VALUES
(45, 'Spesialis jurusan ilmu bedah', '<p>Pembedahan adalah salah satu metode yang sangat penting dalam berbagai macam kasus kesehatan. Melalui Jurusan Spesialis Ilmu Bedah, para dokter diharapkan tak hanya berkompeten dalam mengerjakan berbagai macam kasus bedah yang mereka hadapi, namun juga selalu mengedepankan nilai keilmiahan di setiap situasi yang dihadapi. Dengan begitu, seorang dokter spesialis bedah dengan karakter academic surgeon akan selalu bisa memberikan pelayanan yang maksimal seiring dengan perkembangan ilmu bedah dan teknologi.</p>', '<ul>\r\n<li>Kemampuan melakukan observasi</li>\r\n<li>Kemampuan melakukan analisis</li>\r\n<li>Kemampuan berpikir kritis dan terstruktur</li>\r\n<li>Kemampuan problem solving</li>\r\n<li>Keterampilan komunikasi</li>\r\n<li>Detil, teliti dan tekun</li>\r\n</ul>', '<p>Kemajuan ilmu pengetahuan dan juga teknologi kedokteran di bidang ilmu bedah adalah salah satu jawaban terhadap perkembangan masalah penyakit bedah, kompleksitas dan juga kerja sama interpersonal dalam manajemen bedah, sudah menghasilkan pendalaman ilmu serta teknologi bedah, sehingga berkembanglah profesi dokter subspesialis ini.</p>\r\n<p>Selain itu, transisi epidemiologi, sosio-ekonomi, dan juga sistem kesehatan dengan perkembangan serta jangkauan berbagai macam klasifikasi rumah sakit juga sudah menjadikan tuntutan masyarakat atas pelayanan yang berteknologi tinggi dan juga berkualitas sebagaimana bisa dilaksanakan melalui pelayanan sub spesialisasi bedah.</p>', '<ul>\r\n<li>Dokter bedah</li>\r\n</ul>\r\n<p>Bertugas untuk mengobati penyakit, cedera, atau kondisi gawat darurat pada tubuh melalui metode bedah (operatif) dan obat-obatan. Selain itu, Dokter Bedah juga bertanggung jawab untuk melakukan diagnosis sesuai keahlian dan ilmu yang dimiliki untuk menentukan perlu atau tidaknya prosedur bedah dilakukan.</p>\r\n<ul>\r\n<li>Koroner (pemeriksa medis untuk kematian)</li>\r\n</ul>\r\n<p>Bertugas untuk mengarahkan kegiatan seperti otopsi, analisis patologis dan toksikologi yang berkaitan dengan investigasi kematian yang terjadi dalam ranah hukum.</p>\r\n<ul>\r\n<li>Peneliti medical</li>\r\n</ul>\r\n<p>Bertugas untuk melakukan penelitian yang berhubungan dengan pemahaman penyakit manusia dan peningkatan kesehatan manusia. Juga terlibat dalam penyelidikan klinis, penelitian dan pengembangan, atau kegiatan lain yang terkait.</p>', '<p>Ilmu yang dipelajari dari jurusan ini diantaranya adalah diagnosis, manajemen sebelum operasi, selama operasi dan paska operasi termasuk manajemen komplikasi. Kamu akan belajar banyak mengenai dunia kedokteranloh sobat karier! Tertarik masuk jurusan ini?</p>', 'bedah.jpeg'),
(46, 'Kesehatan Masyarakat', '<p>Program Studi Kesehatan Masyarakat merupakan bidang ilmu yang mempelajari pencegahan dan pengobatan penyakit pada individu. Bidang ilmu ini juga bertujuan menjaga dan mempromosikan kesehatan sosial dengan mempelajari hubungan antara manusia dan lingkungan dan metode pencegahan penyakit, kesehatan dalam suatu kawasan, maupun kesehatan di lingkungan kerja. Pada Prodi Kesehatan Masyarakat, mahasiswa juga akan mempelajari tentang ilmu gizi, manajemen dan administrasi kesehatan, dan proses penyuluhan kesehatan di masyarakat.</p>', '<ul>\r\n<li>Kemampuan komunikasi</li>\r\n<li>Kemampuan manajerial</li>\r\n<li>Kemaampuan bekerja secara efektif</li>\r\n<li>Kemampuan bekerja dalam tim</li>\r\n</ul>', '<ul>\r\n<li>Kompetensi yang dimiliki lulusan jurusan ini menjawab kebutuhan para pengguna ahli kesehatan masyarakat dalam hal penanganan epidemiologi, perancangan, serta agen keselamatan dan kesehatan kerja.</li>\r\n<li>Pemerintah memerlukan Sarjana Kesehatan Masyarakat untuk menangani permasalahan kesehatan lingkungan yang semakin kompleks di berbagai wilayah.</li>\r\n<li>Lulusan kesehatan masyarakat juga dibutuhkan di berbagai sektor, seperti manufaktur, minyak dan gas, untuk mengisi divisi tertentu di sebuah perusahaan.</li>\r\n</ul>', '<p><strong>Prospek kerja&nbsp;</strong>bagi lulusan jurusan Kesehatan Masyarakat tidak hanya di Puskesmas! Berbagai industri dan organisasi swasta juga membutuhkan ahli kesehatan masyarakat. Misalnya, dalam bidang&nbsp;<em>Quality</em>,<em>&nbsp;Health</em>,&nbsp;<em>Safety and Environment</em>&nbsp;(QHSE) di perusahaan minyak dan gas, manufaktur, dll.</p>\r\n<p>Jenjang kariernya pun cukup bervariasi, gaji yang ditawarkan juga sangat menjanjikan. Namun, besaran gajinya tetap mempertimbangkan area tempat bekerja, posisi pekerjaan, serta kemampuan dan pengalaman yang dimiliki seorang Sarjana Kesehatan Masyarakat.</p>', '<p>Prodi Kesehatan Masyarakat merupakan salah satu jurusan favorit calon mahasiswa rumpun kesehatan selain Pendidikan Dokter. Kamu, akan ditempa selama 4 tahun atau 8 semester untuk meraih gelar&nbsp;<strong>Sarjana Kesehatan Masyarakat</strong>. Kamu akan dibekali dengan&nbsp;<em>basic skill</em>&nbsp;yang disebut &ldquo;<em>MIRACLE</em>&rdquo; yaitu&nbsp;<em>Manager</em>&nbsp;(manajer),&nbsp;<em>Innovator</em>&nbsp;(pembaharu),&nbsp;<em>Researcher&nbsp;</em>(peneliti),&nbsp;<em>Apprentice&nbsp;</em>(mampu belajar dalam tim dan mampu bekerja cepat),&nbsp;<em>Communitarian</em>&nbsp;(merakyat),&nbsp;<em>Leader&nbsp;</em>(memimpin), dan&nbsp;<em>Educator&nbsp;</em>(pendidik). Dengan begitu kamu akan siap untuk jadi ahli Kesehatan Masyarakat.</p>\r\n<p>Kuliah di Kesehatan Masyarakat memiliki fokus preventif dan promotif. Jadi, kamu akan belajar bagaimana<em>&nbsp;sih</em>&nbsp;supaya masyarakat yang sehat&nbsp;<em>nggak&nbsp;</em>menjadi sakit. Kamu akan belajar pula soal penyakit dan penyebarannya, serta yang pasti cara mencegahnya. Kamu akan dilatih untuk mengorganisir masyarakat agar setiap masyarakat memperoleh haknya untuk sehat sehingga dapat merasakan harapan hidup yang panjang.</p>\r\n<p><strong>Mata kuliah</strong>&nbsp;yang akan kamu temui selama kuliah di jurusan Kesehatan Masyarakat antara lain Ilmu Kependudukan, Sosio-Antro Kesehatan, Psikologi Kesehatan, Epidemiologi, Kesehatan Lingkungan, Keselamatan dan Kesehatan Kerja, Higiene Lingkungan Kerja, Pemberdayaan Masyarakat, Kebijakan Kesehatan, Renval Kesehatan, serta Penentuan Status Gizi. Di jurusan ini, kamu&nbsp;<em>nggak</em>&nbsp;hanya dibekali teori&nbsp;<em>lho</em>, tapi juga diberikan kesempatan untuk terjun langsung ke lapangan.</p>\r\n<p>Alternatif jurusan yang jurusan erat kaitanya dengan kesehatan masyarakat yaitu&nbsp;<a href=\"https://campus.quipper.com/majors/id-kesehatan-lingkungan\">kesehatan lingkungan</a>&nbsp;berfokus pada kesehatan alam dan lingkungan yang dapat berdampak pada kesehatan masyarakat.</p>', 'kesehatan_masyarakat.jpg'),
(47, 'Filsafat', '<p>Filsafat merupakan bidang ilmu yang mempelajari cara berpikir. Kamu dilatih untuk mempertanyakan suatu keadaan. Selain itu, juga akan diajarkan bagaimana memformulasikan dan mengokohkan pandanganmu secara merdeka tentang suatu permasalahan di dunia ini. Kamu akan diajak untuk mengenal jenis-jenis kesesatan berpikir, karakteristik ilmu pengetahuan, mengkritik suatu karya seni, pentingnya empati, mengkaji kapan suatu tindakan bisa dikatakan baik dan buruk, dan sebagainya.</p>', '<ul>\r\n<li>Kemampuan berpikir kritis</li>\r\n<li>Kemampuan bernalar logis</li>\r\n<li>Kemampuan berargumentasi</li>\r\n<li>Kemampuan komunikasi</li>\r\n<li>Kemampuan observasi</li>\r\n<li>Kemampuan meneliti</li>\r\n<li>kemampuan</li>\r\n</ul>', '<ul>\r\n<li>Memiliki kemampuan berpikir kritis, rasional, dan logis, sehingga mampu menjadi pencetus ide yang diberbagai bidang. Dengan kata lain, lulusan Filsafat bisa kerja jadi apa saja!</li>\r\n<li>Kemampuan membaca, berargumentasi, dan berdiskusi seorang lulusan Filsafat sangat terasah. Selain itu, lulusan filsafat juga punya kemampuan memroses informasi secara jernih.</li>\r\n<li>Mampu mengidentifikasi, merumuskan, dan memecahkan persoalan dasar kemasyarakatan khususnya terkait dengan keilmuan dan teknologi, etika terapan, sosial politik, dll.</li>\r\n<li>Kepribadian seorang Sarjana Filsafat biasanya mencerminkan kepribadian cendikiawan yang bijaksana, humanis, nasionalis, demokratis, juga adil.</li>\r\n<li>Bisa melanjutkan studi jenjang pascasarjana di bidang apapun, karena lulusan Filsafat memiliki bekal analytical thinking yang juara!</li>\r\n</ul>', '<p>Dengan bekal kemampuan berpikir rasional dan bernalar secara logis, lulusan Filsafat bisa kerja jadi apa saja! Ada banyak lulusan Filsafat yang bekerja di industri media, salah satunya Dian Sastrowardoyo. Ada juga yang memilih menjadi aktivis Hak Asasi Manusia, menjadi pengajar, penulis buku, kurator karya seni, dan sebagainya. sarjana filsafat bisa bekerja sebagai konselor atau psikoterapis untuk membantu memecahkan masalah psikologi atau emosional yang dihadapi klien. Jadi ada banyak&nbsp;<em>banget</em>&nbsp;peluang karier bagi lulusan Filsafat.</p>', '<p>Sobat karier, tahukah kamu bahwa filsafat merupakan <em>Mother Of Sciences. </em>mu akan belajar bagaimana cara berpikir kritis dan runtut sesuai dengan nalar. Selama kuliah, kamu akan banyak memakai teori-teori sosial untuk memformulasikan pendapat. Percayalah kuliah selama 4 tahun atau 8 semester di jurusan ini kamu akan ditempatkan pada area latihan mengutarakan pendapat tanpa merasa takut dihakimi.</p>\r\n<p>Beberapa&nbsp;<strong>mata kuliah</strong>&nbsp;yang harus kamu tempuh untuk meraih gelar Sarjana Filsafat antara lain Logika, Sejarah Filsafat Yunani, Sejarah Filsafat Abad Pertengahan, Sejarah Filsafat Modern, Epistemologi, Etika, Estetika, Metafisika, Filsafat Manusia, Filsafat Budaya, Filsafat Bahasa, Filsafat Sosial, Filsafat Agama, Filsafat Teknologi, Filsafat Timur, Teori-teori Keadilan, Filsafat Ketuhanan, Hermeneutika, Fenomenologi, dll.</p>\r\n<p>Selain itu, jurusan ini juga menawarkan bidang minat seperti Ontologi, Aksiologi, dan Epistemologi. Onkologi mendalami hakikat filsafat, sebenarnya apa pengetahuan filsafat itu. Aksiologi mengkaji bagaimana mendapatkan pengetahuan itu. Sementara Aksiologi membahas guna pengetahuan itu. Ada pula yang membagi bidang konsentrasi menjadi Etika, Filsafat Ilmu dan Budaya, Filsafat Religi dan Budaya, serta Filsafat Sosial dan Politik</p>', 'filsafat.jpg');
